import cx from 'classnames';

export interface SectionProps {
  header?: React.ReactNode;
  className?: string;
  children?: React.ReactNode;
  testId?: string;
  trackingId?: string;
  tagline?: string;
  id?: string;
  /** Tailwind spacing class for children container. Defaults to 'space-y-3' */
  verticalSpacing?: string;
}

export const Section: React.FC<SectionProps> = ({
  header,
  className,
  children,
  testId,
  trackingId,
  tagline,
  id,
  verticalSpacing = 'space-y-3',
}): React.ReactElement => (
  <section
    className={cx('space-y-4', className)}
    data-testid={testId}
    data-trackingid={trackingId}
    id={id}
  >
    {(!!header || !!tagline) && (
      <span>
        {!!header && (
          <h3 className="font-heading-3" id={id ? `${id}-header` : undefined}>
            {header}
          </h3>
        )}
        {!!tagline && (
          <p
            className={cx('text-fgDecorative font-caption my-1')}
            data-testid={testId ? `${testId}-tagline` : undefined}
            data-trackingid={trackingId ? `${trackingId}-tagline` : undefined}
          >
            {tagline}
          </p>
        )}
      </span>
    )}
    <div className={cx('text-fgMain font-body', verticalSpacing)}>{children}</div>
  </section>
);
