import React, {
  PropsWithChildren,
  useContext,
  useEffect,
  useRef,
  useState,
} from 'react';
import ReactDOM from 'react-dom';

import { Transition } from '@/externals/headlessui';

export interface OffScreenDetectorChildrenProps {
  /* Ref Object to be applied to the scroll container the trigger element will be scroling out of */
  scrollContainerRef: React.MutableRefObject<HTMLDivElement | null>;

  /* A component to display content when the trigger element scrolls offscreen */
  OffScreenDisplay: React.FC;

  /* A flag to indicate whether or not the trigger element is offscreen */
  isOffScreen: boolean;
}

export interface OffScreenDetectorProps {
  /* Children are a callback to provide a ref to the scrolling container */
  children(props: OffScreenDetectorChildrenProps): React.ReactNode;

  /* IntersectionObserver configuration options */
  observerOptions?: Partial<IntersectionObserverInit>;
}

export interface OffScreenDetectorContextProps {
  displayRef: React.MutableRefObject<HTMLDivElement | null> | null;
  scrollContainerRef: React.MutableRefObject<HTMLDivElement | null> | null;
  isOffScreen: boolean;
  setIsOffScreen: (flag: boolean) => void;
  observerOptions: Partial<IntersectionObserverInit>;
}

const OffScreenDetectorContext =
  React.createContext<OffScreenDetectorContextProps | null>(null);

// Display Container - Creates a div as a ref holder for an eventual <OffScreenContent /> to place content into.
export const OffScreenDisplay: React.FC = (): React.ReactElement | null => {
  const context = useOffScreenDetector();
  if (!context) {
    return null;
  }
  const { displayRef } = context;
  return <div ref={displayRef}></div>;
};

// The main wrapping component, creates the context and sets up state, handles scroll detection
export const OffScreenDetector: React.FC<OffScreenDetectorProps> = ({
  children,
  observerOptions = { rootMargin: '5px', threshold: 0 },
}) => {
  const scrollContainerRef = useRef(null);
  const displayRef = useRef(null);

  const [isOffScreen, setIsOffScreen] = useState(false);

  const contextValue = {
    isOffScreen,
    displayRef,
    scrollContainerRef,
    setIsOffScreen,
    observerOptions,
  };

  return (
    <OffScreenDetectorContext.Provider value={contextValue}>
      {children({ OffScreenDisplay, scrollContainerRef, isOffScreen })}
    </OffScreenDetectorContext.Provider>
  );
};

export interface OffScreenContentContainerProps {
  children(triggerRef: React.MutableRefObject<HTMLDivElement | null>): React.ReactNode;
}

export const OffScreenContentContainer: React.FC<OffScreenContentContainerProps> = ({
  children,
}): React.ReactElement => {
  const triggerRef = useRef(null);
  const context = useOffScreenDetector();

  React.useEffect(() => {
    const options: IntersectionObserverInit = {
      root: context?.scrollContainerRef?.current,
      ...context?.observerOptions,
    };

    const onIntersect = (entries: IntersectionObserverEntry[]) =>
      entries.forEach(
        (entry: IntersectionObserverEntry) =>
          context?.setIsOffScreen(!entry.isIntersecting && entry.target?.isConnected),
      );

    const observer = new IntersectionObserver(onIntersect, options);
    if (triggerRef?.current) {
      observer.observe(triggerRef?.current);
    }
  }, [context, context?.setIsOffScreen, context?.observerOptions]);

  useEffect(() => {
    context?.setIsOffScreen(false);
    return function cleanup() {
      triggerRef.current = null;
      context?.setIsOffScreen(false);
    };
  }, []);

  // TODO: refactor to a modern pattern that doesn't use render props
  // eslint-disable-next-line react-hooks/refs
  return <>{children(triggerRef) ?? null}</>;
};

// Content component, used within sub-components to self-set the content of that bar.
// Automatically wrapped in a transition
export const OffScreenContent: React.FC<PropsWithChildren<{}>> = ({
  children,
}): React.ReactPortal | null => {
  const context = useOffScreenDetector();

  return context?.displayRef?.current
    ? ReactDOM.createPortal(
        <>
          <Transition
            enter="transition ease-out duration-200"
            enterFrom="opacity-0 -translate-y-1"
            enterTo="opacity-100 translate-y-0"
            leave="transition ease-in duration-150"
            leaveFrom="opacity-100 translate-y-0"
            leaveTo="opacity-0 -translate-y-1"
            show={context?.isOffScreen}
            as={React.Fragment}
          >
            <div className="bg-bgBackground absolute left-0 right-0 top-full z-10 h-auto shadow">
              {children}
            </div>
          </Transition>
        </>,
        context.displayRef.current,
      )
    : null;
};

// Hook to expose context, including the triggerRef and the a flag to indicate whether the trigger is off screen.
export const useOffScreenDetector = (): OffScreenDetectorContextProps | null => {
  return useContext(OffScreenDetectorContext);
};
