import { type FC, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useResizeDetector } from 'react-resize-detector';
import { OnRefChangeType } from 'react-resize-detector/build/types';
import {
  autoPlacement as autoPlacementMiddleware,
  autoUpdate,
  offset,
  Placement,
  safePolygon,
  useDismiss,
  useFloating,
  useFocus,
  useHover,
  useId,
  useInteractions,
  useRole,
} from '@floating-ui/react';
import cx from 'classnames';

import { TooltipPanel } from './TooltipPanel';

export interface TooltipProps {
  /** The tooltip trigger */
  children:
    | React.ReactNode
    | ((
        ref: React.MutableRefObject<any> | OnRefChangeType<HTMLElement>,
      ) => React.ReactNode);

  /** If wrapping an <a /> or <button /> or other interactive element, set this to true! */
  childrenAreInteractive?: boolean;

  /** The content to display in the tooltip */
  content: React.ReactNode;

  /** Won't show the tooltip if true */
  hidden?: boolean;

  /** Custom placement for the tooltip */
  placement?: Placement;

  /** try to auto place the tooltip content */
  autoPlacement?: boolean;

  /**
   * Only show the tooltip when content is truncated.
   * If true, children must be a function that passes ref to the truncated element
   */
  displayOnlyWhenTruncated?: boolean;

  /** Wrapper classnames */
  className?: string;

  /** Custom maxWidth for the tooltip */
  maxWidth?: number | 'none';

  /** Use a portal to render. Defaults to true */
  portal?: boolean;

  /** test-id for cypress test targeting */
  testId?: string;
}

export const Tooltip: FC<TooltipProps> = ({
  children,
  childrenAreInteractive = false,
  content,
  className,
  maxWidth,
  hidden = false,
  placement = 'top-start',
  displayOnlyWhenTruncated = false,
  testId = 'tooltip',
  portal = true,
  autoPlacement = false,
}): React.ReactElement => {
  const [isTruncated, setIsTruncated] = useState(false);
  const resizeRef = useRef<HTMLElement | null>(null);
  const [isOpen, setIsOpen] = useState(false);

  const middleware = useMemo(() => {
    const defaultMiddleware = [offset({ mainAxis: 4 })];
    if (autoPlacement) {
      return [
        autoPlacementMiddleware({
          padding: 4,
          alignment: 'start',
        }),
        ...defaultMiddleware,
      ];
    }
    return defaultMiddleware;
  }, [autoPlacement]);

  const { refs, floatingStyles, context } = useFloating({
    placement: autoPlacement ? undefined : placement,
    open: isOpen,
    onOpenChange: setIsOpen,
    middleware,
    whileElementsMounted: autoUpdate,
  });

  const onResize = useCallback(() => {
    const target = resizeRef.current;
    if (target instanceof HTMLElement) {
      const isTruncated = (target.scrollWidth ?? 0) > (target.offsetWidth ?? 0);
      setIsTruncated(isTruncated);
    }
  }, [resizeRef]);
  const { ref: targetRef } = useResizeDetector({ onResize });

  // TODO: find a better way to get onResize to have this reference
  useEffect(() => {
    resizeRef.current = targetRef.current;
  }, [targetRef]);

  const contentId = useId();

  const enabledForTruncation = displayOnlyWhenTruncated && isTruncated && !hidden;
  const enableTooltip = displayOnlyWhenTruncated ? enabledForTruncation : !hidden;

  // shows tooltip with keyboard focus (only when :focus-visible is set)
  const focus = useFocus(context, { enabled: enableTooltip });
  // add accessible props
  const role = useRole(context, { enabled: enableTooltip, role: 'tooltip' });
  // dismisses on escape press
  const dismiss = useDismiss(context, { enabled: enableTooltip });
  // show on hover
  const hover = useHover(context, {
    enabled: enableTooltip,
    delay: 100,
    handleClose: safePolygon(),
  });

  const { getReferenceProps, getFloatingProps } = useInteractions([
    hover,
    focus,
    dismiss,
    role,
  ]);

  const target = useMemo(
    // TODO: refactor to avoid render props pattern
    // eslint-disable-next-line react-hooks/refs
    () => (typeof children === 'function' ? children(targetRef) : children),
    [children, targetRef],
  );

  const targetProps = useMemo(
    () => ({
      role: childrenAreInteractive ? undefined : 'button',
      'aria-describedby': contentId,
      // If the children are interactive, focusing on them should open the tooltip. This avoids multiple nested focus rings.
      // If the tooltip is not enabled, we don't want to focus on the target.
      tabIndex: enableTooltip && !childrenAreInteractive ? 0 : -1,
      className: cx(
        'focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2',
        {
          'cursor-default': !childrenAreInteractive,
        },
        className,
      ),
    }),
    [childrenAreInteractive, className, contentId, enableTooltip],
  );

  const floatingClassName =
    'bg-bgMainHover font-caption text-fgMain px-2 py-1 rounded-md max-w-md text-pretty break-words shadow-hover border border-borderMuted';

  const tooltipStyles = {
    ...floatingStyles,
    maxWidth,
    ...(portal ? { zIndex: 50 } : {}),
  };

  if (!content) {
    return <>{target}</>;
  }

  return (
    <span className={className} data-testid={testId}>
      <span
        {...getReferenceProps()}
        {...targetProps}
        data-testid={`${testId}-target`}
        ref={refs.setReference}
      >
        {target}
      </span>
      {isOpen && (
        <TooltipPanel portal={portal}>
          <span
            {...getFloatingProps()}
            style={tooltipStyles}
            // eslint-disable-next-line react-hooks/refs
            ref={refs.setFloating}
            className={floatingClassName}
            data-testid={`${testId}-content`}
            role="tooltip"
            id={contentId}
          >
            {content}
          </span>
        </TooltipPanel>
      )}
    </span>
  );
};
