import { useMemo } from 'react';
import cx from 'classnames';

import { type RegisterOptions, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { Sizes, useSkeletonContext } from '../../../sourdough';
import { get } from '../../../utils/';
import { CopyButton } from '../../CopyButton/CopyButton';
import { Icon } from '../../Icon/Icon';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { Ryecon } from '../../ryecons/types';
import { Field } from '../Field/Field';
import { FormFieldMessage } from '../FormFieldMessage/FormFieldMessage';

import './Input.css';

type InputIconProps = {
  iconAlt?: string;
  onClick?: () => void;
  className?: string;
  ryecon: Ryecon;
};
interface CustomInputProps extends React.ComponentPropsWithRef<'input'> {
  name: string;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** The default value used to override any higher level default input, or, if child elements aren't supplied, the display value */
  defaultValue?: string;

  /** Description Text */
  description?: React.ReactNode;

  /** Input type */
  type?: 'text' | 'password' | 'number' | 'hidden';

  /** react-hook-form register config, accepts any options react-hook-form's register can accept. */
  formConfig?: Omit<RegisterOptions, 'pattern'>;

  /** Class names for the input element */
  inputClassName?: string;

  /** Boolean to determine whether to include a copy button */
  includeCopyButton?: boolean;

  /** Class names for the read-only element */
  displayClassName?: string;

  /** An icon to display at the start of the input  */
  startIcon?: InputIconProps;

  /** An icon to display at the end of the input  */
  endIcon?: InputIconProps;

  /** Addon to display inline on element */
  addon?: React.ReactNode;

  /** A title for the input */
  title?: string;

  /** Custom onChange handler. Allows for extra handling past the default react-hook-form usage */
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  sizeVariant?: 'xs' | 'sm' | 'md';
}

export type InputProps = BaseInputProps & CustomInputProps;

export const inputClasses = ({
  isError = false,
  isDisabled = false,
  hasAddon = false,
  hasEndIcon = false,
  hasStartIcon = false,
  inputClassName = '',
  sizeVariant = 'md',
}: {
  isError: boolean;
  isDisabled: boolean;
  hasAddon: boolean;
  hasEndIcon: boolean;
  hasStartIcon: boolean;
  inputClassName?: string;
  sizeVariant: 'xs' | 'sm' | 'md';
}) =>
  cx(
    'font-body-sm block w-full',
    {
      'focus:border-borderBrand focus:ring-focusBrand bg-bgMain border-borderMain text-fgMain placeholder-fgDecorative shadow-rest':
        !isError && !isDisabled,
      'border-borderDanger bg-bgMain focus:border-borderDanger focus:ring-focusDanger shadow-rest focus:outline-none':
        isError && !isDisabled,
      'rounded-md': !hasAddon,
      'focus:border-borderBrand focus:ring-focusBrand border-borderMain shadow-rest min-w-0 flex-1 rounded-none rounded-r-md px-3 py-2':
        hasAddon && !isDisabled,
      'border-borderDisabled bg-bgDisabled text-fgDisabled placeholder-fgDisabled cursor-not-allowed shadow-none':
        isDisabled,
      'pr-9': hasEndIcon,
      'pl-9': hasStartIcon,
      // Input size
      'h-6 py-[1px]': sizeVariant === 'xs', // 24px tall
      'h-8 py-[5px]': sizeVariant === 'sm', // 32px tall
      'h-10 py-[9px]': sizeVariant === 'md', // 40px tall
    },
    inputClassName,
  );

export const Input: React.FC<InputProps> = ({
  name,
  label,
  labelIsHidden = false,
  labelFor,
  isOptional,
  helpLink,
  onHelpClick,
  tooltip,
  description,
  defaultValue,
  type = 'text',
  className,
  inputClassName,
  displayClassName,
  error,
  startIcon,
  endIcon,
  addon,
  title,
  isEdit = false,
  isDisabled = false,
  children,
  formConfig,
  testId = 'input',
  trackingId = 'input',
  shouldHideErrorLabel = false,
  skeleton = false,
  includeCopyButton = false,
  sizeVariant = 'md',
  ...props
}) => {
  const formMethods = useFormContext();
  const computedFormConfig = formConfig
    ? { valueAsNumber: type === 'number', ...formConfig }
    : { valueAsNumber: type === 'number' };
  const registration = formMethods?.register(
    name,
    computedFormConfig as RegisterOptions, // workaround for rhf type issues
  );
  const errors = formMethods?.formState?.errors ?? {};
  const errorMessage = get(errors, name)?.message ?? error;
  const formSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || formSkeleton;

  const inputClassNames = inputClasses({
    isError: !!errorMessage,
    isDisabled,
    hasAddon: !!addon,
    hasEndIcon: !!endIcon,
    hasStartIcon: !!startIcon,
    inputClassName,
    sizeVariant,
  });

  const _startIcon = useMemo(() => {
    if (!startIcon) {
      return null;
    }

    const compProps = {
      className: cx(
        'absolute inset-y-0 left-0 flex items-center pl-3',
        {
          'cursor-pointer': !!startIcon.onClick,
        },
        startIcon.className,
      ),
      children: (
        <Icon
          alt={startIcon.iconAlt}
          ryecon={startIcon.ryecon}
          size="sm"
          className="text-fgDecorative"
        />
      ),
      'data-testid': `${testId}-start-icon`,
      'data-trackingid': `${trackingId}-start-icon`,
      onClick: startIcon.onClick,
    };

    const comp = startIcon.onClick ? (
      <button type="button" {...compProps} />
    ) : (
      <div {...compProps} />
    );

    return <div className={!!addon && isEdit ? 'relative' : ''}>{comp}</div>;
  }, [startIcon, addon, isEdit, testId, trackingId]);

  const _endIcon = useMemo(() => {
    if (!endIcon) {
      return null;
    }

    const compProps = {
      className: cx(
        'absolute inset-y-0 right-0 flex items-center pr-3',
        {
          'cursor-pointer': !!endIcon.onClick,
        },
        endIcon.className,
      ),
      children: (
        <Icon
          alt={endIcon.iconAlt}
          ryecon={endIcon.ryecon}
          size="sm"
          className="text-fgDecorative"
        />
      ),
      'data-testid': `${testId}-end-icon`,
      'data-trackingid': `${trackingId}-end-icon`,
      onClick: endIcon.onClick,
    };

    return endIcon.onClick ? (
      <button type="button" {...compProps} />
    ) : (
      <div {...compProps} />
    );
  }, [endIcon, testId, trackingId]);

  return (
    <Field
      label={label}
      labelIsHidden={labelIsHidden}
      labelFor={labelFor}
      tooltip={tooltip}
      isOptional={isOptional}
      isEdit={isEdit}
      helpLink={helpLink}
      onHelpClick={onHelpClick}
      className={cx(`sourdough-input-field`, className)}
      isDisabled={isDisabled}
      testId={`${testId}-wrapper`}
      trackingId={`${trackingId}-wrapper`}
    >
      {!shouldSkeleton && !isEdit && (
        <div
          className={cx(
            'disabled-input bg-bgDisabled text-fgMain font-body-sm flex items-center rounded-md px-3',
            {
              'pl-9': !isEdit && !!startIcon,
              'pr-9': !isEdit && !!endIcon,
              'min-h-6': sizeVariant === 'xs',
              'min-h-8': sizeVariant === 'sm',
              'min-h-10': sizeVariant === 'md',
            },
          )}
        >
          <div
            data-testid={`${testId}-display`}
            data-trackingid={`${trackingId}-display`}
            className={cx('font-body-sm w-full break-words', displayClassName)}
            title={title}
          >
            {children || defaultValue}
          </div>
          {includeCopyButton && (
            <CopyButton
              inputLabel={String(label ?? '')}
              text={String(children)}
              type="tertiary"
              size={Sizes.xs}
              testId={`${testId}-copy-button`}
              trackingId={`${trackingId}-copy-button`}
            />
          )}
        </div>
      )}
      {!shouldSkeleton && isEdit && (
        <div
          className={cx('relative', {
            'shadow-rest flex rounded-md': !!addon,
          })}
        >
          {!!addon && isEdit && (
            <span className="border-borderMuted bg-bgDisabled text-fgAlt font-label inline-flex items-center rounded-l-md border border-r-0 px-3">
              {addon}
            </span>
          )}
          {_startIcon}
          {isEdit && (
            <input
              {...props}
              defaultValue={!formMethods ? defaultValue : undefined}
              className={inputClassNames}
              type={type}
              data-testid={testId}
              data-trackingid={trackingId}
              disabled={isDisabled}
              aria-required={isOptional ? undefined : true}
              aria-describedby={
                description || errorMessage
                  ? `${errorMessage ? `field-${name}-error` : ''} ${
                      description ? `field-${name}-description` : ''
                    }`
                  : undefined
              }
              {...(registration ?? {})}
            />
          )}
          {_endIcon}
        </div>
      )}

      {shouldSkeleton && (
        <LoadingBlock loaderClassName="min-h-input w-full rounded-md" />
      )}

      <FormFieldMessage
        name={name}
        description={description}
        errorMessage={errorMessage}
        isEdit={isEdit}
        shouldHideErrorLabel={shouldHideErrorLabel}
        testId={testId}
        trackingId={trackingId}
      />
    </Field>
  );
};
