import { isAfter, isBefore, isValid, parse } from 'date-fns';
import { enUS } from 'date-fns/locale';

export const DATE_SEPARATOR = '/';

const dateRegex = /^([1-9]|0[1-9]|1[0-2])\/([1-9]|0[1-9]|1\d|2\d|3[01])\/(19|20)\d{2}$/;

/**
 * Formats a date object to a string.
 * Used instead of date-fns format because it has strange year formatting behavior
 *
 * @param date a date object
 * @returns a string with the date in the format mm/dd/yyyy
 */
export const getFormattedDate = (date: Date): string => {
  const month = date.getMonth() + 1; // getMonth is zero indexed
  const day = date.getDate();
  const year = date.getFullYear();
  return `${month}${DATE_SEPARATOR}${day}${DATE_SEPARATOR}${year}`;
};

/**
 * Checks if a string is a valid date in the format MM/dd/yyyy
 *
 * @param str A string
 * @returns a boolean indicating whether the string is a valid date
 */
const isValidDateString = (str: string): boolean => {
  const parsedDate = parse(str, 'P', new Date(), { locale: enUS });
  const valid = isValid(parsedDate);
  return valid;
};

/**
 * Checks if a string is in a valid date format, and that it is within the provided range
 *
 * @param str The input value
 * @param minDate The minimum allowed date
 * @param maxDate The maximum allowed date
 * @returns a boolean indicating whether the input is valid
 */
export const isValidDateInput = (str: string, min?: Date, max?: Date): boolean => {
  const isValidFormat = dateRegex.test(str);
  const isValidDate = isValidDateString(str);
  if (isValidFormat && isValidDate) {
    const date = new Date(str);

    if (isDateInBounds(date, min, max)) {
      return true;
    }
  }

  return false;
};

/**
 * Checks if a date object is in bounds
 *
 * @param date The date value
 * @param minDate The minimum allowed date
 * @param maxDate The maximum allowed date
 * @returns a boolean indicating whether the date is in bounds
 */
export const isDateInBounds = (date: Date, min?: Date, max?: Date): boolean => {
  return (!min || isAfter(date, min)) && (!max || isBefore(max, date));
};

/**
 * Converts a string to a date object and ensures that year values less than four digits are handled correctly
 *
 * @param str The input value
 * @returns a date object
 */
export const getDateFromInput = (str: string): Date => {
  const values = str.split(DATE_SEPARATOR);
  const year = parseInt(values[2]);
  const date = new Date(str);
  date.setFullYear(year);

  return date;
};
