import { To } from 'react-router-dom';
import { Link } from 'react-router-dom';
import cx from 'classnames';

import { Icon } from '../../Icon/Icon';
import { type Ryecon, RyeconCaretRight } from '../../ryecons';

export type CellActionBase = {
  iconAlt?: string;
  iconClassName?: string;
  isDisabled?: boolean;
  ryecon: Ryecon;
};

export type OnClickAction = CellActionBase & {
  href?: never;
  onClick(id?: number): void;
};

export type LinkClickAction = CellActionBase & {
  href: To;
  onClick?: never;
};

export type CellAction = OnClickAction | LinkClickAction;

export interface ActionCellProps {
  actions?: CellAction[];
  rowId?: number;
}

type ActionCellActionProps = {
  action: CellAction;
  rowId: number | undefined;
};

const isLinkAction = (action: CellAction): action is LinkClickAction =>
  'href' in action && typeof action.href === 'string' && action.href !== '';

const isClickAction = (action: CellAction): action is OnClickAction =>
  !isLinkAction(action);

const ActionCellAction = ({ action, rowId }: ActionCellActionProps) => {
  const classes = cx('transition-colors', {
    'text-fgDecorative': !action.isDisabled,
    'text-fgDisabled': action.isDisabled,
  });
  if (isLinkAction(action)) {
    return (
      <Link
        to={action.isDisabled ? '' : action.href}
        aria-disabled={action.isDisabled}
        className={classes}
      >
        <Icon
          alt={action.iconAlt}
          ryecon={action.ryecon}
          className={action.iconClassName}
          size="md"
        />
      </Link>
    );
  }

  if (isClickAction(action) && typeof rowId === 'number') {
    return (
      <button
        className={classes}
        onClick={(e) => {
          e.stopPropagation();
          e.preventDefault();
          if (!action.isDisabled) {
            action.onClick(rowId);
          }
        }}
        type="button"
      >
        <Icon
          alt={action.iconAlt}
          ryecon={action.ryecon}
          className={action.iconClassName}
          size="md"
        />
      </button>
    );
  }
  return null;
};

export const ActionCell: React.FC<ActionCellProps> = ({ actions, rowId }) => {
  if (!actions || actions.length === 0) {
    return (
      <div className="text-fgAlt">
        <Icon ryecon={RyeconCaretRight} size="md" />
      </div>
    );
  }
  return (
    <div className="grid w-full auto-cols-min grid-flow-col grid-rows-1 justify-end justify-items-end gap-3">
      {actions.map((action: CellAction, index: number) => (
        <ActionCellAction key={index} action={action} rowId={rowId} />
      ))}
    </div>
  );
};
