import { useCallback, useState } from 'react';

import { PaginationProps } from './Pagination';

export interface UsePaginationArgs {
  /**
   * The initial current page
   */
  initialCurrentPage?: number;

  /**
   * The initial rows per page
   */
  initialRowsPerPage?: number;

  /**
   * An event bubbler for when onPageChange is called.
   */
  onPageChange?: (page: number) => void;

  /**
   * An event bubbler for when onRowsPerPageChange is called.
   */
  onRowsPerPageChange?: (rowsPerPage: number) => void;

  /**
   * The total number of rows that the pagination component is handling. totalRows is 0 index.  Ex: If there are 14 rows, pass 13 (rowsArray.length)
   */
  totalRows: number;
}

/**
 * External hook for keeping pagination state.  Should be used in conjunction with the Pagination component.
 * Tracks currentPage, rowsPerPage and totalRows as well as provides onPageChange and onRowsPerPageChange handlers.
 */
function usePagination({
  initialCurrentPage = 0,
  initialRowsPerPage,
  onPageChange,
  onRowsPerPageChange,
  totalRows,
}: UsePaginationArgs): PaginationProps {
  const [currentPage, setCurrentPage] = useState(initialCurrentPage);
  const [rowsPerPage, setRowsPerPage] = useState(initialRowsPerPage || 10);

  const _onPageChange = useCallback(
    (page: number) => {
      onPageChange && onPageChange(page);
      setCurrentPage(page);
    },
    [onPageChange],
  );

  const _onRowsPerPageChange = useCallback(
    (rows: number) => {
      onRowsPerPageChange && onRowsPerPageChange(rows);
      setRowsPerPage(rows);

      setCurrentPage(0);
    },
    [onRowsPerPageChange],
  );

  return {
    currentPage,
    onPageChange: _onPageChange,
    rowsPerPage: initialRowsPerPage ? rowsPerPage : undefined,
    onRowsPerPageChange: initialRowsPerPage ? _onRowsPerPageChange : undefined,
    totalRows,
  };
}

export { usePagination };
