import React, { memo, useCallback, useMemo, useState } from 'react';

import { Button } from '../../Button';
import { Icon } from '../../Icon';
import { RyeconSpinner } from '../../ryecons';
import { Sizes } from '../../types';
import { FileTree } from '..';
import {
  FileTreeItem,
  FileTreeItemType,
  FileTreeItemWrapperProps,
  FileTreeProps,
  FONT_SIZE_TO_HEIGHT_MAP,
  type RawNodeData,
  TreeNodeValues,
} from '.';
import { useFileTreeHeight } from './utils/useFileTreeHeight';

export type LoadChildrenResult = {
  items: FileTreeItemType[];
  hasMore: boolean;
};

export type ExtendedNodeDataProps = TreeNodeValues & {
  isLoadingIndicator?: boolean;
  isLoadMoreButton?: boolean;
  parentPath?: string;
  isEmpty?: boolean;
};

export type ExtendedFileTreeItemType = Omit<FileTreeItemType, 'data'> & {
  data: {
    pathType: 'file' | 'directory' | 'loading' | 'load-more' | 'empty';
    name: string;
    relativePath: string;
    depth: number;
    gitStatus?: TreeNodeValues['gitStatus'];
    isEmpty?: boolean;
    isLoadingIndicator?: boolean;
    isLoadMoreButton?: boolean;
    parentPath?: string;
    rawData?: RawNodeData;
  };
};

export type LoadMoreFunction = (path: string) => void;

export type PaginatedFileTreeProps = FileTreeProps & {
  /**
   * Called when a directory is opened or "load more" is clicked
   * requester should be able to handle the call and add items to the file tree
   */
  loadChildren: LoadMoreFunction;

  /**
   * Custom load more button component
   */
  LoadMoreComponent?: React.ComponentType<{
    onClick: (e: React.MouseEvent) => void;
  }>;

  /**
   * Custom item renderer
   */
  itemRenderer?: React.ComponentType<FileTreeItemWrapperProps>;

  /**
   * The maximum height of the file tree
   */
  maxHeight?: number;
};

const DefaultLoadMoreButton = ({
  onClick,
}: {
  onClick: (e: React.MouseEvent) => void;
}) => (
  <Button type="tertiary" size={Sizes.xs} onClick={onClick}>
    Show more
  </Button>
);

export const PaginatedFileTree: React.FC<PaginatedFileTreeProps> = (
  props: PaginatedFileTreeProps,
) => {
  const {
    rootNodeName,
    items: fileTree,
    loadChildren,
    LoadMoreComponent = DefaultLoadMoreButton,
    itemRenderer,
    maxHeight,
    setOpenDirectories,
    openDirectories,
  } = props;
  const [loadedDirectories, setLoadedDirectories] = useState<Set<string>>(new Set());

  const handleOpenDirectory = useCallback(
    (
      fn: (directories: string[] | undefined) => string[] | undefined,
      event: React.MouseEvent,
    ) => {
      setOpenDirectories?.((prevOpen) => {
        const newOpen = fn(prevOpen) || [];

        // if not already 'loaded', load children, otherwise just toggle open
        const toggledDir =
          newOpen.find((dir: string) => !prevOpen?.includes(dir)) ||
          prevOpen?.find((dir: string) => !newOpen.includes(dir));

        if (
          toggledDir &&
          newOpen.includes(toggledDir) &&
          !loadedDirectories.has(toggledDir)
        ) {
          loadChildren(toggledDir);
          setLoadedDirectories((prev) => new Set([...prev, toggledDir as string]));
        }

        return newOpen;
      }, event as React.MouseEvent<HTMLButtonElement>);
    },
    [setOpenDirectories, loadedDirectories, loadChildren],
  );

  const isFolderEmpty = useCallback(
    (path: string) => {
      const items = fileTree.filter((item) => item.id.startsWith(path));
      return items.length === 1 && items[0].data.pathType === 'directory';
    },
    [fileTree],
  );

  const generateLoadingItems = useCallback(() => {
    const additionalItems: ExtendedFileTreeItemType[] = [];
    fileTree.forEach((item) => {
      const path = item.id;
      const pathDepth = path.split('/').length - 1;
      if (openDirectories?.includes(path)) {
        if (item.data.pagination?.isLoading) {
          additionalItems.push({
            id: `${path}/__loading__`,
            parent: path,
            text: '',
            data: {
              pathType: 'loading',
              name: '',
              relativePath: `${path}/__loading__`,
              depth: pathDepth + 1,
              isLoadingIndicator: true,
            },
          });
        }
        if (item.data.pagination?.hasMore) {
          additionalItems.push({
            id: `${path}/__load_more__`,
            parent: path,
            text: '',
            data: {
              pathType: 'load-more',
              name: '',
              relativePath: `${path}/__load_more__`,
              depth: pathDepth + 1,
              isLoadMoreButton: true,
              parentPath: path,
            },
          });
        }

        if (isFolderEmpty(path) && !item.data.pagination?.isLoading) {
          additionalItems.push({
            id: `${path}/__empty__`,
            parent: path,
            text: '',
            data: {
              pathType: 'empty',
              name: '',
              relativePath: `${path}/__empty__`,
              depth: pathDepth + 1,
              isEmpty: true,
            },
          });
        }
      }
    });

    return additionalItems;
  }, [fileTree, openDirectories, isFolderEmpty]);

  const combinedItems = useMemo(() => {
    return [...fileTree, ...generateLoadingItems()] as FileTreeItemType[];
  }, [fileTree, generateLoadingItems]);

  const FileTreeItemContainer = memo((props: FileTreeItemWrapperProps) => {
    const extendedData = props.data as ExtendedNodeDataProps;

    if (extendedData.isLoadingIndicator) {
      return (
        <div style={{ paddingLeft: props.data.depth * 18 }} className="mt-1">
          <Icon ryecon={RyeconSpinner} className="motion-safe:animate-spin" />
        </div>
      );
    }

    if (extendedData.isEmpty) {
      return (
        <div style={{ paddingLeft: props.data.depth * 18 }}>
          <span className="text-fgDecorative font-caption">No items</span>
        </div>
      );
    }

    if (extendedData.isLoadMoreButton) {
      const handleLoadMore = async (e: React.MouseEvent) => {
        e.stopPropagation();
        const parentPath = extendedData.parentPath;
        if (!parentPath) return;

        loadChildren(parentPath);
      };

      return (
        <div
          style={{ paddingLeft: props.data.depth * 18 }}
          className="flex h-[24px] items-center justify-start"
        >
          <div className="w-full">
            <LoadMoreComponent onClick={handleLoadMore} />
          </div>
        </div>
      );
    }

    if (itemRenderer) {
      const ItemRenderer = itemRenderer;
      return <ItemRenderer {...props} />;
    }

    return (
      <div
        data-testid="PaginatedFileTreeItemWrapper"
        style={{
          paddingLeft: props.data.depth * 18,
        }}
      >
        <FileTreeItem {...props} node={props.data} />
      </div>
    );
  });

  const fileTreeFinalProps = useMemo(() => {
    const commonProps = {
      ...props,
      items: combinedItems,
      setOpenDirectories: handleOpenDirectory,
    };

    return {
      ...commonProps,
      rootNodeName,
    };
  }, [combinedItems, props, handleOpenDirectory, rootNodeName]);

  // Hydrate the item heights with the default item height for load-more and loading
  // we set the them to be the same as the directory or file font size if provided
  // we need this to be able to calculate the height of the items in the file tree in the useFileTreeHeight hook
  const itemHeights = useMemo(() => {
    return {
      loadMore:
        FONT_SIZE_TO_HEIGHT_MAP[
          props.itemFontSize?.file || props.itemFontSize?.directory || 'text-sm'
        ],
      loading:
        FONT_SIZE_TO_HEIGHT_MAP[
          props.itemFontSize?.file || props.itemFontSize?.directory || 'text-sm'
        ],
      empty: FONT_SIZE_TO_HEIGHT_MAP['text-sm'],
      file: FONT_SIZE_TO_HEIGHT_MAP[props.itemFontSize?.file || 'text-sm'],
      directory: FONT_SIZE_TO_HEIGHT_MAP[props.itemFontSize?.directory || 'text-sm'],
      root: FONT_SIZE_TO_HEIGHT_MAP[props.itemFontSize?.root || 'text-sm'],
    };
  }, [props.itemFontSize]);

  const { containerHeight } = useFileTreeHeight({
    items: combinedItems,
    openDirectories: openDirectories || [],
    rootNodeName,
    maxHeight,
    itemHeights,
  });

  return (
    <div style={{ height: containerHeight }}>
      <FileTree {...fileTreeFinalProps}>{FileTreeItemContainer}</FileTree>
    </div>
  );
};
