import cx from 'classnames';

import { RegisterOptions, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { HelpIcon } from '../../HelpIcon';
import { Icon } from '../../Icon';
import { RyeconErrorOutline } from '../../ryecons';

export interface RadioButtonProps extends React.InputHTMLAttributes<HTMLInputElement> {
  /** A unique id for the radio button option */
  id: string;

  /** Label for the radio button option */
  label?: React.ReactNode;

  /** Description for the radio button option */
  description?: string;

  /** A link to a help page. Will be placed on a help icon to the right of the label. Only present if label exists. Do not use with onHelpClick! */
  helpLink?: BaseInputProps['helpLink'];

  /** A click handler for the HelpIcon. Will be placed on a help icon to the right of the label. Only present if label exists. Do not use with helpLink! */
  onHelpClick?: BaseInputProps['onHelpClick'];
}

interface BaseRadioGroupProps {
  name: string;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** Array of radio buttons to display in the group */
  options: RadioButtonProps[];

  /** Label Text */
  label?: React.ReactNode;

  /** Description Text */
  description?: React.ReactNode;

  /** react-hook-form register config, accepts any options react-hook-form's register can accept. */
  formConfig?: RegisterOptions;

  /** Class names for the input element(s) */
  inputClassName?: string;

  /** Custom onChange handler. Allows for extra handling past the default react-hook-form usage */
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;

  /**
   * The default selected option. For use in standalone checkboxes only.
   * For setting defaults in react-hook-form, use the defaultValues object passed to useForm instead.
   */
  defaultOptionId?: string;

  /** Boolean to determine whether radio buttons should be displayed horizontally */
  isInline?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;

  /** used when you want to control the value of the radio group from outside the component */
  value?: string;
}

type RadioGroupProps = BaseRadioGroupProps & BaseInputProps;

export const RadioGroup: React.FC<RadioGroupProps> = ({
  name,
  children,
  label,
  description,
  defaultOptionId,
  className,
  inputClassName,
  error,
  onChange,
  formConfig = {},
  helpLink,
  isDisabled,
  isEdit,
  onHelpClick,
  options,
  isInline,
  testId = 'radio',
  trackingId = 'radio',
  value,
}) => {
  const formMethods = useFormContext();
  const registration = formMethods?.register;
  const isControlled = !!value;
  const errors = formMethods?.formState?.errors ?? {};
  const errorMessage = errors[name]?.message ?? error;
  const hasError = !!errorMessage;

  const hasCustomViewOnly = !!children;

  const shouldHaveStandardStyles = !hasError && isEdit && !isDisabled;
  const shouldHaveErrorStyles = hasError && isEdit && !isDisabled;
  const shouldHaveDisabledStyles = !isEdit || isDisabled;

  const radioGroupClasses = cx(inputClassName, 'h4 w4 mt-1', {
    'text-fgBrandSelection focus:ring-focusBrand border-borderMain hover:border-borderMainHover hover:bg-bgMainHover focus:ring-offset-bgMain active:bg-bgMainActive cursor-pointer bg-transparent':
      shouldHaveStandardStyles,
    'border-borderMain text-fgBrandSelection focus:ring-focusBrand focus:ring-offset-bgMain bg-transparent':
      shouldHaveErrorStyles,
    'bg-bgDisabled text-fgDisabled cursor-not-allowed border-transparent':
      shouldHaveDisabledStyles,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(e);
    formMethods?.setValue(name, e.target.value);
  };

  return (
    <div
      className={className}
      data-testid={`${testId}-group`}
      data-trackingid={`${trackingId}-group`}
      aria-describedby={hasError ? `${name}-error` : `${name}-description`}
    >
      {!!label && (
        <label
          className={cx('font-label-lg flex', {
            'text-fgAlt': !hasError && !isDisabled,
            'text-fgDanger': hasError && isEdit && !isDisabled,
            'flex w-full items-center': helpLink || onHelpClick,
            'cursor-not-allowed': shouldHaveDisabledStyles,
            'cursor-pointer': shouldHaveStandardStyles,
          })}
        >
          <span>{label}</span>
          {Boolean(helpLink) && !onHelpClick && (
            <HelpIcon className="ml-1 flex items-center" linkTo={helpLink} />
          )}
          {!helpLink && onHelpClick && (
            <HelpIcon className="ml-1 flex items-center" onClick={onHelpClick} />
          )}
        </label>
      )}
      {!!description && !hasError && (
        <p
          id={`${name}-description`}
          className={cx('font-body', {
            'text-fgDecorative': !hasError,
          })}
          data-testid={`${testId}-description`}
          data-trackingid={`${trackingId}-description`}
        >
          {description}
        </p>
      )}
      {hasError && isEdit && (
        <p
          className="text-fgDanger font-caption flex items-center gap-1.5"
          id={`${name}-error`}
          data-testid={`${testId}-error`}
          data-trackingid={`${trackingId}-error`}
        >
          <Icon
            ryecon={RyeconErrorOutline}
            size="sm"
            className="shrink-0"
            alt="error"
          />
          <>{errorMessage}</>
        </p>
      )}
      {!isEdit && hasCustomViewOnly && (
        <div
          data-testid={`${testId}-display`}
          data-trackingid={`${trackingId}-display`}
          className="min-h-input bg-bgDisabled font-label rounded-md px-3 py-2"
        >
          {children}
        </div>
      )}
      {(isEdit || !hasCustomViewOnly) && (
        <fieldset>
          <legend className="sr-only">{name}</legend>
          <div className={cx({ flex: isInline })}>
            {options.map((option, index) => {
              const {
                id,
                description: optionDescription,
                label: optionLabel,
                helpLink: optionHelpLink,
                onHelpClick: onOptionHelpClick,
                ...optionProps
              } = option;

              return (
                <label
                  key={option.id}
                  data-testid={`${testId}-buttons-wrapper`}
                  data-trackingid={`${trackingId}-buttons-wrapper`}
                  className={cx({ 'mr-6': isInline })}
                >
                  <div className="relative mt-5 flex items-start">
                    <div className="flex items-center">
                      <input
                        aria-describedby={`${id}-description`}
                        type="radio"
                        data-testid={`${testId}-button-${index}`}
                        data-trackingid={`${trackingId}-button-${index}`}
                        defaultChecked={
                          isControlled ? undefined : id === defaultOptionId
                        }
                        className={radioGroupClasses}
                        disabled={isDisabled || !isEdit}
                        value={id}
                        {...(registration
                          ? registration(name, {
                              ...formConfig,
                              onChange: handleChange,
                            })
                          : {
                              name: name,
                              onChange: handleChange,
                            })}
                        {...optionProps}
                        checked={isControlled ? id === value : undefined}
                      />
                    </div>
                    {(!!optionLabel || !!optionDescription) && (
                      <div className="ml-3">
                        <div
                          className={cx('font-label-lg pt-0.5', {
                            'text-fgAlt': !hasError && !isDisabled,
                            'text-fgDanger': hasError && isEdit && !isDisabled,
                            'flex w-full':
                              (optionHelpLink || onOptionHelpClick) && !isInline,
                            'inline-flex':
                              (optionHelpLink || onOptionHelpClick) && isInline,
                            'items-center': optionHelpLink || onOptionHelpClick,
                            'cursor-not-allowed': shouldHaveDisabledStyles,
                            'cursor-pointer': shouldHaveStandardStyles,
                          })}
                        >
                          <span>{optionLabel}</span>
                          {Boolean(optionHelpLink) && !onOptionHelpClick && (
                            <HelpIcon
                              className="ml-1 flex items-center"
                              linkTo={optionHelpLink}
                            />
                          )}
                          {!optionHelpLink && onOptionHelpClick && (
                            <HelpIcon
                              className="ml-1 flex items-center"
                              onClick={onOptionHelpClick}
                            />
                          )}
                        </div>
                        {optionDescription && (
                          <div
                            id={`${id}-description`}
                            className={cx('font-caption', {
                              'text-fgDecorative': !hasError,
                              'cursor-not-allowed': isDisabled,
                              'cursor-pointer': isEdit,
                              'text-fgDanger': hasError && isEdit && !isDisabled,
                            })}
                          >
                            {optionDescription}
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                </label>
              );
            })}
          </div>
        </fieldset>
      )}
    </div>
  );
};
