import { Fragment } from 'react';

import { UseFormReturn } from '@/externals/react-hook-form';
import { getValidationError } from '../../utils/formUtils';
import { Sizes } from '..';
import { RyeconClose, RyeconPencil } from '../ryecons';
import { ActionList } from './Actions';

interface DefaultActionConfig {
  /** Whether the page is in edit mode */
  isEdit: boolean;

  /** Whether to disable all buttons. Commonly used for `isSaving` states */
  isDisabled?: boolean;

  /** Whether the current user has permission to edit the resource */
  canEdit?: boolean;

  /** Edit handler */
  onEdit?: () => void;

  /** Cancel handler */
  onCancel?: () => void;

  /** Submit handler */
  onSubmit: (data: any) => void;

  /** Override the `save` text */
  saveText?: string;

  /** Whether a save mutation is underway */
  isSaving?: boolean;

  /** Whether to disable the save button */
  disableSave?: boolean;

  /** Whether to display a success button state. Usually passed temporarily via  useSuccessState() */
  showSuccessState?: boolean;

  /** Form methods from react-hook-form */
  formMethods: UseFormReturn;

  /** Size override for all buttons */
  size?: Sizes;

  /** Whether to make the edit button use secondary styling */
  useSecondaryEdit?: boolean;

  /** Optional tooltip for cancel action */
  cancelTooltip?: string;

  /** Optional tooltip for save action */
  saveTooltip?: string;

  /** Optional tooltip for edit action */
  editTooltip?: string;

  /** Extra context for the Edit/Cancel buttons; useful if there are multiple on a page! */
  actionsLabel?: string;
}

export const getDefaultActions = (config: DefaultActionConfig): ActionList => {
  const {
    isEdit,
    isDisabled,
    disableSave,
    canEdit = true,
    onSubmit,
    isSaving,
    saveText,
    onCancel,
    onEdit,
    formMethods,
    size = Sizes.md,
    showSuccessState = false,
    useSecondaryEdit,
    cancelTooltip,
    saveTooltip,
    editTooltip,
    actionsLabel,
  } = config;

  const hasValidationError = getValidationError(formMethods);

  const baseActions: ActionList = isEdit
    ? [
        {
          text: (
            <Fragment>
              Cancel
              {actionsLabel && <span className="sr-only"> editing {actionsLabel}</span>}
            </Fragment>
          ),
          tooltip: cancelTooltip,
          onClick: () => {
            formMethods.reset();
            onCancel?.();
          },
          buttonProps: {
            type: 'secondary',
            ryecon: RyeconClose,
            size,
            isDisabled: isDisabled || isSaving,
          },
        },
        {
          state: hasValidationError ? 'error' : isSaving ? 'saving' : 'default',
          onClick: () => formMethods.handleSubmit(onSubmit)(),
          size,
          isDisabled: isDisabled || disableSave || isSaving,
          defaultText: saveText,
          tooltip: saveTooltip,
        },
      ]
    : [
        {
          text: (
            <Fragment>
              Edit
              {actionsLabel && <span className="sr-only"> {actionsLabel}</span>}
            </Fragment>
          ),
          tooltip: editTooltip,
          onClick: () => {
            formMethods.reset();
            onEdit?.();
          },
          buttonProps: {
            ryecon: RyeconPencil,
            size,
            type: useSecondaryEdit ? 'secondary' : 'primary',
            isDisabled: !canEdit || isDisabled || isSaving,
          },
        },
      ];

  return showSuccessState
    ? [
        {
          state: 'success',
          size: size,
        },
      ]
    : baseActions;
};
