import { FC, ReactNode, useMemo } from 'react';
import cx from 'classnames';

import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { Ryecon, RyeconProps, RyeconSpinner } from '../ryecons';

export type MetricTileProps = {
  /** Renders a loading state (including icons if used) */
  skeleton?: boolean;

  /** Smaller descriptive text or a link below the `value` */
  subtext?: ReactNode;

  /** Can be used to override or enhance `subtext` styles */
  subtextClassName?: string;

  /** Used to insert an icon before `subtext` */
  subtextIcon?: Ryecon;

  /** Used to adjust the `subtextIcon` */
  subtextIconProps?: RyeconProps;

  /** A label for the `value` */
  title: string;

  /** Can be used to override or enhance `title` styles */
  titleClassName?: string;

  /** The primary metric, statistic, or number */
  value: ReactNode;

  /** Can be used to override or enhance `value` styles */
  valueClassName?: string;

  /** Used to insert an icon before the `value` */
  valueIcon?: Ryecon;

  /** Used to adjust the `valueIcon` */
  valueIconProps?: RyeconProps;

  /** Take care not to override flex, gap, and padding */
  className?: string;
  testId?: string;
};

const LoadingSpinner = () => <RyeconSpinner className="motion-safe:animate-spin" />;

export const MetricTile: FC<MetricTileProps> = ({
  className,
  skeleton,
  subtext,
  subtextClassName,
  subtextIcon: SubtextIcon,
  subtextIconProps = {},
  testId,
  title,
  titleClassName,
  value,
  valueClassName,
  valueIcon: ValueIcon,
  valueIconProps = {},
}) => {
  const _value = useMemo(() => {
    if (skeleton) {
      const loadingBlock = <LoadingBlock width={120} height={25} />;

      return ValueIcon ? (
        <div className="text-fgMain flex items-center gap-2">
          <LoadingSpinner />
          {loadingBlock}
        </div>
      ) : (
        loadingBlock
      );
    }

    const valueNode = (
      <div className={cx('text-fgMain font-body-lg font-medium', valueClassName)}>
        {value}
      </div>
    );

    return ValueIcon ? (
      <div className="text-fgMain flex items-center gap-2">
        <ValueIcon size="xl" {...valueIconProps} />
        {valueNode}
      </div>
    ) : (
      valueNode
    );
  }, [skeleton, value, valueClassName, ValueIcon, valueIconProps]);

  const _subtext = useMemo(() => {
    if (!subtext) {
      return null;
    }

    if (skeleton) {
      const loadingBlock = <LoadingBlock width={120} height={19} />;

      return SubtextIcon ? (
        <div className="text-fgDecorative flex items-center gap-2">
          <LoadingSpinner />
          {loadingBlock}
        </div>
      ) : (
        loadingBlock
      );
    }

    const subtextNode = (
      <div className={cx('text-fgDecorative font-label', subtextClassName)}>
        {subtext}
      </div>
    );

    return SubtextIcon ? (
      <div className="text-fgDecorative flex items-center gap-2">
        <SubtextIcon size="xs" {...subtextIconProps} />
        {subtextNode}
      </div>
    ) : (
      subtextNode
    );
  }, [skeleton, subtext, subtextClassName, SubtextIcon, subtextIconProps]);

  return (
    <div
      className={cx('flex flex-col gap-1 rounded px-4 py-2', className)}
      data-testid={testId}
    >
      <div className={cx('text-fgAlt font-caption', titleClassName)}>{title}</div>
      {_value}
      {_subtext}
    </div>
  );
};
