import { forwardRef, ReactNode } from 'react';
import cx from 'classnames';

export interface AccordionBodyProps {
  /** The content of the accordion */
  children?: ReactNode;
  /** If the accordion is open / closed */
  isOpen: boolean;
  /** The css height of the accordion content */
  height: string | number;
  /** The class for the wrapper div */
  wrapperClassName?: string;
  /** The class for the content div */
  className?: string;
}

// Uses a dirty ref trick because this version of React / JSX doesn't understand that inert is a valid attribute
// @see {@link https://developer.mozilla.org/en-US/docs/Web/HTML/Global_attributes/inert MDN Web Docs}
const AccordionBody = forwardRef<HTMLDivElement, AccordionBodyProps>(
  ({ children, isOpen, height, wrapperClassName, className }, ref) => (
    <div
      aria-hidden={isOpen ? undefined : true}
      className={cx(
        wrapperClassName,
        'overflow-hidden p-0 transition-[height] duration-300 ease-in-out',
      )}
      ref={(node) => {
        if (node) {
          if (isOpen) {
            node.removeAttribute('inert');
          } else {
            node.setAttribute('inert', '');
          }
        }
      }}
      style={{
        height: isOpen ? height : 0,
      }}
    >
      <div
        className={cx('text-fgAlt', className)}
        ref={ref}
        data-testid="accordion-content"
      >
        {children}
      </div>
    </div>
  ),
);

export { AccordionBody };
