import { FileTreeItemType } from '../types';
import { generateFilesystemSortKey } from './generateFilesystemSortKey';

export const sortNodes = (
  a: FileTreeItemType,
  b: FileTreeItemType,
  onSort?: (a: string, b: string) => number,
): number => {
  if (!a.data || !b.data) return -1;
  // Load more and loading nodes are always at the bottom
  if (a.id.includes('__load_more__') || a.id.includes('__loading__')) return 1;
  if (b.id.includes('__load_more__') || b.id.includes('__loading__')) return -1;
  const aKey = generateFilesystemSortKey(a.id, a.data.pathType);
  const bKey = generateFilesystemSortKey(b.id, b.data.pathType);
  return onSort ? onSort(aKey, bKey) : aKey.localeCompare(bKey);
};
