import { useCallback, useMemo } from 'react';

import { useTheme } from '../context/ThemeProvider';

/**
 * helper hook to replace existing usage of useDarkMode.
 * this should be phased out in favor of the more inclusive useTheme hook
 * so we can support more themes in the future
 */
export const useDarkMode = () => {
  const { themeClass, setTheme } = useTheme();

  const setIsDark = useCallback(
    (isDark: boolean) => {
      setTheme(isDark ? 'dark' : 'light');
    },
    [setTheme],
  );

  return useMemo(
    () => ({
      isDark: themeClass === 'dark',
      setIsDark,
    }),
    [themeClass, setIsDark],
  );
};
