import { type FC, type MouseEvent, useMemo } from 'react';
import cx from 'classnames';

import { RyeconClose } from '../../ryecons';
import { ListSub } from './subcomponents/List';
import { TextareaSub } from './subcomponents/Textarea';
import type { ClickCallback, PillData, PillProps } from './types';

const baseClasses =
  'flex items-center rounded-full border font-label w-fit text-fgMain bg-bgBadgeNeutralMuted border-borderBadgeNeutralMuted';

const baseValueClasses = 'rounded-l-full pl-2 pr-1 py-[3px]';
const baseRemoveClasses = 'rounded-r-full pl-1 h-full inline-flex items-center';
const interactiveClasses = 'hover:text-fgAltHover hover:bg-bgMainHover';

const createHandler =
  (pillData: PillData, cb?: ClickCallback) => (e: MouseEvent<HTMLButtonElement>) => {
    e.stopPropagation();

    if (cb) {
      cb(pillData);
    }
  };

type SubComponents = {
  List: typeof ListSub;
  Textarea: typeof TextareaSub;
};

/**
 * visual representation of a single value and an optional remove button
 * will call appropriate interaction handlers that the parent component can respond to
 */
export const Pill: FC<PillProps> & SubComponents = ({
  id,
  value,
  onClickValue,
  onClickRemove,
  className,
  valueClassName,
  removeClassName,
  testId = 'pill',
  trackingId = 'pill',
}) => {
  const isRemovable = !!onClickRemove;
  const isClickable = !!onClickValue;

  const handleClickValue = useMemo(
    () => createHandler({ id, value }, onClickValue),
    [onClickValue, id, value],
  );

  const handleClickRemove = useMemo(
    () => createHandler({ id, value }, onClickRemove),
    [onClickRemove, id, value],
  );

  return (
    <div
      className={cx(baseClasses, className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {isClickable ? (
        <button
          type="button"
          onClick={handleClickValue}
          className={cx(baseValueClasses, interactiveClasses, valueClassName)}
          data-testid={`${testId}-value-button`}
          data-trackingid={`${testId}-value-button`}
        >
          {value}
        </button>
      ) : (
        <span
          className={cx(baseValueClasses, valueClassName)}
          data-testid={`${testId}-value`}
          data-trackingid={`${testId}-value`}
        >
          {value}
        </span>
      )}

      {isRemovable ? (
        <button
          type="button"
          onClick={handleClickRemove}
          className={cx('pr-2', baseRemoveClasses, interactiveClasses, removeClassName)}
          data-testid={`${testId}-remove-button`}
          data-trackingid={`${testId}-remove-button`}
        >
          <span className="inline-flex items-center">
            <RyeconClose className="h-[10px] w-[10px]" />
          </span>
        </button>
      ) : (
        <span className={cx(baseRemoveClasses, removeClassName)} />
      )}
    </div>
  );
};

Pill.List = ListSub;
Pill.Textarea = TextareaSub;
