import {
  type ChangeEvent,
  type KeyboardEventHandler,
  useCallback,
  useState,
} from 'react';

import { useIMEComposition } from '../../../hooks/useIMEComposition';
import type { ClickCallback, PillData, UsePillState } from './types';
import { arePillsEqual, initPills, parsePills, pillsToStr } from './utils';

export const usePillState: UsePillState = ({ defaultValue, delimiter, onChange }) => {
  const [pills, setPills] = useState(initPills(defaultValue, delimiter));
  const [uncommitted, setUncommitted] = useState('');
  const {
    isComposingRef,
    onCompositionStart: handleCompositionStart,
    onCompositionEnd: handleCompositionEnd,
  } = useIMEComposition<HTMLTextAreaElement>();

  const handleChange = useCallback(
    (e: ChangeEvent<HTMLTextAreaElement>) => {
      const fullValue = pillsToStr(pills, delimiter, e.target.value);
      const { pills: nextPills, remaining } = parsePills(fullValue);

      if (onChange) {
        onChange(fullValue);
      }

      // only update state when values are different
      if (uncommitted !== remaining) {
        setUncommitted(remaining);
      }

      // pills are the same, do nothing
      if (nextPills.length === 0 || arePillsEqual(pills, nextPills)) {
        return;
      }
      // new pill parsed
      setPills(nextPills);
    },
    [pills, delimiter, uncommitted, onChange],
  );

  /**
   * remove pill by id
   */
  const handleRemove = useCallback<ClickCallback>(
    (toRemove) => {
      const nextPills = pills
        .filter(({ id }) => id !== toRemove.id)
        .map((pill, i) => ({ ...pill, id: `${i}` }));
      setPills(nextPills);

      if (onChange) {
        const nextValue = pillsToStr(nextPills, delimiter, uncommitted);
        onChange(nextValue);
      }
    },
    [pills, onChange, delimiter, uncommitted],
  );

  const handleKeyDown = useCallback<KeyboardEventHandler<HTMLTextAreaElement>>(
    (e) => {
      if (e.code === 'Enter') {
        // Allow Enter to pass through during IME composition (e.g. confirming
        // a Japanese/Chinese/Korean character conversion) without creating a pill.
        if (isComposingRef.current || e.nativeEvent.isComposing) {
          return;
        }

        e.preventDefault();
        e.stopPropagation();

        const hasNonWhitespaceChars = /\S/.test(uncommitted);
        if (!uncommitted || !hasNonWhitespaceChars) {
          return;
        }
        // commit current str to a new pill
        const nextPills: PillData[] = [
          ...pills,
          { id: `${pills.length}`, value: uncommitted.trim() },
        ];
        setPills(nextPills);
        setUncommitted('');
      }

      // fixes edge case where clearing input would cause a change event and `parsePills` would
      // re-set uncommitted to the remaining of fullValue i.e. pull in last pill
      if (e.code === 'Backspace' && uncommitted.length === 1) {
        setUncommitted('');
      }
    },
    [pills, uncommitted, isComposingRef],
  );

  return {
    handleChange,
    handleRemove,
    handleKeyDown,
    handleCompositionStart,
    handleCompositionEnd,
    pills,
    uncommitted,
  };
};
