import { ReactNode } from 'react';
import cx from 'classnames';

export interface CodeProps {
  /** The content of the accordion */
  children?: ReactNode;

  /** Classnames for the code */
  className?: string;
}

export const Code: React.FC<CodeProps> = ({
  children,
  className,
}): React.ReactElement => {
  return (
    <code
      className={cx(
        'bg-bgMainHover text-fgAlt font-code mx-0.5 rounded px-1 py-0.5',
        className,
      )}
    >
      {children}
    </code>
  );
};
