import { isRyeconIconProps, isStatusIconProps } from './helpers.internal';
import { RyeconIcon } from './renderers/RyeconIcon.internal';
import { StatusIcon } from './renderers/StatusIcon.internal';
import { IconProps } from './types';

/**
 * Wrapper component that determines and routes props to correct internal Icon component variant
 * StatusIcon
 * RyeconIcon
 * FaIcon
 */
export const Icon = (props: IconProps) => {
  if (isStatusIconProps(props)) {
    return <StatusIcon {...props} />;
  }

  if (isRyeconIconProps(props)) {
    return <RyeconIcon {...props} />;
  }

  // typescript should prevent this case
  return null;
};
