/**
 * The sort key is used to ensure files and directories are sorted in the correct order:
 *
 * 1. Directories before files
 * 2. Root is always first
 * 3. Same rules apply for each subfolder
 *
 * To achieve this order quickly, we create a sort key that enforces by appending a prefix
 *  to files and directories, which allow us to sort the list lexographically
 *
 */
export function generateFilesystemSortKey(
  relativePath: string | null,
  pathType: 'directory' | 'file',
): string {
  // Root is special. We make sure its always first by appending a '0' prefix
  if (relativePath === null) {
    return '0';
  }

  // For all other files/directories, we follow this pattern:
  // All directories get a '1' prefix, all files get a '2' prefix.
  // This solves the recursive constraint to sort folder before files.
  const relativePathParts = relativePath.split('/');

  // Remove trailing "/" if present
  let lastPart = relativePathParts.pop();
  if (!lastPart) {
    lastPart = relativePathParts.pop() ?? '';
  }

  // Mark up all the sub directories
  const modifiedParts = relativePathParts.map((p) => `1${p}`);

  // Mark up the last part of the path
  modifiedParts.push(pathType === 'directory' ? `1${lastPart}/` : `2${lastPart}`);

  // Regenerate
  return modifiedParts.join('/');
}
