import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { ColorSet } from '../../Chart/Color';
import { InteractionMeta, Shape } from '../../types';
import {
  calculateXOffset,
  calculateXPosition,
  CategoryAxisScale,
  LinearAxisScale,
  LogAxisScale,
  TimeAxisScale,
} from '../../util';
import { isPlotFocused } from '../../util/plot';

export interface DotExtras {
  className?: string;
  styledDotComponent?: Shape;
}

export interface SingleDotExtras {
  x?: number;
  y?: number;
}

const TOOLTIP_MARGIN = 10;

/** @deprecated */
export const CircleStyleDot: Shape<SingleDotExtras & { item: unknown }> = ({
  chartMeta,
  x,
  y,
  getColor,
  plotId,
  item,
  testId,
}) => {
  const focus = chartMeta?.focusPlotId;

  return (
    <circle
      data-testid={testId ?? `${chartMeta?.testId}-dot`}
      cx={x}
      cy={y}
      r={3}
      className={cx(
        'stroke-1 transition-colors',
        createDotClassNames(
          getColor(),
          isPlotFocused(focus, plotId),
          item === chartMeta?.interactionItem?.item,
        ),
      )}
    />
  );
};

CircleStyleDot.shapeName = 'CircleStyleDot';

/** @deprecated */
export const SquareStyleDot: Shape<SingleDotExtras & { item: unknown }> = ({
  chartMeta,
  x,
  y,
  getColor,
  plotId,
  item,
  testId,
}) => {
  const focus = chartMeta?.focusPlotId;

  return (
    <rect
      data-testid={testId ?? `${chartMeta?.testId}-dot`}
      x={x}
      y={y}
      width={5}
      height={5}
      className={cx(
        'stroke-1',
        createDotClassNames(
          getColor(),
          isPlotFocused(focus, plotId),
          item === chartMeta?.interactionItem?.item,
        ),
      )}
    />
  );
};
SquareStyleDot.shapeName = 'SquareStyleDot';

/** @deprecated */
export const Dot: Shape<DotExtras & { item: unknown }> = ({
  chartMeta,
  xAccessor,
  yAccessor,
  item,
  styledDotComponent,
  plotId,
  getColor,
  testId,
}) => {
  const xScale = chartMeta?.xScale as CategoryAxisScale | TimeAxisScale;
  const yScale = chartMeta?.yScale as LinearAxisScale | LogAxisScale;

  const getX = xAccessor ?? chartMeta?.xAccessor;
  const getY = yAccessor ?? chartMeta?.yAccessor;

  const xOffset = calculateXOffset(xScale);

  const xCoordinate = (xScale.scale(getX ? getX(item) : 0) ?? 0) + xOffset;
  const yCoordinate = yScale.scale(getY ? getY(item) : 0) ?? 0;

  const DotComponent = styledDotComponent ?? CircleStyleDot;

  return (
    <DotComponent
      testId={testId}
      chartMeta={chartMeta}
      x={xCoordinate}
      y={yCoordinate}
      item={item}
      plotId={plotId}
      getColor={getColor}
    />
  );
};

Dot.shapeName = 'Dot';

/** @deprecated */
export const Dots: Shape<DotExtras> = (props) => {
  const { data, chartMeta } = props;
  const testIdPrefix = chartMeta?.testId ?? 'chart';

  return (
    <g>
      {data?.map((item, idx) => (
        <Dot {...props} item={item} key={idx} testId={`${testIdPrefix}-dot-${idx}`} />
      ))}
    </g>
  );
};

Dots.shapeName = 'Dots';

Dots.getInteractionMeta = ({ chartMeta }): InteractionMeta => {
  const xOffset = chartMeta ? calculateXOffset(chartMeta?.xScale) : 0;
  return {
    tooltipX: { at: 'center', offset: xOffset },
    tooltipY: { at: 'bottom', offset: -TOOLTIP_MARGIN },
  };
};

Dots.getInteractionPoints = ({ chartMeta, plot, item }) => {
  const xOffset = calculateXPosition(chartMeta?.xScale, false, 0);
  const xCoordinate =
    (chartMeta?.xScale.scale(plot.xAccessor(item)) ?? 0) + xOffset / 2;
  const yCoordinate = chartMeta?.yScale.scale(plot.yAccessor(item)) ?? 0;

  return [
    {
      plotName: plot.name,
      plotId: plot.id,
      fullItem: item,
      shape: plot.shape,
      point: [xCoordinate, yCoordinate],
    },
  ];
};

export const createDotClassNames = (
  colorSet: ColorSet,
  focused: boolean,
  interaction: boolean,
) => {
  let extraClasses: string | undefined = '';
  if (focused && interaction) {
    extraClasses = cx(colorSet.strokeInteract, colorSet.fillInteract);
  }

  if (focused && !interaction) {
    extraClasses = colorSet.focused;
  }

  if (!focused) {
    extraClasses = colorSet.unfocused;
  }

  return twMerge(cx(colorSet.stroke, colorSet.fill), extraClasses);
};
