import { useCallback, useState } from 'react';

import { Button, ButtonStyleType } from '../Button';
import { RyeconCheckmark, RyeconCopy } from '../ryecons';
import { Sizes } from '../types';

export interface CopyButtonProps {
  /** label text of the input where the copied text comes from */
  inputLabel?: string;

  /** The text to copy when clicked */
  text: string;

  /** Custom classnames */
  className?: string;

  /** The Copy Button style type */
  type?: ButtonStyleType;

  /** The button size */
  size?: Sizes;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const CopyButton: React.FC<CopyButtonProps> = ({
  inputLabel = '',
  text,
  className,
  type = 'primary',
  size,
  testId = 'copy-button',
  trackingId = 'copy-button',
}): React.ReactElement => {
  const [copied, setCopied] = useState(false);

  const handleClick = useCallback(() => {
    navigator.clipboard.writeText(text);
    setCopied(true);

    setTimeout(() => {
      setCopied(false);
    }, 2000);
  }, [text]);

  const buttonText = copied ? (
    'Copied'
  ) : (
    <span>Copy{inputLabel && <span className="sr-only"> {inputLabel}</span>}</span>
  );
  const buttonRyecon = copied ? RyeconCheckmark : RyeconCopy;

  return (
    <div>
      <Button
        type={type}
        size={size}
        isDisabled={copied}
        onClick={handleClick}
        testId={testId}
        trackingId={trackingId}
        className={className}
        ryecon={buttonRyecon}
        text={buttonText}
      />
      <div aria-live="polite" className="sr-only">
        {copied && `Copied ${inputLabel} to clipboard`}
      </div>
    </div>
  );
};
