import { numberToCommaSeperatedString } from '../../utils/numberToCommaSeperatedString';
import { Label } from '../Text/Label/Label';

interface PaginationCountProps {
  currentPage: number;
  rowsPerPage: number;
  totalRows: number;
}

const PaginationCount = ({
  currentPage,
  rowsPerPage,
  totalRows,
}: PaginationCountProps) => {
  const start = currentPage * rowsPerPage + 1;
  let end = currentPage * rowsPerPage + rowsPerPage;
  if (end > totalRows) {
    end = totalRows;
  }

  return (
    <div className="ml-2 flex items-center gap-1" aria-live="polite" role="status">
      <span className="sr-only">results </span>
      <Label className="text-fgDecorative">{`${numberToCommaSeperatedString(
        start,
      )}-${numberToCommaSeperatedString(end)} of`}</Label>
      <Label className="text-fgMain">{`${numberToCommaSeperatedString(
        totalRows,
      )}`}</Label>
    </div>
  );
};

export default PaginationCount;
