import { useCallback, useMemo } from 'react';

import { PaginationProps } from './Pagination';

const DEFAULT_ROWS_PER_PAGE = 10;

/**
 * Internal pagination state.  Determines if the back and next buttons are disabled, what the currentPage is, and provides page change functions.
 */
const usePaginationInternal = ({
  currentPage = 0,
  onPageChange,
  rowsPerPage,
  totalRows,
}: PaginationProps) => {
  /**
   * Set an internal _rowsPerPage = 10 so we can figure out how many pages there are, even if the user didn't pass a rowsPerPage prop.
   */
  const _rowsPerPage = rowsPerPage || DEFAULT_ROWS_PER_PAGE;

  /**
   * The total number of pages
   */
  const totalPages = useMemo(() => {
    return Math.ceil(totalRows / _rowsPerPage);
  }, [_rowsPerPage, totalRows]);

  /**
   * Out of the total pages, only show 5.  The 5 shown will include the currently selected page.
   */
  const pageNumbersToShow = useMemo(() => {
    const allPages = Array.from(Array(totalPages).keys());
    if (allPages.length < 5) {
      return allPages;
    }
    let start = currentPage - 2;
    if (start < 0) {
      start = 0;
    }
    let end = start + 5;
    if (end > totalPages) {
      end = totalPages;
    }

    if (end === totalPages) {
      if (end - start < 5) {
        start = end - 5;
      }
    }

    return allPages.slice(start, end);
  }, [currentPage, totalPages]);

  /**
   * Handle the back caret button click
   */
  const doPageBack = useCallback(() => {
    let previousPage = currentPage - 1;
    if (previousPage < 0) {
      previousPage = 0;
    }
    onPageChange(previousPage);
  }, [currentPage, onPageChange]);

  /**
   * Handle the next caret button click
   */
  const doPageForward = useCallback(() => {
    let nextPage = currentPage + 1;
    if (nextPage >= totalPages - 1) {
      nextPage = totalPages - 1;
    }

    onPageChange(nextPage);
  }, [currentPage, onPageChange, totalPages]);

  /**
   * Handle the page button click
   */
  const goToPage = useCallback(
    (page: number) => () => {
      onPageChange(page);
    },
    [onPageChange],
  );

  const backButtonDisabled = currentPage === 0;
  const nextButtonDisabled = currentPage === totalPages;

  return {
    backButtonDisabled,
    currentPage,
    doPageBack,
    doPageForward,
    goToPage,
    nextButtonDisabled,
    pageNumbersToShow,
    totalPages,
  };
};

export default usePaginationInternal;
