import React from 'react';
import type { Placement } from '@floating-ui/react';
import { Menu } from '@headlessui/react';
import cx from 'classnames';

import type { TriggerLocation } from '../../hooks';
import { Button, type ButtonProps, type ButtonStyleType } from '../Button';
import { Icon } from '../Icon';
import { type MenuItem, type MenuItemGroup, MenuItems } from '../MenuItems';
import { RyeconCaretDown } from '../ryecons';
import { type Ryecon } from '../ryecons/types';
import { Sizes } from '../types';

export type RyeconVariant = {
  variant: 'ryecon';
  ryecon: Ryecon;
  /** An optional string which will show up when the button is hovered */
  tooltip?: string;
  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;
};

export interface MenuButtonProps {
  debug?: boolean;

  /** Accessible label for the button: optional for backward compatibility, will be required soon */
  label?: string;

  /** The button text */
  text?: string;

  /** An array of items for the menu */
  items: (MenuItem | MenuItemGroup)[];

  /**
   * Since value will be the label if no value is provided.
   * If multiple selections are allowed, always supply an array (empty or not)
   * to ensure consistent accessibility.
   */
  selectedValue?: string | null | string[];

  /** OnChange handler */
  onClick(item: string | number, event: React.MouseEvent): void;

  /** onMenuToggleClick */
  onMenuToggleClick?(event: React.MouseEvent): void;

  /** Placement options for the menu, auto will self-determine position */
  menuPlacement?: 'auto' | TriggerLocation;

  /** Align with the left or right edge of the trigger */
  menuAlignment?: 'left' | 'right';

  /**
   * If the menu placement is clipped by an overflow parent, setting this
   * to true will portal the MenuItems to the same place visually, but
   * into the nearest {@link PortalNodeContext}
   */
  shouldPortal?: boolean;

  /** Custom classnames for the menu items container */
  menuContainerClassName?: string;

  /**
   * If specified, we will use the element with this ID as the scroll parent
   * instead of automatically trying to detect it
   */
  menuScrollRootId?: string;

  /** Boolean representing whether this dropdown is disabled */
  isDisabled?: boolean;

  /** Custom wrapper classnames for the MenuButton */
  wrapperClassName?: string;

  /** Custom classnames for the MenuButton */
  className?: string;

  /** Button Variant */
  buttonVariant?: ButtonProps['variant'] | RyeconVariant;

  /** Button Type */
  buttonStyle?: ButtonStyleType;

  /** Button Size */
  size?: Sizes;

  /** Ryecon to the left of the button text */
  ryecon?: Ryecon;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const MenuButton: React.FC<MenuButtonProps> = ({
  text,
  label,
  items,
  ryecon,
  onClick,
  onMenuToggleClick,
  isDisabled,
  className,
  wrapperClassName,
  menuContainerClassName,
  selectedValue,
  menuScrollRootId,
  testId = 'menu-button',
  trackingId = 'menu-button',
  menuPlacement = 'auto',
  menuAlignment = 'left',
  buttonVariant = 'default',
  buttonStyle = 'secondary',
  size = Sizes.md,
  shouldPortal = false,
  debug = false,
}): React.ReactElement => {
  const isStringVariant = typeof buttonVariant === 'string';
  const isRyecon = !isStringVariant && buttonVariant.variant === 'ryecon';
  const isIconOnly = isRyecon && !text;

  const menuButtonVariant = isStringVariant ? buttonVariant : 'default';
  return (
    <div
      className={cx('relative', { 'inline-block': !shouldPortal }, wrapperClassName)}
    >
      <Menu as={React.Fragment}>
        <Menu.Button
          ariaLabel={label}
          as={Button}
          type={buttonStyle}
          ryecon={isRyecon ? buttonVariant.ryecon : ryecon}
          tooltip={isRyecon ? buttonVariant.tooltip : undefined}
          tooltipPortal={true}
          tooltipPlacement={isRyecon ? buttonVariant.tooltipPlacement : undefined}
          isIconOnly={isIconOnly}
          variant={menuButtonVariant}
          testId={testId}
          trackingId={trackingId}
          className={cx('items-center gap-2 focus-within:z-10', className, {
            'self-stretch': menuButtonVariant === 'group' && !text,
          })}
          isDisabled={isDisabled}
          size={size}
          onClick={onMenuToggleClick}
        >
          {!!text && <span className="font-label">{text}</span>}
          {!isRyecon && (
            <Icon
              ryecon={RyeconCaretDown}
              size={size}
              className={cx({ 'text-fgDisabled': isDisabled })}
            />
          )}
        </Menu.Button>
        <MenuItems
          items={items}
          selectedValue={selectedValue}
          onClick={onClick}
          testId={`${testId}-options`}
          trackingId={`${trackingId}-options`}
          placement={menuPlacement}
          alignment={menuAlignment}
          className={menuContainerClassName}
          shouldPortal={shouldPortal}
          scrollRootId={menuScrollRootId}
          debug={debug}
        />
      </Menu>
    </div>
  );
};
