import { Fragment, useCallback, useEffect, useState } from 'react';
import ReactDatePicker from 'react-datepicker';
import cx from 'classnames';

import { Disclosure, Transition } from '@/externals/headlessui';
import { useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../globalTypes';
import {
  Button,
  Icon,
  RyeconArrowBidirectional,
  RyeconCalendar,
  useSkeletonContext,
} from '../../sourdough';
import { Field } from '../forms';
import { FormFieldMessage } from '../forms/FormFieldMessage/FormFieldMessage';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { Sizes } from '../types';
import {
  getDateFromInput,
  getFormattedDate,
  isValidDateInput,
} from './DatepickerUtils';

import './Datepicker.css';

interface BaseDatepickerProps {
  /** A name for the datepicker. Used to differentiate inputs in forms */
  name: string;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** A default selected start date. If this is not a range picker, this will be the default selected date */
  defaultStartDate?: Date;

  /** A default selected end date.  */
  defaultEndDate?: Date;

  /** A boolean representing whether range selection should be enabled */
  isRange?: boolean;

  /** A description to display below the datepicker */
  description?: string;

  /** A date change callback function. Will be called when a new date or range is selected */
  onChange?: (date: Date | [Date | null, Date | null]) => void;

  /** A minimum date. Dates prior to this will be disabled */
  minDate?: Date;

  /** A maximum date. Dates later than this will be disabled */
  maxDate?: Date;

  /** The classname(s) for the datepicker input. Will be applied to the inputs only */
  inputClassName?: string;

  /** A boolean representing whether datepicker values are required. Only checked when used with react-hook-form */
  isRequired?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export type DatepickerProps = BaseDatepickerProps & BaseInputProps;

export const START_DATE_KEY = 'start-date';
export const END_DATE_KEY = 'end-date';

interface BaseDatepickerInputProps {
  name: string;
  selectedDate: Date | null | undefined;
  placeholder?: string;
  description?: string;
  onChange: (date: string) => void;
  minDate?: Date;
  maxDate?: Date;
  includeCalendarIcon?: boolean;
  hasError?: boolean;
  isRequired?: boolean;
}

type DatepickerInputProps = BaseInputProps & BaseDatepickerInputProps;

const DatepickerInput: React.FC<DatepickerInputProps> = ({
  name,
  selectedDate,
  placeholder,
  onChange,
  className,
  isDisabled,
  minDate,
  maxDate,
  hasError,
  isRequired = false,
  includeCalendarIcon = false,
  testId = 'datepicker',
  trackingId = 'datepicker',
}) => {
  const formContext = useFormContext();
  const [inputValue, setInputValue] = useState<string>(
    selectedDate ? getFormattedDate(selectedDate) : '',
  );

  const resetInternalValue = useCallback(() => {
    setInputValue(selectedDate ? getFormattedDate(selectedDate) : '');
  }, [selectedDate]);

  const resetFormValue = useCallback(() => {
    if (formContext) {
      const newValue = selectedDate ? getFormattedDate(selectedDate) : '';
      formContext.setValue(name, newValue);
    }
  }, [formContext, name, selectedDate]);

  const resetValue = useCallback(() => {
    resetInternalValue();
    resetFormValue();
  }, [resetInternalValue, resetFormValue]);

  // If the date getting passed in changes (e.g, from a calendar selection), we should override the local value
  useEffect(() => {
    resetValue();
  }, [resetValue]);

  // If the current input value is invalid, reset it when exiting the input
  const handleBlur = () => {
    if (!isValidDateInput(inputValue)) {
      resetValue();
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setInputValue(newValue);

    if (isValidDateInput(newValue, minDate, maxDate)) {
      onChange(newValue);
    }
  };

  const datepickerInputClasses = cx(
    'font-label focus:ring-focusBrand relative z-20 block flex w-full items-center border-0 py-2 pl-3 pr-9 focus:outline-none focus:ring-1 focus:ring-inset',
    {
      'placeholder-fgDecorative bg-bgMain text-fgMain': !hasError && !isDisabled,
      'bg-bgMain text-fgMain': !!hasError && !isDisabled,
      'bg-bgDisabled text-fgDisabled placeholder-fgDecorative cursor-not-allowed':
        isDisabled,
    },
    className,
  );

  return (
    <div className="relative">
      <input
        type="text"
        className={datepickerInputClasses}
        placeholder={placeholder}
        data-testid={testId}
        data-trackingid={trackingId}
        aria-describedby={
          hasError ? `field-${name}-error` : `field-${name}-description`
        }
        {...(formContext?.register(name, {
          // If the datepicker is in a form, we pass these handlers as
          // part of the input registration
          onChange: handleChange,
          disabled: isDisabled,
          valueAsDate: true,
          validate: (value) => {
            // react-hook-form does its own parsing of the entered value
            // due to the valueAsDate option. This value will be a Date object
            // no matter what, but it may be invalid. This check ensures that
            // we don't attempt further validation on invalid date objects.
            if (isNaN(value.getTime())) {
              return false;
            }

            const isMissing = isRequired && value === '';
            return !isMissing;
          },
        }) ?? {
          // If the datepicker is not in a form, we need to pass these
          // handlers as props manually.
          onChange: handleChange,
          onBlur: handleBlur,
          disabled: isDisabled,
          value: inputValue,
        })}
      />
      {includeCalendarIcon && (
        <div className="pointer-events-none absolute inset-y-0 right-0 z-20 flex items-center pr-3">
          <Icon ryecon={RyeconCalendar} size="xs" className="text-fgDecorative" />
        </div>
      )}
    </div>
  );
};

interface DatepickerInternalProps extends DatepickerProps {
  close: () => void;
}

const DatepickerInternal: React.FC<DatepickerInternalProps> = ({
  name,
  children,
  label,
  tooltip,
  helpLink,
  description,
  defaultStartDate,
  defaultEndDate,
  isRange = false,
  isRequired = false,
  onChange,
  error,
  close,
  isOptional = false,
  isEdit = false,
  className,
  inputClassName,
  minDate,
  maxDate,
  isDisabled,
  skeleton = false,
  testId = 'datepicker',
  trackingId = 'datepicker',
}) => {
  const [selectedStartDate, setSelectedStartDate] = useState<Date | null | undefined>(
    defaultStartDate,
  );

  const [selectedEndDate, setSelectedEndDate] = useState<Date | null | undefined>(
    defaultEndDate,
  );

  const formContext = useFormContext();
  const formErrors = formContext?.formState.errors;
  const startDateError = formErrors && formErrors[`${name}-${START_DATE_KEY}`];
  const endDateError = formErrors && formErrors[`${name}-${END_DATE_KEY}`];

  const formSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || formSkeleton;

  const hasErrors = startDateError || endDateError || !!error;

  // Handle callback and close behavior for single and range pickers.
  // Single pickers trigger on any date selection, while range pickers trigger on end date selection
  useEffect(() => {
    if (!isRange && selectedStartDate) {
      close();
      if (onChange) {
        onChange(selectedStartDate);
      }
    } else if (isRange && selectedStartDate && selectedEndDate) {
      close();
      if (onChange) {
        onChange([selectedStartDate, selectedEndDate]);
      }
    }
  }, [selectedStartDate, selectedEndDate, isRange, onChange, close]);

  // Manage internal selection state for react-datepicker calendar use
  const handleCalendarSelectionChange = (
    date: Date | [Date | null, Date | null] | null,
  ) => {
    if (isRange) {
      // If this is a range, we can assert the type of date as an array
      const assertedDates = date as [Date | null, Date | null];

      const startDate = assertedDates[0] ?? null;
      const endDate = assertedDates[1] ?? null;

      setSelectedStartDate(startDate);
      setSelectedEndDate(endDate);
    } else {
      // If this is a single date picker, we can assert the type of date as a single value
      const assertedDate = date as Date | null;
      setSelectedStartDate(assertedDate);
    }
  };

  const handleClearClick = () => {
    setSelectedStartDate(null);
    if (isRange) {
      setSelectedEndDate(null);
    }
  };

  return (
    <>
      <Field
        label={label}
        tooltip={tooltip}
        helpLink={helpLink}
        className={className}
        isOptional={isOptional}
        isEdit={isEdit}
        isDisabled={isDisabled}
        testId={`${testId}-wrapper`}
        trackingId={`${trackingId}-wrapper`}
      >
        {!shouldSkeleton && (
          <>
            {!isEdit && children && (
              <div className="min-h-input bg-bgDisabled text-fgMain font-body-sm flex items-center truncate rounded-md px-3 py-2">
                <div className="pb-px pl-px pt-px">{children}</div>
              </div>
            )}
            {!isEdit && !children && (
              <div
                className={cx(
                  'min-h-input bg-bgDisabled text-fgMain font-body-sm flex items-center truncate rounded-md px-3 py-2',
                )}
              >
                <div className="flex items-center truncate pb-px pl-px pt-px">
                  <div>
                    {selectedStartDate
                      ? getFormattedDate(selectedStartDate)
                      : isRange
                        ? 'No start date'
                        : 'No date'}
                  </div>
                  {isRange && (
                    <>
                      <div className="flex items-center px-2.5">
                        <Icon
                          ryecon={RyeconArrowBidirectional}
                          size="xs"
                          className="text-fgDecorative"
                        />
                      </div>
                      <div>
                        {selectedEndDate
                          ? getFormattedDate(selectedEndDate)
                          : 'No end date'}
                      </div>
                    </>
                  )}
                </div>
              </div>
            )}
            {isEdit && (
              <>
                <Disclosure.Button
                  as="div"
                  className={cx(
                    'focus-within:border-borderBrand flex items-center rounded-md border',
                    {
                      'border-borderMain shadow-rest': !hasErrors && !isDisabled,
                      'border-borderDanger shadow-rest': hasErrors && !isDisabled,
                      'border-borderDisabled bg-bgDisabled shadow-none': isDisabled,
                    },
                    inputClassName,
                  )}
                >
                  <DatepickerInput
                    className={cx(
                      'min-h-input',
                      {
                        'rounded-none rounded-bl-md rounded-tl-md': isRange,
                        'rounded-md': !isRange,
                      },
                      inputClassName,
                    )}
                    name={`${name}-${START_DATE_KEY}`}
                    selectedDate={selectedStartDate}
                    placeholder={isRange ? 'Start date..' : 'Date..'}
                    onChange={(value) => setSelectedStartDate(getDateFromInput(value))}
                    minDate={minDate}
                    maxDate={maxDate}
                    hasError={!!startDateError || !!error}
                    isEdit={isEdit}
                    isDisabled={isDisabled}
                    isRequired={isRequired}
                    includeCalendarIcon={!isRange}
                    testId={`${testId}${isRange ? '-start' : ''}-input`}
                    trackingId={`${trackingId}${isRange ? '-start' : ''}-input`}
                  />
                  {isRange && (
                    <>
                      <div className="px-2.5">
                        <Icon
                          ryecon={RyeconArrowBidirectional}
                          size="xs"
                          className="text-fgDecorative"
                        />
                      </div>
                      <DatepickerInput
                        className={cx(
                          'min-h-input rounded-none rounded-br-md rounded-tr-md',
                          inputClassName,
                        )}
                        name={`${name}-${END_DATE_KEY}`}
                        selectedDate={selectedEndDate}
                        placeholder={'End date..'}
                        onChange={(value) =>
                          setSelectedEndDate(getDateFromInput(value))
                        }
                        minDate={minDate}
                        maxDate={maxDate}
                        hasError={!!endDateError || !!error}
                        isEdit={isEdit}
                        isDisabled={isDisabled}
                        isRequired={isRequired}
                        includeCalendarIcon
                        testId={`${testId}-end-input`}
                        trackingId={`${trackingId}-end-input`}
                      />
                    </>
                  )}
                </Disclosure.Button>
              </>
            )}
          </>
        )}
        {shouldSkeleton && (
          <LoadingBlock loaderClassName="rounded-md min-h-input w-full" />
        )}

        <FormFieldMessage
          name={name}
          description={description}
          errorMessage={
            error ||
            (startDateError && (isRange ? 'Invalid start date.' : 'Invalid date.')) ||
            (endDateError && 'Invalid end date.')
          }
          isEdit={isEdit}
          testId={testId}
          trackingId={trackingId}
        />
      </Field>

      {!isDisabled && (
        <Transition
          as={Fragment}
          enter="transition ease-out duration-200"
          enterFrom="opacity-0 translate-y-1"
          enterTo="opacity-100 translate-y-0"
          leave="transition ease-in duration-150"
          leaveFrom="opacity-100 translate-y-0"
          leaveTo="opacity-0 translate-y-1"
        >
          <Disclosure.Panel
            data-testid={`${testId}-popover`}
            data-trackingid={`${trackingId}-popover`}
            className="absolute left-0 top-full z-30 mt-1 max-w-xs transform px-0"
          >
            <div className="shadow-hover overflow-y-auto">
              <div className="datepicker-container border-borderMuted bg-bgMain relative rounded-md border p-3 ">
                {isRange ? (
                  <ReactDatePicker
                    inline
                    formatWeekDay={(nameOfDay) =>
                      JSON.stringify(nameOfDay).substring(0, 1)
                    }
                    onChange={handleCalendarSelectionChange}
                    selected={selectedStartDate}
                    startDate={selectedStartDate}
                    endDate={selectedEndDate}
                    minDate={minDate}
                    maxDate={maxDate}
                    selectsRange={isRange}
                    showPopperArrow={false}
                    disabledKeyboardNavigation
                  />
                ) : (
                  <ReactDatePicker
                    inline
                    formatWeekDay={(nameOfDay) =>
                      JSON.stringify(nameOfDay).substring(0, 1)
                    }
                    onChange={handleCalendarSelectionChange}
                    selected={selectedStartDate}
                    startDate={selectedStartDate}
                    endDate={selectedEndDate}
                    minDate={minDate}
                    maxDate={maxDate}
                    selectsRange={undefined}
                    showPopperArrow={false}
                    disabledKeyboardNavigation
                  />
                )}
                <Button
                  className="w-full justify-center"
                  text="Clear selection"
                  size={Sizes.sm}
                  type="secondary"
                  onClick={handleClearClick}
                  testId={`${testId}-clear-button`}
                />
              </div>
            </div>
          </Disclosure.Panel>
        </Transition>
      )}
    </>
  );
};

export const Datepicker: React.FC<DatepickerProps> = ({
  ...props
}): React.ReactElement => {
  return (
    <Disclosure>
      {({ close, open }) => (
        <div className="relative flex">
          {open && <div className="fixed inset-0 z-10" onClick={() => close()}></div>}
          <DatepickerInternal close={close} {...props} />
        </div>
      )}
    </Disclosure>
  );
};
