import { Button } from '../../Button';
import type { PaginationFooterProps } from '../PaginationFooter';

export type LoadMoreProps = Pick<
  PaginationFooterProps,
  | 'onLoadMore'
  | 'hasMorePages'
  | 'isPageLoading'
  | 'noMorePagesLabel'
  | 'loadingLabel'
  | 'loadMoreLabel'
>;
export const LoadMore: React.FC<LoadMoreProps> = ({
  onLoadMore,
  hasMorePages,
  isPageLoading,
  loadMoreLabel = 'Load more...',
  loadingLabel = 'Loading...',
  noMorePagesLabel = 'No more pages',
}): React.ReactElement => (
  <>
    <div className="bg-borderMuted h-px flex-1" />
    <Button
      className="bg-bgMain"
      type="tertiary"
      onClick={onLoadMore}
      isDisabled={!hasMorePages}
      testId="pagination-load-more"
    >
      {hasMorePages && (isPageLoading ? loadingLabel : loadMoreLabel)}
      {!hasMorePages && noMorePagesLabel}
    </Button>
    <div className="bg-borderMuted h-px flex-1" />
  </>
);
