export interface LiveRegionProps {
  /** Determines whether to use a div or a span or whether the live region is only for screenreader users; defaults to 'block'. */
  display?: 'block' | 'inline' | 'sr-only';

  /** Defaults to 'polite'; only change if you have an extremely urgent message. */
  level?: 'assertive' | 'polite';

  /**
   * The message to be announced. Initially mount without this prop set for best results. Change to update the message!
   * @see ./useLiveRegion for an API that makes this easier to use.
   */
  message?: React.ReactNode;

  /** data-testid for cypress targeting */
  testId?: string;
}

/** Use the hook, not this directly! */
export const LiveRegion: React.FC<LiveRegionProps> = ({
  display = 'block',
  level = 'polite',
  message,
  testId,
}) => {
  const props = {
    'aria-live': level,
    children: message,
    className: display === 'sr-only' ? display : undefined,
    'data-testid': testId,
    role: level === 'assertive' ? 'alert' : 'status',
  };

  return display === 'inline' ? <span {...props} /> : <div {...props} />;
};
