import { type FC, type SVGProps } from 'react';
import cx from 'classnames';

import type { IconSizeType } from '../../Icon';
import { getSizeClasses } from '../../Icon/helpers.internal';
import {
  RyeconDuotoneError,
  RyeconDuotoneHealthCaution,
  RyeconDuotoneHealthDegraded,
  RyeconDuotoneHealthUnknown,
  RyeconDuotoneHealthVerified,
  RyeconDuotoneInfo,
  RyeconDuotoneMinus,
  RyeconDuotoneModified,
  RyeconDuotoneNew,
  RyeconDuotoneQueue,
  RyeconDuotoneRemoved,
  RyeconDuotoneReused,
  RyeconDuotoneSkip,
  RyeconDuotoneStale,
  RyeconDuotoneSuccess,
  RyeconDuotoneUnknown,
  RyeconDuotoneWarn,
} from '../components/icons';

export type StatusRyeconProps = SVGProps<SVGSVGElement> & {
  size?: IconSizeType;
};

const DEFAULT_SIZE = 'lg';

export type StatusRyecon = FC<StatusRyeconProps>;

// Status icons

export const RyeconStatusSuccess: StatusRyecon = ({
  size = DEFAULT_SIZE,
  ...props
}) => {
  const sizeClasses = getSizeClasses(size);

  return (
    <RyeconDuotoneSuccess
      {...props}
      className={cx(sizeClasses, 'text-bgDuotoneSuccess')}
      accentClassName="text-fgDuotoneBase"
      testId="ryecon-status-success"
    />
  );
};
RyeconStatusSuccess.displayName = 'RyeconStatusSuccess';

