import {
  Toast as HotToast,
  toast,
  Toaster as HotToaster,
  ToastOptions,
  ToastPosition,
} from 'react-hot-toast';
import cx from 'classnames';

import { Toast, ToastProps, ToastVariant } from './Toast';

// Default values for toast configuration
const DEFAULT_DURATION = 5000;
const DEFAULT_POSITION: ToastPosition = 'bottom-right';
const DEFAULT_GUTTER = 8;

export interface ToasterProps {
  position?: ToastPosition;
  gutter?: number;
  containerClassName?: string;
  containerStyle?: React.CSSProperties;
  toastOptions?: ToastOptions;
}

export const Toaster: React.FC<ToasterProps> = ({
  position = DEFAULT_POSITION,
  gutter = DEFAULT_GUTTER,
  containerClassName,
  containerStyle,
  toastOptions = {},
}) => {
  return (
    <>
      {/* Persistent live regions for accessibility */}
      <div
        aria-live="polite"
        role="status"
        aria-atomic="true"
        aria-relevant="additions removals"
        className="sr-only"
      />
      <div
        aria-live="assertive"
        role="alert"
        aria-atomic="true"
        aria-relevant="additions removals"
        className="sr-only"
      />
      <HotToaster
        position={position}
        gutter={gutter}
        containerClassName={cx('fixed z-50', containerClassName)}
        containerStyle={containerStyle}
        toastOptions={{
          duration: DEFAULT_DURATION,
          ...toastOptions,
        }}
      />
    </>
  );
};

// Helper functions to show toasts
export const showToast = (props: ToastProps) => {
  // Store the currently focused element
  const previousFocus = document.activeElement as HTMLElement;

  const id = toast.custom(
    (t: HotToast) => (
      <Toast
        {...props}
        onClickClose={
          props.dismissible === false
            ? undefined
            : () => {
                // Remove immediately without animation for better a11y
                toast.remove(t.id);
                props.onClickClose?.();
                // Restore focus when toast is dismissed
                previousFocus?.focus();
              }
        }
      />
    ),
    {
      // Handle duration based on dismissible and variant
      duration:
        props.duration ||
        (props.dismissible === false
          ? DEFAULT_DURATION
          : props.variant === ToastVariant.Error
            ? Infinity
            : DEFAULT_DURATION),
      // Prevent multiple toasts of the same type
      id: props.variant ? `toast-${props.variant}` : undefined,
      // Ensure proper focus management
      ariaProps: {
        role: 'status',
        'aria-live': props.variant === ToastVariant.Error ? 'assertive' : 'polite',
      },
    },
  );

  return id;
};

// Promise-based toast for async operations
export const promiseToast = <T,>(
  promise: Promise<T>,
  {
    loading,
    success,
    error,
  }: {
    loading: string;
    success: string;
    error: string;
  },
) => {
  const toastId = showInfoToast({
    title: loading,
    dismissible: false,
  });

  promise
    .then(() => {
      toast.dismiss(toastId);
      showSuccessToast({
        title: success,
        dismissible: true,
      });
    })
    .catch(() => {
      toast.dismiss(toastId);
      showErrorToast({
        title: error,
        // Keep error toast dismissible so users can acknowledge it
        dismissible: true,
      });
    });

  return promise;
};

export const showSuccessToast = (props: Omit<ToastProps, 'variant'>) => {
  return showToast({ ...props, variant: ToastVariant.Success });
};

export const showErrorToast = (props: Omit<ToastProps, 'variant'>) => {
  return showToast({ ...props, variant: ToastVariant.Error });
};

export const showWarningToast = (props: Omit<ToastProps, 'variant'>) => {
  return showToast({ ...props, variant: ToastVariant.Warn });
};

export const showInfoToast = (props: Omit<ToastProps, 'variant'>) => {
  return showToast({ ...props, variant: ToastVariant.Info });
};

// Legacy support functions for backward compatibility
export const error = (message: string) => {
  return showErrorToast({
    title: message,
    dismissible: true,
  });
};

export const success = (message: string) => {
  return showSuccessToast({
    title: message,
    dismissible: true,
  });
};

export const warn = (message: string) => {
  return showWarningToast({
    title: message,
    dismissible: true,
  });
};

export const info = (message: string) => {
  return showInfoToast({
    title: message,
    dismissible: true,
  });
};

// Generic toast for backward compatibility
export const show = (message: string, options?: ToastOptions) => {
  return toast.custom(
    (t: HotToast) => (
      <Toast
        title={message}
        variant={ToastVariant.Info}
        dismissible={true}
        onClickClose={() => toast.remove(t.id)}
      />
    ),
    options,
  );
};

// Re-export toast methods for full backward compatibility
export { toast };
