import { PropsWithChildren, useEffect } from 'react';
import cx from 'classnames';

import { Dialog } from '@/externals/headlessui';
import { useLiveRegion } from '../../hooks';
import { Icon } from '../Icon/Icon';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { Notification, NotificationBanner } from '../NotificationBanner';
import { RyeconClose } from '../ryecons';
import { SidePanelActionBar, SidePanelActionBarProps } from './SidePanelActionBar';

export type SidePanelWidth = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '3xl' | '4xl';

export interface SidePanelContentProps {
  /** Event handler for close button click */
  onClose: () => void;

  /** A title component */
  title: React.ReactNode;

  /** Whether to display a loading state in place of the title */
  skeleton?: boolean;

  /** Whether to display the border under the title */
  showBorder?: boolean;

  /** The width of the sidepanel */
  width?: SidePanelWidth;

  /** Action bar configuration */
  actionBarConfig?: SidePanelActionBarProps;

  /** Error notification to display, if it exists */
  errorNotification?: Notification;

  /** A callback to be triggered when the error banner close button is clicked **/
  onErrorDismiss?: () => void;

  /** Custom classname for the content */
  className?: string;
}

export const SidePanelContent: React.FC<PropsWithChildren<SidePanelContentProps>> = ({
  onClose,
  title,
  skeleton,
  showBorder = true,
  width = 'lg',
  actionBarConfig,
  errorNotification,
  onErrorDismiss,
  className,
  children,
}): React.ReactElement => {
  const {
    clearMessage: clearErrorNotification,
    LiveRegion: ErrorNotification,
    setMessage: setErrorNotification,
  } = useLiveRegion();

  useEffect(() => {
    if (errorNotification) {
      setErrorNotification(
        <NotificationBanner
          className="mb-4"
          notification={errorNotification}
          onCloseClick={onErrorDismiss}
        />,
      );
    } else {
      clearErrorNotification();
    }
  }, [clearErrorNotification, errorNotification, onErrorDismiss, setErrorNotification]);

  return (
    <div
      className={cx('h-full w-screen', {
        'max-w-xs': width === 'xs',
        'max-w-sm': width === 'sm',
        'max-w-md': width === 'md',
        'max-w-lg': width === 'lg',
        'max-w-xl': width === 'xl',
        'max-w-2xl': width === '2xl',
        'max-w-3xl': width === '3xl',
        'max-w-4xl': width === '4xl',
      })}
    >
      <div className="border-borderMuted bg-bgMain shadow-hover flex h-full flex-col border-l ">
        <div
          className={cx('px-4 py-2', {
            'border-borderMuted border-b': showBorder,
          })}
        >
          <div className="flex items-center justify-between">
            <Dialog.Title className="text-fgMain font-heading-4">
              {skeleton && <LoadingBlock height={20} width={250} />}
              {!skeleton && title}
            </Dialog.Title>
            <button
              type="button"
              className="text-fgDecorative hover:text-fgAltHover inline-flex items-center rounded-md"
              onClick={onClose}
              data-testid="close-button"
            >
              <span className="sr-only">Close panel</span>
              <Icon ryecon={RyeconClose} size="md" />
            </button>
          </div>
        </div>
        <div className="h-full overflow-auto px-6 py-4">
          <ErrorNotification />
          <div className={cx(className, 'space-y-12')}>{children}</div>
        </div>
        {!!actionBarConfig && <SidePanelActionBar {...actionBarConfig} />}
      </div>
    </div>
  );
};
