import { FC, useEffect, useRef } from 'react';
import cx from 'classnames';

import { Dialog } from '@/externals/headlessui';
import { useAriaLabelledby } from '../../hooks/useAriaLabelledby';
import {
  ModalAction,
  type ModalActionProps,
  type ModalSize,
  type ModalTypes,
} from './Modal';

type ModalContentContainerProps = {
  /** Content to display in the modal  */
  children: React.ReactNode;

  /** The modal title */
  title: string;

  /** If false, the title will only be available on screen readers */
  showTitle?: boolean;

  /** Alternative to icon - overrides icon when present */
  image?: React.ReactNode;

  /** An onclose handler function */
  onClose?(isOpen: boolean): void;

  /** An array of modal actions */
  actions?: ModalActionProps[];

  /** The modal type */
  modalType?: ModalTypes;

  /** The size of the modal */
  modalSize?: ModalSize;

  /** Force enable dark mode. Useful since this element is portaled */
  forceDark?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Default: hidden - visible often needed for menues or dropdowns  */
  overflow?: 'hidden' | 'visible';
};

export const ModalContentContainer: FC<ModalContentContainerProps> = ({
  children,
  title,
  showTitle = true,
  onClose = () => {},
  modalType = 'success',
  image,
  modalSize = 'standard',
  actions = [
    {
      text: 'Ok',
      onClick: () => onClose(false),
      type: modalType === 'alert' ? 'error' : 'primary',
    },
  ],
  testId = 'modal-content',
  trackingId = 'modal-content',
  overflow = 'hidden',
}) => {
  const ref = useRef<HTMLDivElement>(null);
  const labelId = useAriaLabelledby(title);
  const containerClassName = cx(
    'border-borderMuted bg-bgMain shadow-hover inline-block w-full transform overflow-hidden rounded-lg border p-6 text-left align-middle transition-all',
    {
      'max-w-lg': modalSize === 'standard',
      'h-[95vh]': modalSize === 'fullScreen',
      'overflow-hidden': overflow === 'hidden',
      'overflow-visible': overflow === 'visible',
    },
  );
  const imagePositionClasses = cx(
    'mx-auto flex h-12 w-12 items-center justify-center rounded-full',
  );

  useEffect(() => {
    ref.current?.focus();
  }, []);

  return (
    <div
      ref={ref}
      className={containerClassName}
      data-testid={testId}
      data-trackingid={trackingId}
      role="dialog"
      aria-label={showTitle ? undefined : title}
      aria-labelledby={showTitle ? labelId : undefined}
      tabIndex={-1}
    >
      <div>
        {modalType !== 'blank' && image && (
          <div className={imagePositionClasses}>{image}</div>
        )}
        {showTitle && (
          <div data-testid="modal-title">
            <Dialog.Title
              id={labelId}
              as="h3"
              className="text-fgMain font-heading-3 leading-6"
            >
              {title}
            </Dialog.Title>
            <div className="mt-2">
              <div className="text-fgAlt font-body">{children}</div>
            </div>
          </div>
        )}
        {!showTitle && (
          <>
            <Dialog.Title as="h3" className="sr-only">
              {title}
            </Dialog.Title>
            <div>
              <div className="text-fgAlt font-body">{children}</div>
            </div>
          </>
        )}
      </div>
      <div
        className={`mt-6 grid ${
          actions.length === 1 ? 'grid-cols-1' : 'grid-cols-2'
        } grid-flow-row-dense gap-3`}
      >
        {actions.map((action) => (
          <ModalAction key={String(action.text)} {...action} />
        ))}
      </div>
    </div>
  );
};
