import type { Delimiter, PillData } from './types';

const isValidValue = (str?: string) => {
  if (!str) {
    return false;
  }
  const hasNonWhitespaceChars = /\S/.test(str);
  return hasNonWhitespaceChars;
};

const getIsValidValue = (delimiter: Delimiter) => {
  return (str?: string) => str !== delimiter && isValidValue(str);
};

type ParsedPills = {
  pills: PillData[];
  remaining: string;
};
export const parsePills = (
  rawValue: string = '',
  delimiter: Delimiter = ',',
): ParsedPills => {
  const parsed = rawValue.split(delimiter);
  if (rawValue === '' || parsed.length === 0) {
    return { pills: [], remaining: rawValue };
  }
  const isValid = getIsValidValue(delimiter);
  const remaining = parsed.pop() ?? '';
  const values = parsed.filter(isValid);
  const pills = values.map((value, i) => ({ id: `${i}`, value: value.trim() }));
  return { pills, remaining };
};

export const initPills = (rawValue: string = '', delimiter: Delimiter = ',') => {
  const { pills, remaining } = parsePills(rawValue, delimiter);
  if (remaining) {
    return [...pills, { id: `${pills.length}`, value: remaining.trim() }];
  }
  return pills;
};

export const pillsToStr = (
  pills: PillData[],
  delimiter: Delimiter = ',',
  remaining: string = '',
): string => {
  // no pills to join
  if (pills.length === 0) {
    return remaining;
  }

  // combine pill values
  const pillStr = pills.map(({ value }) => (value ?? '').trim()).join(delimiter);
  if (remaining === '') {
    return pillStr;
  }

  // combine pill values + uncommitted text
  return `${pillStr}${delimiter}${remaining}`;
};

/**
 * returns true when all `value`s of pills are equal
 */
export const arePillsEqual = (pillsA: PillData[], pillsB: PillData[]): boolean => {
  if (pillsA.length !== pillsB.length) {
    return false;
  }
  const valuesA = pillsA.map(({ value }) => value);
  return pillsB.every(({ value }) => valuesA.includes(value));
};
