import { PropsWithChildren, ReactElement } from 'react';
import { useNavigate } from 'react-router-dom';

import { AuthenticationButton } from '../../Button';
import { Card } from '../../Card';
import { Icon } from '../../Icon/Icon';
import { Link } from '../../Link/Link';
import { Logo } from '../../Logo';
import { NotificationBanner } from '../../NotificationBanner';
import { RyeconCaretLeft, RyeconSpinner } from '../../ryecons';
import { Section } from '../../Section';

interface AuthenticationLayoutProps {
  /** Text to display above the card*/
  headerText?: React.ReactNode;

  /** Subtext to display above the card */
  subText?: React.ReactNode;

  /** Boolean to display a loading state */
  isLoading: boolean;

  /** Boolean to display a load error notification banner */
  isLoadError: boolean;

  /** Custom message to display in load error notification banner */
  customLoadError?: string;

  /** Boolean to display a mutation error notification banner */
  isMutationError?: boolean;

  /** Custom message to display in mutation error notification banner */
  customMutationError?: string | ReactElement;

  /** Boolean to display back to login link */
  showBackToLoginLink?: boolean;

  /** Boolean to display sign up CTA below card */
  showSignUpSection?: boolean;

  /** Boolean to display load error and children component */
  showLoadErrorAndChildren?: boolean;

  /** Boolean to display link to the VS Code extension docs for existing users */
  showExtensionDocsForExistingUsers?: boolean;

  /** URL for VS Code extension docs */
  extensionDocsLink?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Footer content to display below the main content card */
  footer?: React.ReactNode;
}

export const AuthenticationLayout: React.FC<
  PropsWithChildren<AuthenticationLayoutProps>
> = ({
  children,
  headerText,
  subText,
  isLoading,
  isLoadError,
  customLoadError,
  isMutationError,
  customMutationError,
  showBackToLoginLink = false,
  showSignUpSection = false,
  showLoadErrorAndChildren = false,
  showExtensionDocsForExistingUsers = false,
  extensionDocsLink = 'https://docs.getdbt.com/docs/install-dbt-extension#register-with-an-existing-dbt-account',
  testId = 'authentication-form',
  trackingId = 'authentication-form',
  footer,
}) => {
  const navigate = useNavigate();

  return (
    // always use "dark bg" for this layout
    <div className="bg-bgBackground dark h-screen w-full overflow-y-auto overflow-x-hidden">
      {isLoading && (
        <div className="flex h-screen items-center justify-center p-20">
          <Icon ryecon={RyeconSpinner} className="text-fgMain animate-spin" size="md" />
        </div>
      )}

      {!isLoading && (
        <div className="flex justify-center px-5 py-10 sm:px-20 sm:py-20">
          <div className="w-full max-w-lg">
            <div className="mb-10">
              <Logo className="h-[30px] w-auto lg:block" title="dbt" />
              {!isLoadError && (
                <>
                  {!!headerText && (
                    <h1 className="text-fgWhite font-display mt-10">{headerText}</h1>
                  )}
                  {!!subText && (
                    <p className="text-fgWhite font-body-lg mt-2">{subText}</p>
                  )}
                </>
              )}
              {isLoadError && (
                <NotificationBanner
                  className="mt-10"
                  notification={{
                    type: 'error',
                    header:
                      customLoadError ??
                      'An unknown error occurred, please try refreshing. If the error persists, please contact support.',
                    id: 'invalid-link',
                  }}
                />
              )}
            </div>

            {(!isLoadError || showLoadErrorAndChildren) && (
              <Card testId={`${testId}-form`} trackingId={`${trackingId}-form`}>
                {isMutationError && (
                  <Section>
                    <NotificationBanner
                      notification={{
                        type: 'error',
                        header:
                          customMutationError ??
                          'An unknown error occurred, please try refreshing. If the error persists, please contact support.',
                        id: 'submit-error',
                      }}
                      className="mb-10"
                    />
                  </Section>
                )}
                {children}
              </Card>
            )}

            {showBackToLoginLink && (
              <Link
                to="/login"
                isInternal
                className="dark mt-10 flex items-center gap-1 text-sm"
                colorVariant="light"
                hideUnderline
                testId="login-link"
                trackingId="login-link"
              >
                <Icon ryecon={RyeconCaretLeft} size="xs" /> back to login
              </Link>
            )}

            {showSignUpSection && (
              <div className="mt-8">
                <h2 className="text-fgWhite font-heading-3">Don't have an account?</h2>
                <p className="text-fgWhite font-body">
                  Create a new account for your company to schedule, deploy, and
                  visualize your dbt project in minutes.
                </p>
                <AuthenticationButton
                  onClick={() => navigate('/signup')}
                  type="signup"
                  className="mt-4"
                >
                  Create a free company account
                </AuthenticationButton>
              </div>
            )}
            {showExtensionDocsForExistingUsers && (
              <div className="mt-8">
                <h2 className="text-fgWhite font-heading-3">
                  Already have an account?
                </h2>
                <p className="text-fgWhite font-body">
                  View the{' '}
                  <Link shouldOpenNewTab isInternal={false} to={extensionDocsLink}>
                    docs
                  </Link>{' '}
                  on how to configure your credentials.
                </p>
              </div>
            )}
            {footer && <div className="text-fgWhite mt-8">{footer}</div>}
          </div>
        </div>
      )}
    </div>
  );
};
