import cx from 'classnames';

import { useSkeletonContext } from '../../../context/SkeletonProvider';
import { Badge } from '../../Badge';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { DEFAULT_STATUS_BAR_CHILD_CLASSES } from '../StatusBar';

export interface StatusBarCountItem {
  /** The count */
  count: number;

  /** The status of the item */
  status: 'success' | 'warning' | 'error';

  /** The text to display */
  label: string;

  /** Flag to render in skeleton mode */
  skeleton?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export interface StatusBarCountTileProps {
  /** Array of status count items to display */
  items: StatusBarCountItem[];

  /** Custom classnames */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const StatusBarCountTile: React.FC<StatusBarCountTileProps> = ({
  items,
  className,
  testId = 'status-bar-count-tile',
  trackingId = 'status-bar-count-tile',
}): React.ReactElement => {
  const globalSkeleton = useSkeletonContext()?.skeleton;
  return (
    <div
      className={cx(
        'flex items-center justify-between font-semibold',
        DEFAULT_STATUS_BAR_CHILD_CLASSES,
        className,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {items.map((item) => {
        const shouldSkeleton = item.skeleton || globalSkeleton;
        return (
          <div
            className="flex h-full flex-col items-center px-5"
            key={item.label}
            data-testid={item.testId}
            data-trackingid={item.trackingId}
          >
            {!shouldSkeleton && (
              <Badge size="lg" type={item.status} text={String(item.count)} />
            )}
            {shouldSkeleton && <LoadingBlock width={35} height={24} className="py-1" />}
            <div className="text-fgDecorative font-label flex grow basis-0 items-end">
              {item.label}
            </div>
          </div>
        );
      })}
    </div>
  );
};
