import cx from 'classnames';

export interface TabBarTabProps {
  /** The Text of the tab **/
  text: string;

  /** A unique identifier for onClick handling **/
  id: string;

  /** Flag for indicating the currently selected tab **/
  isActive?: boolean;

  /** onClick handling for the tab */
  onClick?(id: string): void;

  /** className overrides for an individual tab */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const TabBarTab: React.FC<TabBarTabProps> = ({
  text,
  id,
  isActive,
  onClick,
  className = '',
  testId = 'tab-bar-tab',
  trackingId = 'tab-bar-tab',
}): React.ReactElement => {
  const tabClasses = cx(
    className,
    'font-label-lg group relative min-w-0 flex-1 overflow-hidden px-4 py-4 text-center transition-colors first:rounded-tl-lg last:rounded-tr-lg focus:z-10',
    {
      'text-fgBrand': isActive,
      'hover:text-fgBrandHover active:text-fgBrandActive text-fgAlt hover:bg-bgMainHover active:bg-bgMainActive transition-colors':
        !isActive,
    },
  );
  const indicatorClasses = cx('absolute inset-x-0 bottom-0 h-0.5', {
    'bg-bgBrand': isActive,
    'bg-transparent': !isActive,
  });

  return (
    <button
      className={tabClasses}
      type="button"
      aria-current={isActive ? 'page' : undefined}
      onClick={() => onClick && onClick(id)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <span>{text}</span>
      <span className={indicatorClasses} />
    </button>
  );
};

export interface TabBarProps {
  children: React.ReactNode;

  /** className overrides for the overall TabBar */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

interface SubComponents {
  Tab: typeof TabBarTab;
}

export const TabBar: React.FC<TabBarProps> & SubComponents = ({
  children,
  className = '',
  testId = 'tab-bar',
  trackingId = 'tab-bar',
}): React.ReactElement => {
  return (
    <nav
      className={cx(className, 'relative z-0 flex rounded-t-lg shadow')}
      aria-label="Tabs"
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {children}
    </nav>
  );
};

TabBar.Tab = TabBarTab;
