import { MutableRefObject, useCallback, useEffect, useState } from 'react';
import { useResizeDetector } from 'react-resize-detector';
import { OnRefChangeType } from 'react-resize-detector/build/types';
interface UseAccordionProps {
  initialOpen?: boolean;
  onToggleOpen?: (open: boolean) => void;
}

export type UseAccordion = {
  contentHeight: string | number;
  contentRef: MutableRefObject<any> | OnRefChangeType<any>;
  isOpen: boolean;
  toggleOpen: () => void;
};

const useAccordion = ({
  initialOpen = false,
  onToggleOpen,
}: UseAccordionProps): UseAccordion => {
  const { width, height, ref: contentRef } = useResizeDetector();

  const [isOpen, setIsOpen] = useState(initialOpen);
  const [contentHeight, setContentHeight] = useState(initialOpen ? 'auto' : 0);

  const toggleOpen = useCallback(() => {
    onToggleOpen && onToggleOpen(!isOpen);
    setIsOpen(!isOpen);
  }, [isOpen, onToggleOpen]);

  useEffect(() => {
    const clientHeight: number = contentRef?.current?.clientHeight as number;

    if (clientHeight && clientHeight !== contentHeight) {
      setContentHeight(clientHeight);
    }
  }, [
    contentHeight,
    contentRef,
    /* Need width and height dependencies to listen to resize */
    width,
    height,
  ]);

  return {
    contentHeight,
    contentRef,
    isOpen,
    toggleOpen,
  };
};

export default useAccordion;
