import type { Ryecon } from './components';

import '@tanstack/react-table';

/**
 * In order to extend columnDef.meta, we need to do this, even though it feels gross.
 * @see https://tanstack.com/table/latest/docs/api/core/column-def#meta
 */
declare module '@tanstack/react-table' {
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  interface ColumnMeta<TData extends unknown, TValue> {
    /** Control column alignment, using old or new approaches to alignment; left == start, right == end. */
    align?: 'left' | 'right' | 'start' | 'end';
  }
}

export enum State {
  Active = 1,
  Deleted = 2,
}

export interface LinkProps {
  title: string;
  href: string;
  ryecon?: Ryecon;
}

export interface RouteParams {
  section?: string;
  subsection?: string;
  accountId?: string;
  projectId?: string;
  page?: string;
  resourceId?: string;
}

export type ConstEnum<T> = keyof T;

// Global form types

export interface BaseInputProps {
  /** Form label */
  label?: React.ReactNode;

  /** Visually hides the label */
  labelIsHidden?: boolean;

  /** Content to show in a tooltip when hovering over help icon to the right of the label. Only present if label exists */
  tooltip?: React.ReactNode;

  /** A link to a help page. Will be placed on a help icon to the right of the label. Only present if label exists */
  helpLink?: string;

  /** A click handler for the HelpIcon. Will be placed on a help icon to the right of the label. Only present if label exists */
  onHelpClick?: () => void;

  /** Flag to indicate if the input is required */
  isOptional?: boolean;

  /** Error message */
  error?: React.ReactNode;

  /** Flag for disabling error message display, used for inline editing where errors are disconnected from the inputs. Error color transition still applies, just hides the message text */
  shouldHideErrorLabel?: boolean;

  /** Flag to indicate disabled inputs */
  isDisabled?: boolean;

  /** Flag to indicate edit or view mode */
  isEdit?: boolean;

  /** Flag to indicate a loading value */
  skeleton?: boolean;

  /** Class names for the wrapping markup */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** An id to use to associate the label with a specific element */
  labelFor?: string;
}

export interface SourdoughComponent {
  /** class names for the main element */
  className?: string;

  /** data-testid for cypress testing */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Flag for trigger skeleton state to indicate loading */
  skeleton?: boolean;
}

export interface LoadingDimensions {
  width?: number;
  height?: number;
}
