import cx from 'classnames';

import { useSkeletonContext } from '../../../context';
import type { LoadingDimensions, SourdoughComponent } from '../../../globalTypes';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import type { SizeType } from '../../types';

export interface TextSubtextProps extends SourdoughComponent {
  /** Main text */
  text?: React.ReactNode;

  /** Main text as child nodes */
  children?: React.ReactNode;

  /** Class names for the main text */
  textClassName?: string;

  /** Sub text */
  subtext?: React.ReactNode;

  /** Class names for the subtext */
  subtextClassName?: string;

  /** size prop to determine text size/spacing */
  size?: SizeType;

  /** Width and Height for LoadingBlock during skeleton */
  loadingDimensions?: LoadingDimensions;
}

const defaultDimensions = { width: 100, height: 15 };

export const TextSubtext: React.FC<TextSubtextProps> = ({
  children,
  className,
  text,
  textClassName,
  subtext,
  subtextClassName,
  skeleton = false,
  loadingDimensions,
  size = 'xs',
  testId = 'text-subtext',
  trackingId = 'text-subtext',
}) => {
  const skeletonDimensions: LoadingDimensions = {
    ...defaultDimensions,
    ...loadingDimensions,
  };
  const globalSkeleton = useSkeletonContext()?.skeleton;
  const showSkeleton = skeleton || globalSkeleton;
  const textSizes = {
    'font-body-sm': size === 'xs',
    'font-body': size === 'sm',
    'font-body-lg': size === 'md',
  };
  return (
    <div
      className={cx(className, 'inline-flex flex-col justify-between')}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <div
        className={cx(textClassName, textSizes)}
        data-testid={`${testId}-text`}
        data-trackingid={`${trackingId}-text`}
      >
        {showSkeleton ? (
          <LoadingBlock
            width={skeletonDimensions.width}
            height={skeletonDimensions.height}
          />
        ) : (
          text || children
        )}
      </div>
      {!!subtext && (
        <div
          className={cx(subtextClassName, textSizes, {
            'text-fgDecorative': !subtextClassName,
          })}
          data-testid={`${testId}-subtext`}
          data-trackingid={`${trackingId}-subtext`}
        >
          {showSkeleton ? (
            <LoadingBlock
              width={skeletonDimensions.width}
              height={skeletonDimensions.height}
            />
          ) : (
            subtext
          )}
        </div>
      )}
    </div>
  );
};
