import cx from 'classnames';

import { buttonClassNames } from '../Button/buttonClassNames.internal';
import { Sizes, SizeType } from '../types';

export type IconButtonStyleType =
  | 'primary'
  | 'secondary'
  | 'success'
  | 'error'
  | 'link'
  | 'active'
  | 'none';

interface IconButtonClassNamesParams {
  className?: string;
  isDisabled?: boolean;
  size: SizeType;
  styleType?: IconButtonStyleType;
}

export const iconButtonClassNames = ({
  className,
  isDisabled,
  size,
  styleType = 'none',
}: IconButtonClassNamesParams) =>
  styleType === 'none'
    ? cx(
        className,
        'focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain inline-flex items-center transition-colors focus-visible:outline-none focus-visible:ring-2',
        {
          'rounded focus-visible:ring-offset-2': !(
            size === Sizes.lg || size === Sizes.xl
          ),
          'rounded-md focus-visible:ring-offset-4':
            size === Sizes.lg || size === Sizes.xl,
          'text-fgAlt hover:text-fgMain active:text-fgMain focus-visible:text-fgMain':
            !isDisabled,
          'text-fgDisabled cursor-not-allowed': isDisabled,
        },
      )
    : cx(
        className,
        'focus-visible:border-borderMain',
        buttonClassNames({
          isDisabled,
          isRounded: true,
          type: styleType,
        }),
      );
