import cx from 'classnames';

import { HeaderCell } from '../cells/HeaderCell.internal';
import { CellVariant, DefaultTData, Header, StickyColumn } from '../types';
import type { VirtualGridProps } from '../types.internal';
import { WithVirtualPadding } from './WithVirtualPadding.internal';

type HeaderRowProps<
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
> = VirtualGridProps & {
  headers: Header<TData, TValue>[];
  rowRef?: React.MutableRefObject<HTMLTableRowElement | null>;
  cellVariant: CellVariant;
  stickyColumn: StickyColumn | undefined;
  testId: string;
  trackingId: string;
};

export const HeaderRow = <
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
>({
  headers,
  rowRef,
  cellVariant,
  stickyColumn,
  testId,
  trackingId,
  virtualPaddingLeft,
  virtualPaddingRight,
  colIdxOffset,
}: HeaderRowProps<TData, TValue>) => {
  const headerRowClasses = cx('bg-bgBackground flex w-full');
  const headerCells = headers.map((header, idx) => (
    <HeaderCell
      key={`${header.id}-${idx + colIdxOffset}`}
      header={header}
      colIdx={idx + colIdxOffset}
      cellVariant={cellVariant}
      stickyColumn={stickyColumn}
      testId={testId}
      trackingId={trackingId}
    />
  ));
  return (
    <tr
      className={headerRowClasses}
      ref={rowRef}
      data-testid={`${testId}-headers`}
      data-trackingid={`${trackingId}-headers`}
    >
      <WithVirtualPadding
        virtualPaddingLeft={virtualPaddingLeft}
        virtualPaddingRight={virtualPaddingRight}
        as="th"
      >
        {headerCells}
      </WithVirtualPadding>
    </tr>
  );
};
