import { FormSchema, SchemaField } from '..';
import { ConditionalDropdownOption } from '../SchemaFields';

export const getDependedOnFields = (schema: FormSchema): any => {
  const depends = Object.keys(schema.fields)
    .map((fieldKey: string) => {
      const field = schema.fields[fieldKey];

      if (field) {
        const generalDependencies = Object.keys(field.metadata.depends_on ?? {});
        const optionDependencies = (field.metadata.options ?? [])
          .map((option) => Object.keys(option.depends_on ?? {}))
          .flat();

        const allDependencies = [...generalDependencies, ...optionDependencies];

        return allDependencies;
      }
      return [];
    })
    .flat();

  return Array.from(new Set(depends));
};

export const fieldShouldShow = (
  field_name: string,
  field: SchemaField,
  getValues: () => any,
  hiddenFields: string[] = [],
): boolean => {
  const depends = field.metadata.depends_on;

  if (hiddenFields.includes(field_name)) {
    return false;
  }

  return shouldShow(getValues, depends);
};

export const optionShouldShow = (
  option: ConditionalDropdownOption,
  getValues: () => any,
): boolean => {
  const depends = option.depends_on;

  return shouldShow(getValues, depends);
};

const shouldShow = (
  getValues: () => any,
  depends?: Record<string, string | number | boolean | (string | number)[]>,
) => {
  const currentValues = getValues();

  if (depends) {
    return Object.keys(depends).every((dependField) => {
      const requiredDependentValue = depends[dependField];

      let currentDependentValue = currentValues[dependField];

      // If the value is a dropdown option, it will be an object with .value;
      if (
        typeof currentDependentValue === 'object' &&
        'value' in currentDependentValue
      ) {
        currentDependentValue = currentDependentValue.value;
      }

      const hasMultiplePossibleDependentValues = Array.isArray(requiredDependentValue);

      if (hasMultiplePossibleDependentValues) {
        return requiredDependentValue.includes(currentDependentValue);
      }
      return currentDependentValue === requiredDependentValue;
    });
  }

  return true;
};
