import type { SourdoughComponent } from '../../globalTypes';
import { RyeconSpinner } from '../ryecons';
import type { Ryecon } from '../ryecons/types';
import { ListItem, ListItemProps } from './ListItem';

export type ListSkeletonFeatures = 'ryecon' | 'title' | 'trailing' | 'meta';

export interface ListProps extends SourdoughComponent {
  /** An array of items to display in the list */
  items: ListItemProps[];

  /** The number of list items to show for a skeleton loading state */
  skeletonItemCount?: number;

  /** List item features to show a loading block for, defaults to all */
  skeletonFeatures?: {
    [key in ListSkeletonFeatures]?: boolean | Ryecon;
  };
}

export const defaultListSkeletonFeatures: ListProps['skeletonFeatures'] = {
  ryecon: true,
  title: true,
  trailing: true,
  meta: true,
};

export const List: React.FC<ListProps> = ({
  items,
  skeleton = false,
  testId = 'list',
  trackingId = 'list',
  skeletonItemCount = 3,
  skeletonFeatures = defaultListSkeletonFeatures,
}): React.ReactElement | null => {
  if (!skeleton && !items.length) {
    return null;
  }

  return (
    <div data-testid={testId} data-trackingid={trackingId}>
      <ul className="divide-borderMuted border-borderMuted divide-y border-b border-t">
        {!skeleton &&
          items.map((item, index) => (
            <ListItem
              key={item.id}
              {...item}
              testId={`${testId}-item-${index}`}
              trackingId={`${trackingId}-item-${index}`}
            />
          ))}

        {skeleton &&
          new Array(skeletonItemCount)
            .fill({})
            .map((_, i) => (
              <ListItem
                key={i}
                id={i}
                ryecon={RyeconSpinner}
                skeleton
                skeletonFeatures={skeletonFeatures}
                testId={`${testId}-item-loading`}
              />
            ))}
      </ul>
    </div>
  );
};
