import isEmail from 'validator/lib/isEmail.js';
import isFQDN from 'validator/lib/isFQDN.js';
import { z, ZodObject } from 'zod';

import { FormSchema, SchemaField, SchemaValidation } from '../';
import { fieldShouldShow } from './dependencies';

type ValidationGenerator = (base: any, field: SchemaField) => any;

const defaultValidation = z.nullable(z.string());

const checkPattern = (value: string, pattern: string) => {
  switch (pattern) {
    case 'email':
      return isEmail(value);
    case 'hostname':
      return /^(([a-zA-Z0-9]|[a-zA-Z0-9][a-zA-Z0-9-]*[a-zA-Z0-9])\.)*([A-Za-z0-9]|[A-Za-z0-9][A-Za-z0-9-]*[A-Za-z0-9])$/i.test(
        value,
      );
    case 'fqdn':
      return isFQDN(value);
    case 'databricks_hostname':
      return /^(.*databricks.*)$/.test(value);
    case 'databricks_http_path':
      return /^(\/sql\/)|^(sql\/)/.test(value);
  }

  return defaultValidation;
};

const patternErrors: Record<string, (field: SchemaField) => string> = {
  email: (field) => `${field.metadata.label} must be a valid email`,
  hostname: (field) => `${field.metadata.label} must be a valid hostname`,
  fqdn: (field) => `${field.metadata.label} must be a fully qualified domain name`,
  databricks_hostname: (field) =>
    `${field.metadata.label} must be a valid Databricks hostname`,
  databricks_http_path: (field) =>
    `${field.metadata.label} must be a valid Databricks HTTP Path`,
};

const validationGenerators: Record<keyof SchemaValidation, ValidationGenerator> = {
  pattern: (base, field) => {
    let message = 'An unknown issue was found with this field';

    const pattern = field.metadata.validation?.pattern ?? '';
    if (pattern in patternErrors) {
      message = patternErrors[pattern](field);
    }

    return base.refine(
      (val: string) => checkPattern(val, field.metadata.validation?.pattern ?? ''),
      {
        message,
      },
    );
  },
  required: (base, field) => {
    if (field.metadata.validation?.required) {
      return base.min(1, { message: `${field.metadata.label} is required.` });
    }
    // Some fields have required explicitly set to false. In that case, don't add any new validation
    return base;
  },
  min_length: (base, field) =>
    base.min(field.metadata.validation?.min_length ?? 1000, {
      message: `${field.metadata.label} must be at least ${
        field.metadata.validation?.min_length ?? 0
      } characters long`,
    }),
  max_length: (base, field) =>
    base.max(field.metadata.validation?.max_length ?? 0, {
      message: `${field.metadata.label} cannot be more than ${
        field.metadata.validation?.max_length ?? 1000
      } characters long`,
    }),
  min: (base, field) =>
    base.min(field.metadata.validation?.min ?? 1000, {
      message: `${field.metadata.label} must be greater than ${
        field.metadata.validation?.min ?? 1000
      }`,
    }),
  max: (base, field) =>
    base.max(field.metadata.validation?.max ?? 0, {
      message: `${field.metadata.label} must be less than ${
        field.metadata.validation?.min ?? 0
      }`,
    }),
};

export const generateSchemaValidation = (
  schema: FormSchema,
  getValues: () => any,
  hiddenFields: string[] = [],
  isOverride: boolean = false,
): ZodObject<any> => {
  const fieldKeys = Object.keys(schema.fields);

  const validationRules: Record<string, Partial<SchemaValidation>> = fieldKeys.reduce(
    (validations, fieldKey) => {
      return {
        ...validations,
        ...{ [fieldKey]: schema.fields[fieldKey].metadata.validation },
      };
    },
    {},
  );

  const validators = fieldKeys
    .filter(
      (fieldKey) =>
        fieldShouldShow(fieldKey, schema.fields[fieldKey], getValues, hiddenFields) &&
        isOverrideEditable(schema.fields[fieldKey], isOverride),
    )
    .reduce((validations, fieldKey) => {
      const validationConfig: SchemaValidation = validationRules[fieldKey];

      // Filter out any null values from the validation config
      const filteredValidationConfig: SchemaValidation = Object.fromEntries(
        Object.entries(validationConfig ?? {}).filter(([_, v]) => v != null),
      );

      const field = schema.fields[fieldKey];

      let baseValidator: any = z.string({
        required_error: `${field.metadata.label} is required`,
        invalid_type_error: `${field.metadata.label} must be a string`,
      });

      if (field.metadata.field_type === 'number') {
        baseValidator = z.number({
          required_error: `${field.metadata.label} is required`,
          invalid_type_error: `${field.metadata.label} must be a number`,
        });
      }

      if (field.metadata.field_type === 'checkbox') {
        baseValidator = z.boolean({
          required_error: `${field.metadata.label} is required`,
          invalid_type_error: `${field.metadata.label} must be a boolean`,
        });
      }

      if (field.metadata.field_type === 'hidden') {
        const isBooleanField = typeof field.value === 'boolean';
        if (isBooleanField) {
          baseValidator = z.boolean({
            required_error: `${field.metadata.label} is required`,
            invalid_type_error: `${field.metadata.label} must be a boolean`,
          });
        }
      }

      const finalValidator = Object.keys(filteredValidationConfig ?? {}).reduce(
        (baseValidator, currentRule) => {
          return validationGenerators[currentRule as keyof SchemaValidation](
            baseValidator,
            field,
          );
        },
        baseValidator,
      );

      return {
        ...validations,
        ...{
          // If it's required, don't use nullable, unless we're in override mode and this field is overridable
          // it should always be optional in that case, since we have a default
          [fieldKey]:
            filteredValidationConfig?.required &&
            !(isOverride && field.metadata.overrideable)
              ? finalValidator
              : // React hook form treats empty strings as Nan for number inputs (using valueAsNumber).
                // For optional fields, we explicitly allow that value here.
                // https://github.com/colinhacks/zod/issues/310
                finalValidator.or(z.nan()).nullish(),
        },
      };
    }, {});

  return z.object(validators);
};

const isOverrideEditable = (field: SchemaField, isOverride: boolean) =>
  isOverride ? field.metadata.overrideable : true;
