import { useLayoutEffect, useRef, useState } from 'react';
import { flexRender, type Header, type SortDirection } from '@tanstack/react-table';
import cx from 'classnames';

import { checkOverflow } from '../../../utils/checkOverflow';
import { Icon } from '../../Icon/Icon';
import { RyeconArrowDown, RyeconArrowUp, RyeconArrowUpDown } from '../../ryecons';
import { Tooltip } from '../../Tooltip/Tooltip';
import { type DefaultTData } from '../types';

type SortableHeaderProps<TData extends DefaultTData, TValue extends React.ReactNode> = {
  header: Header<TData, TValue>;
  onClick?: (event: unknown) => void;
  sortDir: false | SortDirection;
  isRightAligned: boolean;
  isSorted: boolean;
};

export const SortableHeader = <
  TData extends DefaultTData,
  TValue extends React.ReactNode,
>({
  header,
  onClick,
  sortDir,
  isRightAligned,
  isSorted,
}: SortableHeaderProps<TData, TValue>) => {
  const containerRef = useRef<HTMLButtonElement | null>(null);
  const [isOverflowing, setIsOverflowing] = useState(false);

  // value passed to header to trigger new layout
  const headerValue = header.column.columnDef.header?.toString() ?? '';

  useLayoutEffect(() => {
    if (containerRef.current) {
      const overflowing = checkOverflow(containerRef.current);
      setIsOverflowing(overflowing);
    }
  }, [containerRef, headerValue]);

  // rendered ReactNode from header
  const headerContent = flexRender(header.column.columnDef.header, header.getContext());

  return (
    <button
      ref={containerRef}
      className={cx('flex w-full cursor-pointer items-center font-medium', {
        'text-left': !isRightAligned,
        'gap-x-1': isOverflowing,
        'gap-1': !isOverflowing,
        relative: isOverflowing,
      })}
      type="button"
      onClick={onClick}
    >
      {isOverflowing ? (
        <div
          className={cx('w-full group-focus-within:pr-4 group-hover:pr-4', {
            'pr-4': isSorted,
          })}
        >
          <Tooltip content={headerContent} childrenAreInteractive>
            {(ref) => (
              <div ref={ref} className="truncate">
                {headerContent}
              </div>
            )}
          </Tooltip>
        </div>
      ) : (
        <span className={cx({ 'inline-flex w-full justify-end': isRightAligned })}>
          {headerContent}
        </span>
      )}
      <span
        className={cx('inline-flex', {
          'absolute right-0': isOverflowing,
        })}
      >
        {!sortDir && (
          <Icon
            alt="sort"
            className="hidden group-focus-within:inline group-hover:inline"
            size="xs"
            ryecon={RyeconArrowUpDown}
          />
        )}
        {sortDir === 'desc' && (
          <Icon
            alt="sort ascending"
            className="inline"
            size="xs"
            ryecon={RyeconArrowDown}
          />
        )}
        {sortDir === 'asc' && (
          <Icon
            alt="sort descending"
            className="inline"
            size="xs"
            ryecon={RyeconArrowUp}
          />
        )}
      </span>
    </button>
  );
};
