import type { PopoverOffset } from './types';

export const getFinalOffset = (
  computed: PopoverOffset = {},
  overrides: PopoverOffset = {},
) => {
  return {
    top: Number(computed.top ?? 0) + Number(overrides.top ?? 0),
    left: Number(computed.left ?? 0) + Number(overrides.left ?? 0),
  };
};
