import { ActionList, Actions } from '../Actions/Actions';
import { Badge, type BadgeProps } from '../Badge';
import { type Breadcrumb, Breadcrumbs } from '../Breadcrumbs';
import { OffScreenContentContainer } from '../OffScreenDetector';
import { Body } from '../Text';
import { Tooltip } from '../Tooltip';

export interface PageHeaderProps {
  /** The page title */
  title: string;

  /** The page subtitle */
  subtitle?: string;

  /** A status badge to display on the page header */
  badge?: BadgeProps;

  /** An array of page actions */
  actions?: ActionList;

  /** Breadcrumbs for the page */
  breadcrumbs?: Breadcrumb[];

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const PageHeader: React.FC<PageHeaderProps> = ({
  title,
  subtitle,
  badge,
  actions,
  breadcrumbs,
  testId = 'page-header',
  trackingId = 'page-header',
}): React.ReactElement => {
  const mainActions = !!actions?.length && <Actions actions={actions} />;

  return (
    <OffScreenContentContainer>
      {(triggerRef) => (
        <div ref={triggerRef} data-testid={testId} data-trackingid={trackingId}>
          {!!breadcrumbs && <Breadcrumbs className="mb-4" breadcrumbs={breadcrumbs} />}
          <div className="items-left flex flex-col justify-between sm:flex-row md:items-center">
            <div className="min-w-4 truncate">
              <div className="flex flex-wrap items-center gap-x-2 gap-y-1 truncate md:gap-4">
                <Tooltip displayOnlyWhenTruncated content={title}>
                  {(ref) => (
                    <h1
                      ref={ref}
                      className="text-fgMain my-px min-w-0 flex-1 truncate text-3xl font-semibold"
                      data-testid={`${testId}-title`}
                      data-trackingid={`${trackingId}-title`}
                    >
                      {title}
                    </h1>
                  )}
                </Tooltip>
                {badge && <Badge {...badge} size="lg" />}
              </div>
              {subtitle && (
                <div className="pt-1">
                  <Body size="sm">{subtitle}</Body>
                </div>
              )}
            </div>
            <div className="flex items-center justify-end gap-2">{mainActions}</div>
          </div>
        </div>
      )}
    </OffScreenContentContainer>
  );
};
