import { cloneElement, forwardRef, type HTMLProps, isValidElement } from 'react';
import { useMergeRefs } from '@floating-ui/react';

import { usePopoverContext } from '../context';
import type { TriggerProps } from '../types';

export const HeadlessTrigger = forwardRef<
  HTMLElement,
  HTMLProps<HTMLElement> & TriggerProps
>(function PopoverTrigger({ children, asChild = false, ...props }, propRef) {
  const context = usePopoverContext();

  // React 19: Get child's ref from props (new location) or element (old location)
  const childRef = isValidElement(children)
    ? (children as any)?.props?.ref ?? (children as any)?.ref
    : null;

  // Always pass the same array structure to useMergeRefs to ensure consistent behavior
  // useMergeRefs will handle null/undefined refs internally
  const ref = useMergeRefs([context.refs.setReference, propRef, childRef]);

  const testId = `${context.testId ?? 'popover'}-trigger`;
  const trackingId = `${context.trackingId ?? context.testId ?? 'popover'}-trigger`;

  if (asChild && isValidElement(children)) {
    // Known issue: https://github.com/floating-ui/floating-ui/discussions/3405
    // eslint-disable-next-line react-hooks/refs
    const targetProps = context.getReferenceProps({
      ...props,
      ...children.props,
      ref,
      // @ts-expect-error - data-testid and data-trackingid are valid HTML props
      'data-testid': testId,
      'data-trackingid': trackingId,
    });
    return cloneElement(children, targetProps);
  }

  return (
    <button
      ref={ref}
      type="button"
      data-testid={testId}
      data-trackingid={trackingId}
      {...context.getReferenceProps(props)}
    >
      {children}
    </button>
  );
});
