import { type Dispatch, type SetStateAction, useState } from 'react';
import { useDebounce } from 'react-use';

import type { InteractionItem } from '../components/viz';

export interface UseInteractionItemResult {
  setInteractionItem: Dispatch<SetStateAction<InteractionItem<any> | null>>;
  ineractionItem: InteractionItem<any> | null;
  undebouncedInteractionItem: InteractionItem<any> | null;
  cancelInteraction(): void;
}

/**
 * useInteractionItem
 *
 * Internal state and event handlers for charts
 *
 */
export const useInteractionItem = () => {
  const [interactionItem, setInteractionItem] = useState<InteractionItem<any> | null>(
    null,
  );
  const [debouncedItem, setDebouncedItem] = useState<InteractionItem<any> | null>(null);
  const [, cancel] = useDebounce(
    () => {
      setDebouncedItem(interactionItem);
    },
    250,
    [interactionItem],
  );
  return {
    setInteractionItem,
    interactionItem: debouncedItem,
    undebouncedInteractionItem: interactionItem,
    cancelInteraction: cancel,
  };
};
