import { useEffect, useMemo, useState } from 'react';
import ReactSelect, {
  ActionMeta,
  ClassNamesConfig,
  ClearIndicatorProps,
  components,
  ControlProps,
  DropdownIndicatorProps,
  InputProps,
  MultiValueProps,
  OptionProps,
  SelectComponentsConfig,
  StylesConfig,
} from 'react-select';
import cx from 'classnames';

import { Controller, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { useSkeletonContext } from '../../../sourdough';
import { get } from '../../../utils';
import {
  type DropdownOption,
  type DropdownOptionGroup,
  getFlattenedDropdownOptions,
} from '../../DropdownOptions';
import { Icon } from '../../Icon';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { RyeconCaretDown, RyeconClose, RyeconMagnifyingGlass } from '../../ryecons';
