import './MultiSelect.css';

// Classnames marked with (!) important are overriding internal react-select styling
const dropdownSizes: {
  [k: string]: {
    className: string;
    classNames?: ClassNamesConfig<DropdownOption, true, DropdownOptionGroup>;
  };
} = {
  xs: {
    className: 'min-h-[24px]',
    classNames: {
      control: () => '!min-h-[24px] !py-0',
      dropdownIndicator: () => '!py-0',
      input: () => '!py-0 !my-0',
      multiValueLabel: () => '!py-0 !my-0',
      multiValue: () => '!my-0 leading-4',
      multiValueRemove: () => '!h-4',
      clearIndicator: () => '!py-1',
    },
  },
  sm: {
    className: 'min-h-[32px]',
    classNames: {
      control: () => '!min-h-[32px] !py-0',
      multiValueLabel: () => '!py-0 !my-0',
      multiValue: () => '!my-0',
      multiValueRemove: () => '!h-4',
      clearIndicator: () => '!py-1',
    },
  },
  md: {
    className: 'min-h-[40px]',
    classNames: {
      control: () => '!min-h-[40px]',
    },
  },
};

export interface BaseMultiSelectProps {
  /** The Name of the mutli-select field **/
  name: string;

  /** An array of options for the dropdown */
  options: (DropdownOption | DropdownOptionGroup)[];

  /** The default value of the form */
  defaultValue?: DropdownOption[];

  /** Helpful description text for the field */
  description?: React.ReactNode;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** Classname(s) for the wrapping element */
  className?: string;

  /** Any onChange handling, allows for extra handling past the default react-hook-form usage */
  onChange?: (selectedOptions: readonly DropdownOption[]) => void;

  /** The maximum number of selected items to display before
   * truncating.  When set to 0, this will behave the same as 1 with a
   * single selected item, but in all other cases will show only "#
   * selected" rather than the ordinary overflow text of "+# more...". */
  maxDisplayedSelectedItems?: number;

  /** Boolean to display a select all option */
  showSelectAll?: boolean;

  /** Custom select all text */
  selectAllText?: string;

  /** When true, the select all option will act as a distinct value.
   * React-hook-form and the onChange will recieve a single "ALL" dropdown option, rather than an array of all available options
   * Useful for cases where we need to differentiate between "all into perpetuity", and "all that exist right now" */
  enableDistinctSelectAll?: boolean;

  /** Whether to close the menu automatically after selecting an option */
  closeMenuOnSelect?: boolean;

  /** If passed, dropdown will be rendered on the specified element. Useful in contexts where a container might have overflow:hidden */
  portalElement?: HTMLElement | null;

  /** Flag to indicate react-select menuPlacement, when omitted it is set to 'auto' */
  shouldOpenBottom?: boolean;

  /** Placeholder message when no items are selected */
  placeholder?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** option enabling/disabling searchable text and icon */
  isSearchable?: boolean;

  /** vertical height of dropdown input */
  size?: 'xs' | 'sm' | 'md';

  // Styles objects for react select
  reactSelectStyles?: StylesConfig<DropdownOption, true, DropdownOptionGroup>;

  // Component overrides for react select
  reactSelectComponents?: SelectComponentsConfig<
    DropdownOption,
    true,
    DropdownOptionGroup
  >;
}

export type MultiSelectProps = BaseInputProps & BaseMultiSelectProps;

const Control: React.FC<ControlProps<DropdownOption, true, DropdownOptionGroup>> = ({
  children,
  ...props
}) => {
  const { isSearchable } = props.selectProps;
  return (
    <components.Control {...props}>
      {isSearchable && (
        <Icon ryecon={RyeconMagnifyingGlass} className="text-fgDecorative ml-3" />
      )}
      {children}
    </components.Control>
  );
};

const ClearIndicator: React.FC<
  ClearIndicatorProps<DropdownOption, true, DropdownOptionGroup>
> = (props) => (
  <components.ClearIndicator {...props}>
    <Icon ryecon={RyeconClose} className="text-fgMain" />
  </components.ClearIndicator>
);

const DropdownIndicator: React.FC<
  DropdownIndicatorProps<DropdownOption, true, DropdownOptionGroup>
> = (props) => (
  <components.DropdownIndicator {...props}>
    <Icon ryecon={RyeconCaretDown} className="text-fgMain" />
  </components.DropdownIndicator>
);

// react-select is adding color on the style prop internally so !important is required to only override text color
const Input: React.FC<InputProps<DropdownOption, true, DropdownOptionGroup>> = (
  props,
) => {
  return (
    <components.Input {...props} inputClassName="focus:ring-transparent !text-fgMain" />
  );
};

const Option: React.FC<OptionProps<DropdownOption, true, DropdownOptionGroup>> = ({
  children,
  ...props
}) => {
  return (
    <components.Option {...props}>
      <div
        className="flex items-center"
        data-testid={`multi-select-option-${props.data.value}`}
        data-trackingid={`multi-select-option-${props.data.value}`}
      >
        <Checkbox
          name="option"
          ignoreForm
          isEdit
          className="mb-1 mr-2"
          defaultChecked={props.isSelected}
        />
        {children}
      </div>
    </components.Option>
  );
};

interface CustomMultiValueProps
  extends MultiValueProps<DropdownOption, true, DropdownOptionGroup> {
  numOptionsSelected: number;
  numOptionsToShow: number;
}

const CustomMultiValue: React.FC<CustomMultiValueProps> = ({
  numOptionsSelected,
  numOptionsToShow,
  ...props
}) => {
  const shouldDisplayItem = props.index < numOptionsToShow;
  const shouldDisplayOverflow = props.index === numOptionsToShow;

  const numOverflowItems = numOptionsSelected - numOptionsToShow;
  // When showing 0 options, `+X more` doesn't make sense
  const overflowText =
    numOptionsToShow > 0
      ? `+${numOverflowItems} more...`
      : `${numOverflowItems} selected`;

  return shouldDisplayItem ? (
    <components.MultiValue {...props} />
  ) : shouldDisplayOverflow ? (
    <p className="ml-2">{overflowText}</p>
  ) : null;
};

export const SELECT_ALL_VALUE = 'ALL';

const MultiSelectComponent: React.FC<MultiSelectProps> = ({
  options,
  defaultValue,
  placeholder,
  showSelectAll,
  selectAllText = 'All',
  enableDistinctSelectAll,
  maxDisplayedSelectedItems = 2,
  closeMenuOnSelect,
  onChange,
  portalElement,
  shouldOpenBottom,
  isDisabled,
  isSearchable = true,
  reactSelectStyles,
  reactSelectComponents,
  size = 'md',
}) => {
  const [selectedOptions, setSelectedOptions] = useState<readonly DropdownOption[]>(
    defaultValue || [],
  );

  // If default value changes, update the selected options
  useEffect(() => {
    if (defaultValue) {
      setSelectedOptions(defaultValue);
    }
  }, [defaultValue]);

  const selectAllOption = useMemo(() => {
    return {
      value: SELECT_ALL_VALUE,
      label: selectAllText,
    };
  }, [selectAllText]);

  const availableOptions = useMemo(() => {
    return [...(showSelectAll ? [selectAllOption] : []), ...options];
  }, [options, selectAllOption, showSelectAll]);

  const isSelectAllSelected = () =>
    !!showSelectAll &&
    (enableDistinctSelectAll
      ? selectedOptions.some(({ value }) => value === SELECT_ALL_VALUE)
      : selectedOptions.length === options.length);

  const isOptionSelected = (option: DropdownOption) =>
    selectedOptions.some(({ value }) => value === option.value) ||
    (!enableDistinctSelectAll && isSelectAllSelected());

  const handleChange = (
    newValue: readonly DropdownOption[],
    actionMeta: ActionMeta<DropdownOption>,
  ) => {
    const { action, option, removedValue } = actionMeta;

    let optionsToSet: DropdownOption[] = [];

    if (enableDistinctSelectAll) {
      // Distinct mode:
      // Select all is its own distinct option.
      // If "all" is selected, we unselect deselect else. If something else gets selected, we deselect "all".
      if (action === 'select-option' && option?.value === SELECT_ALL_VALUE) {
        optionsToSet = [selectAllOption];
      } else if (
        actionMeta.action === 'select-option' &&
        option?.value !== SELECT_ALL_VALUE &&
        isSelectAllSelected()
      ) {
        const filteredOptions = getFlattenedDropdownOptions([...newValue]).filter(
          ({ value }) => value !== SELECT_ALL_VALUE,
        );
        optionsToSet = filteredOptions;
      } else {
        optionsToSet = [...newValue];
      }
    } else {
      // Default (non distinct) mode:
      // Select all is just a UX feature.
      // If "all" is selected, we select everything.
      // If "all" is deselected, we deselect everything.
      //
      // eslint-disable-next-line no-lonely-if
      if (action === 'select-option' && option?.value === SELECT_ALL_VALUE) {
        const allOptions = getFlattenedDropdownOptions(options);
        optionsToSet = allOptions;
      } else if (
        (action === 'deselect-option' && option?.value === SELECT_ALL_VALUE) ||
        (action === 'remove-value' && removedValue?.value === SELECT_ALL_VALUE)
      ) {
        optionsToSet = [];
      } else if (actionMeta.action === 'deselect-option' && isSelectAllSelected()) {
        const filteredOptions = getFlattenedDropdownOptions(options).filter(
          ({ value }) => value !== option?.value,
        );
        optionsToSet = filteredOptions;
      } else {
        optionsToSet = [...newValue];
      }
    }

    setSelectedOptions(optionsToSet);
    onChange?.(optionsToSet);
  };

  /* In situations where the MultiSelect has limited horizontal space,
     a selected item and overflow text can't both fit.  If
     maxDisplayedSelectedItems is 0, then overflow text will normally
     be displayed.  However, if only one option is selected, we can
     just display that instead, which is especially useful when there
     is an option for ALL. */
  const numOptionsToShow =
    maxDisplayedSelectedItems === 0 && selectedOptions.length === 1
      ? 1
      : maxDisplayedSelectedItems;

  return (
    <ReactSelect<DropdownOption, true, DropdownOptionGroup>
      isMulti
      isSearchable={isSearchable}
      options={availableOptions}
      isOptionSelected={isOptionSelected}
      value={isSelectAllSelected() ? [selectAllOption] : selectedOptions}
      placeholder={placeholder}
      closeMenuOnSelect={closeMenuOnSelect}
      menuPlacement={
        shouldOpenBottom === undefined ? 'auto' : shouldOpenBottom ? 'bottom' : 'top'
      }
      onChange={handleChange}
      isDisabled={isDisabled}
      hideSelectedOptions={false}
      className={cx('multi-select-container', dropdownSizes[size].className)}
      classNames={{
        ...dropdownSizes[size].classNames,
      }}
      classNamePrefix="multi-select"
      menuPortalTarget={portalElement}
      styles={{
        ...reactSelectStyles,
        // @ts-ignore
        menuPortal: (baseStyles, props) => ({
          ...baseStyles,
          zIndex: 100, // Ensure portal always appears above other elements
          ...(reactSelectStyles?.menuPortal?.(baseStyles, props) || {}),
        }),
      }}
      components={{
        ClearIndicator,
        Control,
        DropdownIndicator,
        Input,
        MultiValue: (props) => {
          return (
            <CustomMultiValue
              numOptionsToShow={numOptionsToShow}
              numOptionsSelected={selectedOptions.length}
              {...props}
            />
          );
        },
        Option,
        ...reactSelectComponents,
      }}
    />
  );
};

export const MultiSelect: React.FC<MultiSelectProps> = ({
  name,
  options,
  label,
  labelIsHidden = false,
  tooltip,
  helpLink,
  onHelpClick,
  description,
  showSelectAll,
  portalElement,
  shouldOpenBottom,
  selectAllText = 'All',
  enableDistinctSelectAll,
  maxDisplayedSelectedItems = 2,
  error,
  isEdit,
  isOptional,
  children,
  placeholder = 'Select option...',
  closeMenuOnSelect = true,
  defaultValue,
  onChange: providedOnChange,
  className,
  isDisabled,
  testId = 'multi-select',
  trackingId = 'multi-select',
  skeleton = false,
  isSearchable = true,
  size = 'md',
  reactSelectStyles,
  reactSelectComponents,
}): React.ReactElement => {
  const formContext = useFormContext();
  const errors = formContext?.formState.errors;
  const errorMessage = get(errors && errors, name)?.message ?? error;

  const formSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || formSkeleton;

  const hasError = !!errorMessage;

  return (
    <Field
      label={label}
      labelIsHidden={labelIsHidden}
      tooltip={tooltip}
      helpLink={helpLink}
      onHelpClick={onHelpClick}
      isOptional={isOptional}
      isEdit={isEdit}
      className={cx(className, {
        'multi-select-input-error': hasError, // Enables custom classes for error states
      })}
      isDisabled={isDisabled}
      testId={testId}
      trackingId={trackingId}
    >
      {!shouldSkeleton && (
        <>
          {!isEdit && (
            <div
              className={cx(
                'bg-bgDisabled text-fgMain font-body-sm flex items-center rounded-md px-3 py-[10px]',
                {
                  'min-h-[24px]': size === 'xs',
                  'min-h-[32px]': size === 'sm',
                  'min-h-[40px]': size === 'md',
                },
                className,
              )}
              data-testid={`${testId}-display`}
              data-trackingid={`${trackingId}-display`}
            >
              {children ||
                (defaultValue?.map((option) => option.label).join(', ') ?? '')}
            </div>
          )}
          {isEdit && (
            <>
              {!!formContext?.control && (
                <Controller
                  control={formContext.control}
                  name={name}
                  render={({ field: { onChange: hookFormChange, value } }) => {
                    const defaultFormValue = value;
                    return (
                      <MultiSelectComponent
                        name={name}
                        options={options}
                        defaultValue={defaultFormValue}
                        placeholder={placeholder}
                        showSelectAll={showSelectAll}
                        selectAllText={selectAllText}
                        enableDistinctSelectAll={enableDistinctSelectAll}
                        maxDisplayedSelectedItems={maxDisplayedSelectedItems}
                        closeMenuOnSelect={closeMenuOnSelect}
                        onChange={(selectedOptions) => {
                          if (providedOnChange) {
                            providedOnChange(selectedOptions);
                          }

                          hookFormChange(selectedOptions);
                        }}
                        portalElement={portalElement}
                        isDisabled={isDisabled}
                        shouldOpenBottom={shouldOpenBottom}
                        isSearchable={isSearchable}
                        size={size}
                        reactSelectStyles={reactSelectStyles}
                        reactSelectComponents={reactSelectComponents}
                      />
                    );
                  }}
                />
              )}
              {!formContext?.control && (
                <MultiSelectComponent
                  name={name}
                  options={options}
                  defaultValue={defaultValue}
                  placeholder={placeholder}
                  showSelectAll={showSelectAll}
                  selectAllText={selectAllText}
                  enableDistinctSelectAll={enableDistinctSelectAll}
                  maxDisplayedSelectedItems={maxDisplayedSelectedItems}
                  closeMenuOnSelect={closeMenuOnSelect}
                  onChange={providedOnChange ? providedOnChange : undefined}
                  portalElement={portalElement}
                  isDisabled={isDisabled}
                  shouldOpenBottom={shouldOpenBottom}
                  isSearchable={isSearchable}
                  size={size}
                  reactSelectStyles={reactSelectStyles}
                  reactSelectComponents={reactSelectComponents}
                />
              )}
            </>
          )}
        </>
      )}
      {shouldSkeleton && (
        <LoadingBlock loaderClassName="min-h-input w-full rounded-md" />
      )}
      <FormFieldMessage
        name={name}
        description={description}
        errorMessage={errorMessage}
        isEdit={isEdit}
        testId={testId}
        trackingId={trackingId}
      />
    </Field>
  );
};
