import { useCallback, useEffect, useMemo, useState } from 'react';

import { DEFAULT_ITEM_HEIGHT, parseItemHeights } from '../constants';
import { FileTreeItemType, ItemHeights } from '../types';

interface FileTreeHeightParams {
  /**
   * The nodes (files and folders) which make up the FileTree
   */
  items: FileTreeItemType[];
  /**
   * Array of relative paths that will show folder's children
   */
  openDirectories: string[];
  /**
   * The name of the root node
   */
  rootNodeName: string;
  /**
   * Minimum height of the FileTree in pixels
   * @default DEFAULT_ITEM_HEIGHT (28)
   */
  minHeight?: number;
  /**
   * Maximum height of the FileTree in pixels
   * @default 600
   */
  maxHeight?: number;
  /**
   * The height of each tree item in pixels. It can be set for each type of item (file, directory, loadMore, loading, empty)
   * @default
   * {
   *  file: 28,
   *  directory: 28,
   *  loadMore: 32,
   *  loading: 28,
   *  empty: 28
   * }
   */
  itemHeights?: ItemHeights;
}

/**
 * A hook that calculates the appropriate height for the FileTree container
 * based on the number of visible items. The height will update when directories
 * are opened or closed.
 *
 * Requires openDirectories/setOpenDirectories to be used by the FileTree.
 */
export const useFileTreeHeight = ({
  items,
  openDirectories,
  rootNodeName,
  minHeight = DEFAULT_ITEM_HEIGHT,
  maxHeight = 600,
  itemHeights,
}: FileTreeHeightParams) => {
  const [containerHeight, setContainerHeight] = useState(minHeight);
  const parsedItemHeights = parseItemHeights(itemHeights);
  // count visible items in the tree based on what directories are open
  const calculateVisibleItems = useCallback(() => {
    let size = 0;
    const rootItems = items.filter((item) => item.parent === rootNodeName);

    if (items.length === 0) return size;

    size += rootItems.length * parsedItemHeights.root;

    openDirectories.forEach((dirPath) => {
      if (!dirPath) return;

      const children = items.filter((item) => {
        if (!item.id || item.id === dirPath) return false;

        const itemParts = item.id.split('/');
        const dirParts = dirPath.split('/');
        // we must evaluate if all parents of the item are open, otherwise we should not calculate the height of the item
        const parents: string[] = itemParts
          .slice(0, -1)
          .reduce((acc: string[], part) => {
            // we only add the '/' if it's not the first part
            const path = `${acc.length > 0 ? '/' : ''}${part}`;
            const lastParent = acc[acc.length - 1] ?? '';
            // The last parent will always have the complete path of their ancestors
            acc.push(`${lastParent}${path}`);
            return acc;
          }, []);

        if (!parents.every((parent) => openDirectories.includes(parent))) return false;

        return (
          item.id.startsWith(`${dirPath}/`) && itemParts.length === dirParts.length + 1
        );
      });

      children.forEach((child) => {
        size += parsedItemHeights[child.data.pathType];
      });
    });

    return size;
  }, [parsedItemHeights, items, openDirectories, rootNodeName]);

  useEffect(() => {
    const size = calculateVisibleItems();
    const calculatedHeight = Math.min(maxHeight, Math.max(minHeight, size));
    setContainerHeight(calculatedHeight);
  }, [
    calculateVisibleItems,
    parsedItemHeights,
    itemHeights,
    maxHeight,
    minHeight,
    openDirectories,
  ]);

  return useMemo(
    () => ({
      containerHeight,
      itemCount: calculateVisibleItems(),
    }),
    [containerHeight, calculateVisibleItems],
  );
};
