import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { HeadlessContent } from './headless/HeadlessContent';
import type { ContentProps } from './types';

const boxClasses = 'p-4 min-w-[256px] max-w-[512px] rounded-md shadow-hover';
const colorClasses =
  'focus-visible:ring-focusBrand border border-borderMuted bg-bgMain text-fgMain';

export const Content = ({
  children,
  className,
  style,
  /** @deprecated Let user config set variant */
  variant,
  ...rest
}: ContentProps) => {
  const wrapperClassNames = twMerge(
    cx(
      boxClasses,
      colorClasses,
      {
        dark: variant === 'dark',
        light: variant === 'light',
      },
      className,
    ),
  );

  return (
    <HeadlessContent
      {...rest}
      className={wrapperClassNames}
      style={{ width: 'fit-content', ...style }}
    >
      {children}
    </HeadlessContent>
  );
};
