import { useEffect } from 'react';
import cx from 'classnames';

import { useLiveRegion } from '../../hooks';
import { ActionList, Actions } from '../Actions';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { Notification, NotificationBanner } from '../NotificationBanner';
import { CardResourceLink } from './cardSubComponents/CardResourceLink.internal';
import { CardSubheader } from './cardSubComponents/CardSubheader.internal';

export interface CardProps {
  /** Children to display in the card */
  children?: React.ReactNode;

  /** A header string */
  header?: React.ReactNode;

  /** A single sentence to convey extra information about the card */
  tagline?: React.ReactNode;

  /** An array of header actions */
  actions?: ActionList;

  /** Error notification to display, if it exists */
  errorNotification?: Notification;

  /** A callback to be triggered when the error banner close button is clicked **/
  onErrorDismiss?: () => void;

  /** Flag to enable __compact__ styling */
  isCompact?: boolean;

  /** Flag to enable sticky header */
  isSticky?: boolean;

  /** Flag to enable __borderless_ styling */
  isBorderless?: boolean;

  /** Classnames for the card */
  className?: string;

  /** Flag to show the card in a skeleton loading state */
  skeleton?: boolean;

  /** data-test-id for cypress test targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export interface CardSubComponents {
  Subheader: typeof CardSubheader;
  ResourceLink: typeof CardResourceLink;
}

export const Card: React.FC<CardProps> & CardSubComponents = ({
  children,
  header,
  tagline,
  actions,
  errorNotification,
  onErrorDismiss,
  isCompact = false,
  isBorderless = false,
  isSticky = false,
  skeleton = false,
  className = '',
  testId = 'card',
  trackingId = 'card',
}): React.ReactElement => {
  const {
    clearMessage: clearErrorNotification,
    LiveRegion: ErrorNotification,
    setMessage: setErrorNotification,
  } = useLiveRegion();

  useEffect(() => {
    if (errorNotification) {
      setErrorNotification(
        <NotificationBanner
          notification={errorNotification}
          onCloseClick={onErrorDismiss}
        />,
      );
    } else {
      clearErrorNotification();
    }
  }, [clearErrorNotification, errorNotification, onErrorDismiss, setErrorNotification]);

  const classNames = cx(
    'bg-bgMain',
    {
      'p-4 sm:p-6 md:p-8': !isCompact,
      'py-4 sm:py-6 md:py-8': isCompact && header != null,
      'border-borderMuted rounded-lg border': !isBorderless,
    },
    className,
  );

  return (
    <div className={classNames} data-testid={testId} data-trackingid={trackingId}>
      {(!!skeleton || !!header || !!actions || !!tagline) && (
        <div
          className={cx('mb-6 space-y-1', {
            'bg-bgMain sticky top-0 z-10 -mx-1 -mt-2 px-1 pt-2': isSticky,
          })}
        >
          {skeleton && (
            <div className={cx({ 'px-4 sm:px-6 md:px-8': isCompact })}>
              <LoadingBlock width={250} height={25} />
            </div>
          )}
          {!skeleton && (!!header || !!actions) && (
            <div
              className={cx('flex flex-wrap items-center justify-between gap-y-2', {
                'px-4 sm:px-6 md:px-8': isCompact,
                'border-borderMuted border-b pb-2': isSticky && !tagline,
              })}
            >
              {!!header && (
                <h2
                  className="font-heading-3 text-fgMain"
                  data-testid={`${testId}-header`}
                  data-trackingid={`${trackingId}-header`}
                >
                  {header}
                </h2>
              )}
              {!!actions?.length && (
                <div
                  className="ml-4 flex min-w-0 flex-wrap gap-2"
                  data-testid={`${testId}-actions`}
                  data-trackingid={`${trackingId}-actions`}
                >
                  <Actions actions={actions} />
                </div>
              )}
            </div>
          )}
          {!!tagline && (
            <p
              className={cx('text-fgDecorative font-caption', {
                'px-4 sm:px-6 md:px-8': isCompact,
                'border-borderMuted border-b pb-2': isSticky,
              })}
              data-testid={`${testId}-tagline`}
              data-trackingid={`${trackingId}-tagline`}
            >
              {tagline}
            </p>
          )}
        </div>
      )}
      {/*
        We need this to be visible to everyone & announced by screenreaders,
        so we can't conditionally render the notification. This keeps it
        from affecting layout until it actually needs to be visible.
      */}
      <div className={errorNotification ? 'mb-6' : 'sr-only'}>
        <ErrorNotification />
      </div>
      <div className="text-fgMain font-body space-y-12">{children}</div>
    </div>
  );
};

Card.Subheader = CardSubheader;
Card.ResourceLink = CardResourceLink;
