import React from 'react';
import { Link as RouterLink, LinkProps, NavLink, NavLinkProps } from 'react-router-dom';
import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { baseButtonClassNames } from '../Button/BaseButton.internal';
import { buttonClassNames, ButtonStyleType } from '../Button/buttonClassNames.internal';
import { Sizes } from '../types';

interface LinkOrAnchorBase {
  /** To be used when linking to other pages within the same app, uses a react-router Link, with our classes applied. */
  isInternal: boolean;
  shouldOpenNewTab?: boolean;
  testId?: string;
  trackingId?: string;
  children: React.ReactNode;
  hideUnderline?: boolean;
  /** special use-cases; see stories; overridden if you declare a buttonStyleType */
  colorVariant?:
    | 'default'
    | 'headless'
    | 'success'
    | 'error'
    | 'warning'
    | 'info'
    | 'tooltip' /** @deprecated. We now use tokens to handle dark background SURF-1569 */
    | 'light' /** @deprecated. We now use tokens to handle dark background SURF-1569 */
    | 'info';
  onClick?(e: React.MouseEvent<HTMLAnchorElement>): void;
  /** Use if you need a link to look like a button; overrides colorVariant styles */
  buttonStyleType?: ButtonStyleType;
  /** Use with buttonStyleType */
  buttonIsDisabled?: boolean;
  /** Use with buttonStyleType */
  buttonIsRounded?: boolean;
  /** Use with buttonStyleType */
  buttonSize?: Sizes;
}

interface InternalLink extends LinkProps {
  activeClassName?: never;
  type?: 'link';
  className?: string;
}

interface InternalNavLink extends NavLinkProps {
  type?: 'navlink';
  className?: string;
  /** If you need additional classNames that only exist when a nav link is active, put them here. */
  activeClassName?: string;
}

interface ExternalLink {
  activeClassName?: never;
  className?: string;
  to: string;
  type?: 'link';
}

export type LinkOrAnchorProps = LinkOrAnchorBase &
  (InternalLink | InternalNavLink | ExternalLink);

export const Link: React.ForwardRefExoticComponent<LinkOrAnchorProps> =
  React.forwardRef(
    (
      {
        isInternal,
        children,
        to,
        activeClassName,
        className,
        testId,
        trackingId,
        colorVariant = 'default',
        type = 'link',
        shouldOpenNewTab = false,
        hideUnderline = false,
        buttonStyleType,
        buttonIsDisabled,
        buttonIsRounded,
        buttonSize,
        ...restProps
      },
      ref,
    ) => {
      const linkClasses = buttonStyleType
        ? twMerge(
            cx(
              baseButtonClassNames({ isRounded: buttonIsRounded, size: buttonSize }),
              buttonClassNames({
                isDisabled: buttonIsDisabled,
                isRounded: buttonIsRounded,
                type: buttonStyleType,
              }),
              className,
            ),
          )
        : twMerge(
            cx(
              {
                'text-fgMain hover:text-fgAlt active:text-fgAlt font-medium no-underline':
                  colorVariant === 'default' || colorVariant === 'tooltip',
                'decoration-borderMain hover:decoration-borderMainHover active:decoration-borderMainActive underline underline-offset-2':
                  colorVariant === 'default' && !hideUnderline,
                'text-fgSuccess hover:text-fgSuccessHover active:text-fgSuccessActive decoration-borderMuted hover:decoration-borderSuccessHover underline underline-offset-4':
                  colorVariant === 'success',
                'text-fgDanger hover:text-fgDangerHover active:text-fgDangerActive decoration-borderMuted hover:decoration-borderDangerHover underline underline-offset-4':
                  colorVariant === 'error',
                'text-fgWarning hover:text-fgWarningHover active:text-fgWarningActive decoration-borderMuted hover:decoration-borderWarningHover underline underline-offset-4':
                  colorVariant === 'warning',
                'no-underline': colorVariant === 'headless',
                /**
                 * TODO: deprecate with SURF-1569
                 */
                'text-fgDecorative hover:text-fgDecorative active:text-fgDecorative':
                  colorVariant === 'light',
                'text-fgInfo hover:text-fgInfoHover active:text-fgInfoActive decoration-borderMuted hover:decoration-borderInfoHover underline underline-offset-4':
                  colorVariant === 'info',
                underline: !hideUnderline,
              },
              className,
              'focus-visible:outline-focusBrand focus-visible:ring-offset-bgMain outline-offset-2 focus-visible:z-[2]',
            ),
          );

      if (isInternal) {
        if (type === 'navlink') {
          return (
            <NavLink
              to={to}
              className={({ isActive }) =>
                twMerge(
                  className,
                  cx({
                    [activeClassName ?? '']: isActive,
                  }),
                )
              }
              data-testid={testId}
              data-trackingid={trackingId}
              ref={ref as React.ForwardedRef<HTMLAnchorElement>}
              {...(restProps as Partial<InternalNavLink>)}
            >
              {children}
            </NavLink>
          );
        }
        return (
          <RouterLink
            to={to}
            className={linkClasses}
            data-testid={testId}
            data-trackingid={trackingId}
            ref={ref as React.ForwardedRef<HTMLAnchorElement>}
            {...(shouldOpenNewTab
              ? {
                  rel: shouldOpenNewTab ? 'noreferrer' : undefined,
                  target: shouldOpenNewTab ? '_blank' : undefined,
                }
              : {})}
            {...(restProps as Partial<InternalLink>)}
          >
            {children}
          </RouterLink>
        );
      }
      return (
        <a
          href={String(to)}
          className={linkClasses}
          data-testid={testId}
          data-trackingid={trackingId}
          ref={ref as React.ForwardedRef<HTMLAnchorElement>}
          {...(shouldOpenNewTab
            ? {
                rel: shouldOpenNewTab ? 'noreferrer' : undefined,
                target: shouldOpenNewTab ? '_blank' : undefined,
              }
            : {})}
          {...(restProps as Partial<React.ComponentProps<'a'>>)}
        >
          {children}
        </a>
      );
    },
  );
