import { ReactNode } from 'react';
import cx from 'classnames';

import { InvisibleButton } from '../InvisibleButton';
import { AccordionIcon } from './AccordionIcon.internal';

interface AccordionHeaderProps {
  /** Any component.  It will be rendered on the right side of the header. */
  actions?: ReactNode;
  /** An icon to display next to the caret open toggle button */
  icon: ReactNode;
  /** If the accordion is open */
  isOpen: boolean;
  /** The title text to show in the accordion header */
  title: ReactNode;
  /** Handler for when clicking on the header and caret toggle open button */
  toggleOpen: () => void;
  /** A boolean representing whether the header is disabled */
  isDisabled?: boolean;
  /** A boolean for applying sticky css to the AccordionHeader */
  isSticky?: boolean;
}

const AccordionHeader = ({
  actions,
  icon,
  isOpen,
  title,
  toggleOpen,
  isSticky,
  isDisabled,
}: AccordionHeaderProps) => {
  const wrapperClassName = 'flex items-center justify-between gap-1';
  const headerWrapperClassName = cx(
    'bg-bgMain top-0 z-10 flex min-w-0 items-center gap-2',
    {
      sticky: isSticky,
      'shadow-hover': isSticky,
    },
  );

  return (
    <div className={headerWrapperClassName}>
      <InvisibleButton
        onClick={toggleOpen}
        aria-expanded={isOpen}
        disabled={isDisabled}
        className="flex-grow truncate px-4 py-3"
      >
        <div className={wrapperClassName} data-testid="accordion-header">
          <div className="flex min-w-0 items-center gap-2">
            <AccordionIcon isOpen={isOpen} isDisabled={isDisabled} />
            <div data-testid="accordion-icon" className="flex items-center">
              {icon}
            </div>
            <div
              className="text-fgMain font-body min-w-0 flex-1 text-left font-medium"
              data-testid="accordion-title"
            >
              {title}
            </div>
          </div>
        </div>
      </InvisibleButton>
      {actions && (
        <div className="flex-shrink-0 px-4 py-3" data-testid="accordion-actions">
          {actions}
        </div>
      )}
    </div>
  );
};

export { AccordionHeader };
