import { Cell, flexRender } from '@tanstack/react-table';
import cx from 'classnames';

import { type CellProps, type CellVariant, type DefaultRowProps } from '../types';
import { getColumnStyles } from '../utils';
import { LoadingCell } from './LoadingCell';

const CELL_VARIANT_CLASSES: { [key in CellVariant]: string } = {
  DEFAULT: 'px-3 py-[11.5px] first:font-medium',
  COMPACT: 'px-3 py-2',
  NO_PADDING: 'p-0',
};

export const DefaultCell = <
  TData extends DefaultRowProps = DefaultRowProps,
  TValue extends React.ReactNode = React.ReactNode,
>({
  row,
  cell,
  index,
  stickyColumn,
  testId,
  trackingId,
  selected,
  handleCellClick,
  isClickable,
  cellVariant = 'DEFAULT',
}: CellProps<TData, TValue> & {
  handleCellClick?: (cell: Cell<TData, TValue>) => void;
  selected?: boolean;
  isClickable: boolean;
}): React.ReactElement => {
  const hoverClasses = 'cursor-pointer';
  const classNames = cx(
    'border-borderMuted flex items-center whitespace-nowrap border-b bg-inherit',
    {
      'hover:bg-bgMainHover active:bg-bgMainActive cursor-pointer`': isClickable,
      'first:border-borderMuted first:sticky first:left-0 first:border-r':
        stickyColumn === 'first',
      'last:border-borderMuted last:sticky last:right-0 last:border-l':
        stickyColumn === 'last',
      'justify-end':
        cell.column.columnDef.meta?.align === 'end' ||
        cell.column.columnDef.meta?.align === 'right',
      [hoverClasses]: isClickable && !selected,
    },
    CELL_VARIANT_CLASSES[cellVariant],
  );

  return (
    <td
      key={cell.id}
      className={classNames}
      data-testid={`${testId}-cell-${index}`}
      data-trackingid={`${trackingId || testId}-cell-${index}`}
      data-selected={selected}
      style={{
        ...getColumnStyles<TData, TValue>(cell.column.columnDef),
      }}
      onClick={() => handleCellClick && handleCellClick(cell)}
    >
      {flexRender(
        row.original.isLoadingRow ? LoadingCell : cell.column.columnDef.cell,
        cell.getContext(),
      )}
    </td>
  );
};
