import { ButtonHTMLAttributes } from 'react';
import { MouseEvent, ReactNode } from 'react';
import cx from 'classnames';

interface InvisibleButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  children: ReactNode;
  onClick: (e: MouseEvent<HTMLButtonElement>) => void;
  testId?: string;
  trackingId?: string;
}

const InvisibleButton = ({
  children,
  onClick,
  className,
  testId = 'invisible-button',
  trackingId = 'invisible-button',
  ...others
}: InvisibleButtonProps) => {
  const baseClassName =
    'w-full focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-focusBrand focus-visible:ring-offset-focusInverse transition-colors rounded focus-visible:ring-offset-2';

  return (
    <button
      type="button"
      onClick={onClick}
      {...others}
      className={cx(baseClassName, className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {children}
    </button>
  );
};

export { InvisibleButton };
