import cx from 'classnames';

interface DisplayProps {
  /** The text to render */
  children: string;
  /** An optional testId for cypress */
  testId?: string;
}

export const Display = ({ children, testId }: DisplayProps) => (
  <h1 className={cx('font-display text-fgMain')} data-testid={testId}>
    {children}
  </h1>
);
