import cx from 'classnames';

import { Button } from '../../Button';
import { ColorSet } from '../Chart';
import { PlotInfo, useChartContext } from '../ChartProvider/ChartProvider';
import { createFullPlotId, isPlotFocused } from '../util';

export interface LegendProps {
  /** Width of the Legend when position is `right` */
  width?: number;
  /** Position of the legend */
  position?: 'bottom' | 'right';
}

const createLegendColorClassNames = (colorSet: ColorSet, focused: boolean) => {
  return cx(colorSet.legendIconColor, focused ? colorSet.focused : colorSet.unfocused);
};

/** @deprecated */
export const Legend: React.FC<LegendProps> = ({ width, position = 'right' }) => {
  const { chartMeta, plots } = useChartContext() ?? {};
  const plotInfos = Object.values(plots ?? {});
  const focusPlotId = chartMeta?.focusPlotId;

  const createEntries = () => {
    return plotInfos.map((plotInfo: PlotInfo) => {
      const plotId = plotInfo.id;
      const plot = plots?.[plotId];

      if (plot) {
        const name = plot.name;
        return (Array.isArray(name) ? name : [name]).map(
          (subPlotName, subPlotIndex) => {
            const isFocused = isPlotFocused(focusPlotId, plotId, subPlotIndex);
            const color = plot?.getColor?.(subPlotIndex) ?? {};
            const swatchClassNames = cx(
              'h-3.5 w-3.5 rounded-sm stroke-none',
              { 'stroke-2': isFocused },
              createLegendColorClassNames(color, isFocused),
            );

            const entry = (
              <div key={createFullPlotId(plotId, subPlotIndex)}>
                <Button
                  type={'link'}
                  onClick={() => chartMeta?.onClickDataset!(plotId, subPlotIndex)}
                  className={cx('stroke-none', 'text-sm', 'text-fgMain')}
                >
                  <div className={swatchClassNames}></div>
                  {subPlotName}
                </Button>
              </div>
            );
            return entry;
          },
        );
      }
      return null;
    });
  };

  return (
    <div className={`m-4 space-y-0 w-[${width ?? 0}px] grow`}>
      <div>Legend</div>
      <div
        className={cx('flex', {
          'flex-row': position === 'bottom',
          'flex-col': position === 'right',
        })}
      >
        {createEntries()}
      </div>
    </div>
  );
};
