const canvas = document.createElement('canvas');

export const TRUNCATE_SVG_TEXT_RELATIVE_WIDTH = 0.85;

function getCssStyle(element: Element, prop: string) {
  return window.getComputedStyle(element, null).getPropertyValue(prop);
}

/**
 * Currently, we are unable to compute the text size so we're just going to use default values
 * @deprecated
 */
function getCanvasFont(el: SVGRectElement | null) {
  if (!el) {
    // eslint-disable-next-line sentence-case/sentence-case
    return '400 10px Sans Serif';
  }
  const fontWeight = getCssStyle(el, 'font-weight');
  const fontSize = getCssStyle(el, 'font-size');
  const fontFamily = getCssStyle(el, 'font-family');

  return `${fontWeight} ${fontSize} ${fontFamily}`;
}

/**
 * text-overflow etc. styles do not work in SVGs! So we have to manually
 * truncate and add ...
 *
 * https://stackoverflow.com/questions/15975440/add-ellipses-to-overflowing-text-in-svg
 * @deprecated
 */
export function truncateSvgTextXAxis(text: string, width: number): string | null {
  const context = canvas.getContext('2d');
  if (!context || typeof text !== 'string') return text;
  /**
   * TODO: Can we take in an element to calculate the font instead
   * of relying solely on the defaults? This would allow us to
   * set fonts dynamically and still calculate the text
   * size accurately.
   */
  context.font = getCanvasFont(null);

  // Compare to a relatively smaller width due to width calculation inaccuracy
  width *= TRUNCATE_SVG_TEXT_RELATIVE_WIDTH;

  let textWidth = context.measureText(text).width;
  if (textWidth <= width) return text;

  while (textWidth > width && text.length) {
    text = text.slice(0, -1);
    textWidth = context.measureText(`${text}…`).width;
  }
  return text ? `${text}…` : null;
}

/** @deprecated */
export const generateAxisTextFormatter =
  (allowTruncation: boolean, maxTextWidth: number) => (text: string) => {
    if (!allowTruncation) return text;

    const maybeTruncated = truncateSvgTextXAxis(text, maxTextWidth);
    if (maybeTruncated !== text) {
      return (
        <>
          <title>{text}</title>
          {maybeTruncated || '*'}
        </>
      );
    }
    return text;
  };
