import cx from 'classnames';

export interface FormLabelProps {
  /** Label text */
  label: string;

  /** Classnames */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
}

/** This component can be used to create arbitrary form labels for content that may not have its own sourdough component */
export const FormLabel: React.FC<FormLabelProps> = ({
  label,
  className,
  testId = 'form-label',
  trackingId = 'form-label',
}) => {
  return (
    <p
      className={cx('text-fgAlt font-label mb-1 block', className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {label}
    </p>
  );
};
