import { forwardRef } from 'react';
import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { Sizes } from '../types';
import { BaseButton, BaseButtonProps } from './BaseButton.internal';
import {
  buttonClassNames,
  ButtonStyleType as ButtonStyleTypeInternal,
} from './buttonClassNames.internal';

export type ButtonStyleType = ButtonStyleTypeInternal;

export type ButtonProps = BaseButtonProps & {
  /** The button style type */
  type?: ButtonStyleType;
};

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ type = 'primary', isDisabled, className, variant, children, ...props }, ref) => {
    const paginationStyles = cx(
      'hover:border-borderMainHover text-fgAlt hover:text-fgAltHover flex content-center justify-center rounded-md border-transparent',
      'focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2',
      {
        'min-h-[24px] min-w-[24px] px-1 py-[2px]': props.size === Sizes.sm,
        'bg-bgInverse text-fgInverse border-none': type === 'pagination-active',
      },
    );

    const buttonStyles = twMerge(
      cx(
        buttonClassNames({ isDisabled, type, variant }),
        {
          'focus-visible:border-borderMain': variant !== 'group',
          relative: true,
        },
        className,
      ),
    );

    const styleClasses =
      type === 'pagination' || type === 'pagination-active'
        ? paginationStyles
        : buttonStyles;

    return (
      <BaseButton
        innerRef={ref}
        isDisabled={isDisabled}
        variant={variant}
        className={styleClasses}
        type={type}
        {...props}
      >
        {children}
      </BaseButton>
    );
  },
);
