import { FC, MouseEvent, PropsWithChildren, ReactElement, ReactNode } from 'react';
import { Placement } from '@floating-ui/react';

import { Icon } from '../Icon';
import { Link } from '../Link';
import { RyeconHelp } from '../ryecons';
import { Tooltip } from '../Tooltip';

export interface HelpIconProps {
  /** A URL to link to on click.  Only use if NOT providing an onClick. Mutually exclusive with tooltipContent */
  linkTo?: string;

  /** A URL to link to on click. Only use if NOT providing a linkTo. Mutually exclusive with tooltipContent */
  onClick?: () => void;

  /** The content to display in the tooltip. Mutually exclusive with linkTo */
  tooltipContent?: ReactNode;

  /** Custom placement for the tooltip */
  tooltipPlacement?: Placement;

  /** Optional classnames for the icon */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;

  /** An id to identify this element */
  id?: string;

  /** An accessible label to distinguish among help icons */
  ariaLabel?: string;
}

export const HelpIcon: FC<HelpIconProps> = ({
  ariaLabel,
  tooltipContent,
  linkTo,
  onClick,
  className,
  tooltipPlacement = 'top-start',
  testId = 'help-icon',
  trackingId = 'help-icon',
  id = 'help-icon',
}): ReactElement => {
  const tooltipIcon = (
    <Icon
      ryecon={RyeconHelp}
      size="xs"
      className="text-fgDecorative inline-block"
      alt={ariaLabel ?? 'help'}
    />
  );

  return (
    <HelpIconComponent
      className={className}
      data-testid={testId}
      data-trackingid={trackingId}
      id={id}
      onClick={onClick}
      // {...withOnClickProps}
    >
      {onClick && !tooltipContent && !linkTo && tooltipIcon}
      {tooltipContent && !linkTo && (
        <Tooltip content={tooltipContent} placement={tooltipPlacement}>
          {tooltipIcon}
        </Tooltip>
      )}
      {linkTo && !tooltipContent && (
        <Link to={linkTo} isInternal={false} shouldOpenNewTab>
          {tooltipIcon}
        </Link>
      )}
      {linkTo && tooltipContent && (
        <Tooltip
          childrenAreInteractive
          content={tooltipContent}
          placement={tooltipPlacement}
        >
          <Link to={linkTo} isInternal={false} shouldOpenNewTab>
            {tooltipIcon}
          </Link>
        </Tooltip>
      )}
    </HelpIconComponent>
  );
};

const HelpIconComponent: FC<PropsWithChildren<HelpIconProps>> = ({
  children,
  onClick,
  ...others
}) =>
  onClick ? (
    // If helpIcon is passed an onClick function, let's use a button
    <button
      {...others}
      onClick={(e: MouseEvent<HTMLButtonElement>) => {
        e.preventDefault();
        onClick();
      }}
    >
      {children}
    </button>
  ) : (
    // otherwise we will use a div
    <div {...others}>{children}</div>
  );
