import { ButtonVariant } from './BaseButton.internal';

export type ButtonStyleType =
  | 'primary'
  | 'secondary'
  | 'tertiary'
  | 'brand'
  | 'success'
  | 'error'
  | 'link' // @deprecated use 'tertiary' instead
  | 'rounded' // @deprecated do not round buttons
  | 'active' // @deprecated use 'primary' + disabled for correct styles - SURF-1568
  | 'none'
  | 'pagination'
  | 'pagination-active'
  | 'icon-button';

interface ButtonClassNameArgs {
  isDisabled?: boolean;
  isRounded?: boolean;
  type?: ButtonStyleType;
  variant?: ButtonVariant;
}

export const buttonClassNames = ({
  isDisabled,
  isRounded,
  type = 'primary',
  variant,
}: ButtonClassNameArgs) => ({
  // Main styles
  'text-fgInverse border-transparent bg-bgInverse hover:bg-bgInverseHover active:bg-bgInverseActive focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain shadow-brand-rest hover:shadow-brand-hover active:shadow-none':
    (type === 'rounded' || type === 'primary') && !isDisabled,

  // Alt styles
  'text-fgMain bg-bgMain border-1 border-borderMain hover:border-borderMainHover hover:bg-bgMainHover active:bg-bgMainActive focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain shadow-rest hover:shadow-hover  active:shadow-none':
    (type === 'secondary' || variant === 'group') && !isDisabled,

  // Tertiary styles
  'text-fgMain bg-transparent border-transparent hover:bg-bgMainHover hover:text-fgAltHover active:text-fgAltActive active:bg-bgMainActive focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain':
    type === 'tertiary' && !isDisabled,

  // Rounded styles
  'rounded-full': isRounded || type === 'rounded',

  // Success styles
  'text-fgWhite bg-bgSuccess border-transparent hover:border-borderSuccessHover hover:bg-bgSuccessHover active:border-borderSuccessActive active:bg-bgSuccessActive focus-visible:ring-borderSuccess focus-visible:ring-offset-bgMain':
    type === 'success' && !isDisabled,
  'text-fgWhite bg-bgSuccess border-transparent': type === 'success' && isDisabled,

  // Brand styles
  'text-fgBlack bg-origin-border border-transparent bg-gradient-to-br from-transparent to-[#FE6703]/60 transition-all bg-brandYellow hover:bg-gradient-to-tr hover:to-transparent hover:from-[#FE6703] hover:to-brandYellow active:bg-brandOrange active:from-brandOrange active:to-brandOrange focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain shadow-brand-rest hover:shadow-brand-hover active:shadow-none':
    (type === 'rounded' || type === 'brand') && !isDisabled,
  /**
   * @deprecated
   * should use 'primary' type + disabled to get correct styles - SURF-1568
   */
  'text-fgWhite bg-bgBrand border-transparent shadow-rest': type === 'active',

  // Error styles
  'text-fgWhite border-transparent bg-bgDanger hover:bg-bgDangerHover active:bg-bgDangerActive focus-visible:ring-focusDanger focus-visible:ring-offset-bgMain shadow-danger-rest hover:shadow-danger-hover active:shadow-none':
    type === 'error' && !isDisabled,

  // Link styles
  'text-fgBrand border-transparent hover:bg-bgMainHover hover:text-fgBrandHover active:bg-bgMainActive active:text-fgBrandActive focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain focus-visible:shadow-none':
    type === 'link' && !isDisabled,

  'cursor-not-allowed shadow-none': isDisabled,

  // General disabled styles
  'bg-bgDisabled border-borderDisabled text-fgDisabled placeholder-fgDecorative':
    type !== 'link' &&
    type !== 'success' &&
    type !== 'active' &&
    type !== 'tertiary' &&
    isDisabled,
  'text-fgDisabled border-transparent':
    (type === 'link' && isDisabled) || (type === 'tertiary' && isDisabled),

  // icon button
  'text-fgMain hover:text-fgAltHover active:text-fgAltActive border-transparent p-[0px]':
    type === 'icon-button',
});
