import { useId } from 'react';
import cx from 'classnames';

import { RegisterOptions, useFormContext } from '@/externals/react-hook-form';
import { useSkeletonContext } from '../../../context';
import { BaseInputProps } from '../../../globalTypes';
import { get } from '../../../utils';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { Field } from '../Field/Field';
import { FormFieldMessage } from '../FormFieldMessage/FormFieldMessage';

interface CustomInputProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  name: string;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** The display value */
  defaultValue?: string;

  /** Description Text */
  description?: React.ReactNode;

  /** react-hook-form register config, accepts any options react-hook-form's register can accept. */
  formConfig?: RegisterOptions;

  /** Class names for the textarea element */
  textareaClassName?: string;

  /** Custom onChange handler. Allows for extra handling past the default react-hook-form usage */
  onChange?: (e: React.ChangeEvent<HTMLTextAreaElement>) => void;
}

export type TextareaProps = BaseInputProps & CustomInputProps;

export const Textarea: React.FC<TextareaProps> = ({
  name,
  label,
  labelIsHidden = false,
  tooltip,
  helpLink,
  onHelpClick,
  description,
  defaultValue,
  className,
  textareaClassName,
  error,
  isOptional = false,
  isEdit = false,
  isDisabled = false,
  children,
  formConfig,
  skeleton = false,
  testId = 'textarea',
  trackingId = 'textarea',
  onChange,
  value,
  ...props
}) => {
  const formMethods = useFormContext();
  const isControlled = value !== undefined && onChange !== undefined;
  const registration = isControlled ? {} : formMethods?.register(name, formConfig);
  const errors = formMethods?.formState?.errors ?? {};
  const errorMessage = get(errors, name)?.message ?? error;

  const formSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || formSkeleton;

  const textareaClasses = cx(
    'block w-full rounded-md text-sm',
    {
      'focus:border-borderBrand focus:ring-focusBrand bg-bgMain border-borderMain text-fgMain placeholder-fgDecorative shadow-rest ':
        !errorMessage && !isDisabled,
      'border-borderDanger placeholder-fgDecorative bg-bgMain focus:border-borderDanger focus:ring-focusDanger shadow-rest focus:outline-none':
        !!errorMessage && !isDisabled,
      'border-borderDisabled bg-bgDisabled text-fgDisabled placeholder-fgDisabled cursor-not-allowed shadow-none ':
        isDisabled,
    },
    textareaClassName,
  );

  const uniqueId = useId();
  const labelId = `textarea-${uniqueId}`;

  return (
    <Field
      label={label}
      labelIsHidden={labelIsHidden}
      tooltip={tooltip}
      helpLink={helpLink}
      onHelpClick={onHelpClick}
      className={className}
      isDisabled={isDisabled}
      isEdit={isEdit}
      isOptional={isOptional}
      testId={`${testId}-wrapper`}
      trackingId={`${trackingId}-wrapper`}
      labelFor={labelId}
    >
      {shouldSkeleton && (
        <LoadingBlock loaderClassName="min-h-input w-full rounded-md" />
      )}
      {!shouldSkeleton && (
        <>
          {!isEdit && (
            <div className="min-h-textarea bg-bgDisabled text-fgMain font-body-sm rounded-md px-3 py-2">
              {children || defaultValue}
            </div>
          )}
          {isEdit && (
            <>
              <div>
                <textarea
                  {...props}
                  id={labelId}
                  defaultValue={!formMethods ? defaultValue : undefined}
                  className={textareaClasses}
                  data-testid={testId}
                  data-tracking-id={trackingId}
                  aria-describedby={
                    errorMessage ? `field-${name}-error` : `field-${name}-description`
                  }
                  disabled={isDisabled}
                  value={value}
                  onChange={onChange}
                  {...(registration ?? {})}
                ></textarea>
              </div>
            </>
          )}
        </>
      )}
      <FormFieldMessage
        name={name}
        description={description}
        errorMessage={errorMessage}
        isEdit={isEdit}
        testId={testId}
        trackingId={trackingId}
      />
    </Field>
  );
};
