import { getBaseIconClasses, getWrapperClasses } from '../helpers.internal';
import { RyeconIconProps } from '../types';

export const RyeconIcon = ({
  ryecon: RyeconComponent,
  alt,
  testId,
  trackingId,
  className,
  size = 'sm',
  iconColor,
  animate,
}: RyeconIconProps) => {
  const baseIconClasses = getBaseIconClasses(iconColor, animate);
  const wrapperClasses = getWrapperClasses(size, className);

  return (
    <span className={wrapperClasses} data-testid={testId} data-trackingid={trackingId}>
      <RyeconComponent
        aria-label={alt}
        role={alt ? 'img' : 'presentation'}
        className={baseIconClasses}
      />
    </span>
  );
};
