import { DropdownOption } from '../../../DropdownOptions';
import { FormSchema, SchemaField } from '..';

type FormValue = string | number | DropdownOption | boolean | null;

const nullOnEmpty = (value: any, type: string) => {
  const isInvalidNumber = type === 'number' && isNaN(value);

  return value === '' || isInvalidNumber || value === undefined ? null : value;
};

// A single form may contain multiple flattened schemas and custom fields
// (for example, the project setup form includes schemas for both connections and credentials)
// This function parses an individual schema back out of the flattened object.
export const getSchemaFromFormValues = (
  schema: FormSchema,
  formValues: Record<string, FormValue>,
  nullEmptyString = false, // Some optional fields need to be null rather than an empty string when sent to the backend
): FormSchema => {
  const schemaKeys = Object.keys(schema.fields);

  const schemaValues = schemaKeys.reduce(
    (parsedSchema, schemaKey) => {
      parsedSchema[schemaKey] = formValues[schemaKey];
      return parsedSchema;
    },
    {} as Record<string, FormValue>,
  );

  return buildValueSchema(schema, schemaValues, nullEmptyString);
};

const buildValueSchema = (
  schema: FormSchema,
  values: Record<string, FormValue>,
  nullEmptyString = false,
): FormSchema => {
  const valueSchema = {
    fields: { ...(schema?.fields ?? {}) },
    field_order: [...(schema?.field_order ?? Object.keys(schema?.fields ?? {}))],
  };
  return Object.entries(schema?.fields ?? {}).reduce(
    (newSchema: FormSchema, [fieldKey, field]: [string, SchemaField]) => {
      if (field.metadata.field_type === 'number') {
        const value = values[fieldKey] ?? field.value;
        const nullableValue = nullEmptyString
          ? nullOnEmpty(value, field.metadata.field_type)
          : value;
        const valueToSave = nullableValue === null ? null : Number(nullableValue);

        newSchema.fields[fieldKey] = {
          ...newSchema.fields[fieldKey],
          value: valueToSave,
        };
      } else if (field.metadata.field_type === 'select') {
        const value =
          (values[fieldKey] as DropdownOption)?.value ??
          values[fieldKey] ??
          field.value;

        newSchema.fields[fieldKey] = {
          ...newSchema.fields[fieldKey],
          value: nullEmptyString
            ? nullOnEmpty(value, field.metadata.field_type)
            : value,
        };
      } else {
        const value = values[fieldKey] ?? field.value;
        newSchema.fields[fieldKey] = {
          ...newSchema.fields[fieldKey],
          value: nullEmptyString
            ? nullOnEmpty(value, field.metadata.field_type)
            : value,
        };
      }

      return newSchema;
    },
    valueSchema,
  );
};

// Used for passing default values from a schema to useZodForm
// Has special handling for null number values
export const getDefaultValuesFromSchema = (schema: FormSchema): Record<string, any> => {
  return Object.entries(schema?.fields ?? {}).reduce(
    (values: Record<string, any>, [fieldKey, fieldValue]: [string, SchemaField]) => {
      let value = fieldValue.value;

      // When setting default values, we want to convert number field nulls to empty
      // strings so that optional number fields behave as expected
      if (fieldValue.metadata.field_type === 'number' && value === null) {
        value = '';
      }

      values[fieldKey] = value;
      return values;
    },
    {},
  );
};

// Used for converting a schema to a flat object for saving legacy schemas
// to the backend. Differs from the above in the way it handles null values for numbers
export const getApiValuesFromSchema = (schema: FormSchema): Record<string, any> => {
  return Object.entries(schema?.fields ?? {}).reduce(
    (values: Record<string, any>, [fieldKey, fieldValue]: [string, SchemaField]) => {
      values[fieldKey] = fieldValue.value;
      return values;
    },
    {},
  );
};

// Filter a schema to include only specific fields
export const getFilteredSchema = (schema: FormSchema, fields: string[]): FormSchema => {
  const filteredSchema: FormSchema = {
    fields: {},
    field_order: [],
  };
  for (const [key, val] of Object.entries(schema.fields)) {
    if (fields.includes(key)) {
      filteredSchema.fields[key] = val;
      filteredSchema.field_order = [...filteredSchema.field_order!, key];
    }
  }
  return filteredSchema;
};
