import React from 'react';
import { ScaleOrdinal, scaleOrdinal } from 'd3';

import { ChartProps, InteractionItem } from '../Chart/Chart';
import { ColorSet } from '../Chart/Color';
import { PlotProps } from '../Plot/Plot';
import { Accessor, Shape } from '../types';

interface ChartExtras {
  plotHeight: number;
  plotWidth: number;
  svgWidth: number;
  svgHeight: number;
  interactionItem: InteractionItem<any> | null;
  cancelInteraction(): void;
  setInteractionItem: React.Dispatch<React.SetStateAction<InteractionItem<any> | null>>;
  handleLeave: any;
  getColor?: (subPlotIndex?: number) => ColorSet;
  colors: ColorSet[];
  focusClassNames?: string;
  unfocusClassNames?: string;
}

export interface PlotInfo
  extends Omit<PlotProps, 'children' | 'xAccessor' | 'yAccessor'> {
  id: string;
  xAccessor: Accessor<any, any>;
  yAccessor: Accessor<any, any>;
  getColor?: (subPlotIndex?: number) => ColorSet;
  shape: Shape | null;
}

export interface PlotRegistry {
  [key: string]: PlotInfo;
}

export type ChartMeta = ChartProps & ChartExtras;

export interface ChartContext {
  chartMeta: ChartMeta | null;
  setChartMeta: React.Dispatch<React.SetStateAction<ChartMeta | null>>;
  plots: PlotRegistry;
  registerPlot(plot: PlotInfo): void;
  unregisterPlot(plotId: string): void;
  colorScale: ScaleOrdinal<string, ColorSet>;
}

const ChartContextContext = React.createContext<ChartContext>({
  chartMeta: null,
  setChartMeta: () => {},
  plots: {},
  registerPlot: () => {},
  unregisterPlot: () => {},
  colorScale: scaleOrdinal<string, ColorSet>(),
});

export interface ChartContextProviderProps {
  children: React.ReactNode;
  chartMeta: ChartContext['chartMeta'];
}

const SINGLE_PLOT_DEFAULT_INDEX = 0;

/** @deprecated */
export function ChartContextProvider({
  children,
  chartMeta,
}: ChartContextProviderProps) {
  const [, setChartMeta] = React.useState<ChartContext['chartMeta']>(chartMeta);
  const [plots, setPlots] = React.useState<PlotRegistry>({});

  const expandedPlotIds = Object.keys(plots ?? {}).flatMap((pId) => {
    const name = plots?.[pId]?.name;
    return name instanceof Array
      ? name.map((_: string, idx: number) => pId + idx)
      : pId + SINGLE_PLOT_DEFAULT_INDEX;
  });

  const colorScale: ScaleOrdinal<string, ColorSet> = scaleOrdinal<string, ColorSet>()
    .domain(expandedPlotIds)
    .range(chartMeta?.colors ?? []);

  const registerPlot = React.useCallback(
    (plot: PlotInfo) => {
      setPlots((_plots) => {
        const newPlots = { ..._plots };
        newPlots[plot.id] = plot;
        return newPlots;
      });
    },
    [setPlots],
  );

  const unregisterPlot = React.useCallback(
    (plotId: string) => {
      setPlots((_plots) => {
        const newPlots = { ..._plots };
        delete newPlots[plotId];
        return newPlots;
      });
    },
    [setPlots],
  );

  const value = React.useMemo(
    () => ({
      setChartMeta,
      chartMeta,
      plots,
      registerPlot,
      unregisterPlot,
      colorScale,
    }),
    [setChartMeta, chartMeta, plots, registerPlot, unregisterPlot, colorScale],
  );

  return (
    <ChartContextContext.Provider value={value}>
      {children}
    </ChartContextContext.Provider>
  );
}

/** @deprecated */
export function useChartContext(): ChartContext | undefined {
  const context = React.useContext(ChartContextContext);

  return context;
}
