import { PropsWithChildren, useMemo } from 'react';

import { ActionList } from '../../Actions';
import { BadgeProps } from '../../Badge';
import { Breadcrumb } from '../../Breadcrumbs';
import { IconTextProps } from '../../elements/IconText';
import { Notification } from '../../NotificationBanner';
import { ProductPageHeader } from '../../ProductPageHeader';
import { RyeconChatResponse } from '../../ryecons';
import { type TabProps } from '../../tabs/FloatingTabs';

export interface BasicLayoutProps {
  /** The Header of the page **/
  title: string;

  /** The Subtitle of the page **/
  subtitle?: string;

  /** Layout width control - standard (default), narrow, or full */
  layoutWidth?: 'standard' | 'narrow' | 'full';

  headerBadge?: BadgeProps;

  /** An array of actions for the page header */
  actions?: ActionList;

  /** A flag to indicate whether to show a feedback button - usually for pendo */
  feedbackButton?: boolean;

  /** A list of breadcrumbs to display **/
  breadcrumbs?: Breadcrumb[];

  /** A status badge to display on the page header */
  badge?: { text: string; type: string };

  /** Error notification to display at the top of the page */
  errorNotification?: Notification;

  /** A callback to be triggered when the error banner close button is clicked */
  onErrorDismiss?: () => void;

  /** A boolean to determine whether the page is loading */
  isLoading?: boolean;

  /** Navigation tabs to display below the header */
  tabs?: TabProps[];

  /** Flag to make the header sticky */
  sticky?: boolean;

  /** Metadata items to display below the title using IconText components */
  metadata?: Omit<IconTextProps, 'size'>[];
}

export const BasicLayout: React.FC<PropsWithChildren<BasicLayoutProps>> = ({
  children,
  title,
  subtitle,
  layoutWidth = 'standard',
  headerBadge,
  actions,
  breadcrumbs,
  feedbackButton,
  errorNotification,
  onErrorDismiss,
  isLoading = false,
  tabs,
  sticky,
  metadata,
}): React.ReactElement => {
  const _actions = useMemo(
    () =>
      feedbackButton
        ? ([
            {
              text: 'Leave feedback',
              buttonProps: {
                type: 'link',
                ryecon: RyeconChatResponse,
                testId: 'leave-feedback',
                trackingId: 'leave-feedback',
              },
            },
            ...(actions ?? []),
          ] as ActionList)
        : actions,
    [actions, feedbackButton],
  );

  const layoutClasses = {
    standard: 'max-w-page',
    narrow: 'max-w-narrow-page',
    full: 'max-w-full',
  }[layoutWidth];

  return (
    <>
      <div className="relative h-full">
        <ProductPageHeader
          title={title}
          subtitle={subtitle}
          badge={headerBadge}
          actions={_actions}
          breadcrumbs={breadcrumbs}
          isLoading={isLoading}
          errorNotification={errorNotification}
          onErrorDismiss={onErrorDismiss}
          tabs={tabs}
          sticky={sticky}
          metadata={metadata}
        />
        <div className={`p-4 sm:p-4 md:p-6 lg:p-8`}>
          <div className={`mx-2 mx-auto space-y-8 ${layoutClasses}`}>{children}</div>
        </div>
      </div>
    </>
  );
};
