import { useEffect, useMemo, useRef } from 'react';
import cx from 'classnames';

import { Button } from '../Button';
import { Icon } from '../Icon/Icon';
import { IconProps } from '../Icon/types';
import {
  RyeconCheckmarkOutline,
  RyeconClose,
  RyeconErrorOutline,
  RyeconInfoOutline,
  RyeconLogoDbtBit,
  RyeconWarningOutline,
} from '../ryecons';
import { Sizes } from '../types';

export enum ToastVariant {
  Default = 'default',
  Success = 'success',
  Warn = 'warn',
  Error = 'error',
  Info = 'info',
}

export interface ToastAction {
  /** The text to display on the action button */
  text: string;
  /** The onClick handler for the action button */
  onClick?: () => void;
  /** Optional aria label for the action button */
  ariaLabel?: string;
  /** Optional test id for the action button */
  testId?: string;
}

export interface ToastProps {
  /** Title text to display in notification */
  title: string;

  /** URL notification links to on user click. Optional. */
  url?: string;

  /** Allows developers to override the icon used in a given notification */
  icon?: React.ReactElement<IconProps>;

  /** A function to trigger when the user clicks the 'X' button */
  onClickClose?: () => void;

  /** More detailed information to render in the notification body */
  description?: string;

  /** Styles and icon are derived from this optional prop */
  variant?: ToastVariant;

  /** Whether to show the dismiss button. Defaults to true. */
  dismissible?: boolean;

  /** Duration in milliseconds before auto-dismiss. Only applies when dismissible is false. */
  duration?: number;

  /** Optional action button configuration */
  action?: ToastAction;
}

// TODO: Fix a11y issues: SURF-908
export const Toast: React.FC<ToastProps> = ({
  title,
  description,
  icon,
  onClickClose,
  url,
  variant = ToastVariant.Default,
  dismissible = true,
  duration,
  action,
}): React.ReactElement => {
  const timeoutRef = useRef<number>(-1);
  const isPaused = useRef(false);

  useEffect(() => {
    if (!dismissible && onClickClose) {
      const startTime = Date.now();
      const tick = () => {
        if (!isPaused.current) {
          const elapsed = Date.now() - startTime;
          const remaining = (duration || 5000) - elapsed;

          if (remaining <= 0) {
            onClickClose();
            return;
          }
        }
        timeoutRef.current = window.requestAnimationFrame(tick);
      };

      timeoutRef.current = window.requestAnimationFrame(tick);

      return () => {
        if (timeoutRef.current) {
          window.cancelAnimationFrame(timeoutRef.current);
        }
      };
    }
  }, [dismissible, duration, onClickClose]);

  const notificationClasses = cx({
    'border-borderMuted bg-bgMain border': variant === ToastVariant.Default,
    'border-borderSuccessMuted bg-bgSuccessMuted border':
      variant === ToastVariant.Success,
    'border-borderWarningMuted bg-bgWarningMuted border': variant === ToastVariant.Warn,
    'border-borderDangerMuted bg-bgDangerMuted border': variant === ToastVariant.Error,
    'border-borderInfoMuted bg-bgInfoMuted border': variant === ToastVariant.Info,
  });

  const renderedIcon = useMemo(() => {
    let _alt: string | undefined;
    let _variantIcon = null;

    switch (variant) {
      case ToastVariant.Default:
        _variantIcon = RyeconLogoDbtBit;
        break;
      case ToastVariant.Error:
        _alt = 'error';
        _variantIcon = RyeconErrorOutline;
        break;
      case ToastVariant.Warn:
        _alt = 'warning';
        _variantIcon = RyeconWarningOutline;
        break;
      case ToastVariant.Info:
        _alt = 'information';
        _variantIcon = RyeconInfoOutline;
        break;
      case ToastVariant.Success:
        _alt = 'success';
        _variantIcon = RyeconCheckmarkOutline;
        break;
    }

    return icon ? (
      icon
    ) : (
      <Icon
        alt={_alt}
        className={cx({
          'text-fgAlt': variant === ToastVariant.Default,
          'text-fgSuccess': variant === ToastVariant.Success,
          'text-fgWarning': variant === ToastVariant.Warn,
          'text-fgDanger': variant === ToastVariant.Error,
          'text-fgInfo': variant === ToastVariant.Info,
        })}
        ryecon={_variantIcon}
        size="md"
        testId={`toast--${variant}-icon`}
      />
    );
  }, [icon, variant]);

  const handleContentClick = () => {
    if (url) {
      window.location.href = url;
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      handleContentClick();
    }
  };

  return (
    <div className="w-full max-w-sm" data-testid="toast--wrapper">
      <div
        className={cx(
          notificationClasses,
          'shadow-hover w-full overflow-hidden rounded-lg',
        )}
        onMouseEnter={() => {
          isPaused.current = true;
        }}
        onMouseLeave={() => {
          isPaused.current = false;
        }}
      >
        <div className="flex justify-between gap-2 p-2">
          <div
            className={cx('flex flex-1 items-start gap-2', url && 'cursor-pointer')}
            onClick={handleContentClick}
            onKeyDown={handleKeyDown}
            role={url ? 'link' : undefined}
            tabIndex={url ? 0 : undefined}
          >
            {variant === ToastVariant.Default ? null : (
              <div className="flex pt-0.5" aria-hidden="true">
                {renderedIcon}
              </div>
            )}
            <div className="w-0 flex-1">
              <p className="text-fgMain font-body font-medium">{title}</p>
              {description && <p className="text-fgMain font-caption">{description}</p>}
            </div>
          </div>
          <div className="flex flex-shrink-0 items-start gap-2">
            {action && (
              <Button
                type="secondary"
                size={Sizes.xs}
                onClick={(e) => {
                  e.stopPropagation();
                  action.onClick?.();
                }}
                text={action.text}
                ariaLabel={action.ariaLabel}
                testId={action.testId || 'toast--action-button'}
              />
            )}
            {dismissible && onClickClose && (
              <Button
                type="tertiary"
                size={Sizes.xs}
                className="hover:bg-bgMainHoverTinted"
                ryecon={RyeconClose}
                testId="toast--close-icon"
                onClick={(e) => {
                  e.stopPropagation();
                  onClickClose();
                }}
              />
            )}
          </div>
        </div>
      </div>
    </div>
  );
};
