import { byTestId } from '../../../utils';

/**
 * Pull the transform attribute from an element
 *
 * @deprecated
 * @param el element with the transform attribute
 * @returns transform attribute - translate(x, y)
 */
export const getTransformAttribute = (
  el: JQuery<HTMLElement>,
): Cypress.Chainable<string | undefined> => {
  return cy.wrap(el).invoke('attr', 'transform');
};

/**
 * Pull the amount of translation from the transform attribute in x or y
 *
 * @deprecated
 * @param transform transform attribute that contains translate(x, y)
 * @param isX are we looking for x or y of the translation
 * @returns value of the translation in x or y
 */
export const getTransformValue = (
  transform: string | undefined,
  isX: boolean,
): number => {
  if (transform) {
    const inCoordinate = transform.match(/\((.*?)\)/);
    if (inCoordinate) {
      const location: number = Number(inCoordinate[1].split(',')[isX ? 1 : 0]);
      return location;
    }
  }
  return -1;
};

/**
 * Calculate the relative x value compared to a reference x value.
 * If x axis scale does not start at 0 startScale is required
 *
 * @deprecated
 * @param x value of object being compared
 * @param referenceX y value of the reference
 * @param xStartScale where your x axis scale starts
 * @returns
 */
export const calculateRelativeSizeX = (
  x: number,
  referenceX: number,
  xStartScale: number = 0,
) => (x - xStartScale) / (referenceX - xStartScale);

/**
 * Calculate the relative value compared to a reference value.
 * If y axis scale does not start at 0 startScale is required
 *
 * @deprecated
 * @param y y value of object being compared
 * @param referenceY y value of the reference
 * @param endScale where your y axis scale ends
 * @returns
 */
export const calculateRelativeSizeY = (
  y: number,
  referenceY: number,
  yEndScale: number = 0,
) => (y - yEndScale) / (referenceY - yEndScale);

// Tooltip

/**
 * Mouse over an interaction layer of a chart to show it's corresponding tooltip
 *
 * @deprecated
 * @param interactionLayerTestId id of the interaction layer
 * @param index if multiple interaction layers exist, which one to interact with
 */
export const showTooltip = (
  interactionLayerTestId: string,
  index: number = 0,
  force: boolean = false,
) => {
  cy.get(byTestId(interactionLayerTestId)).eq(index).trigger('mouseover', { force });
};

/**
 * Mouse away from an interaction layer of a chart to hide it's corresponding tooltip
 *
 * @deprecated
 * @param interactionLayerTestId id of the interaction layer
 * @param index if multiple interaction layers exist, which one to interact with
 */
export const hideTooltip = (
  interactionLayerTestId: string,
  index: number = 0,
  position: string = 'center',
  force: boolean = false,
) => {
  cy.get(byTestId(interactionLayerTestId))
    .eq(index)
    .trigger('mouseout', { position, force });
};

/**
 * Get the tooltip element
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @returns tooltip element
 */
export const getTooltip = (chartTestId: string) => {
  return cy.get(byTestId(`tooltip-${chartTestId}`));
};

// Axis

/**
 * Get the testId of the axis
 *
 * @deprecated
 * @param isXAxis is the axis being tested on the x plane
 * @param axisType what type of axis is it (category, linear, time, etc)
 * @returns testid of the axis
 */
export const getAxisTestId = (isXAxis: boolean, axisType: string) => {
  return `${isXAxis ? 'x' : 'y'}-${axisType}-axis`;
};

/**
 * Check that the category axis is rendered correctly
 *
 * @deprecated
 * @param isXAxis is the axis being tested on the x plane
 * @param axisLabel axis name if set
 * @param labels list of labels that should be on the axis
 */
export const isCategoryAxis = (
  isXAxis: boolean,
  axisLabel: string,
  labels: string[],
) => {
  const axisTestId = getAxisTestId(isXAxis, 'category');
  if (axisLabel) cy.get(byTestId(axisTestId)).contains(axisLabel);
  labels.forEach((label) => {
    cy.get(byTestId(axisTestId)).contains(label);
  });
};

/**
 * Check that the linear axis is rendered correctly
 *
 * @deprecated
 * @param isXAxis is the axis being tested on the x plane
 * @param axisLabel axis name if set
 * @param min minimum value of the linear axis that is shown on the axis
 * @param max maximum value of the linear axis that is shown on the axis
 */
export const isLinearAxis = (
  isXAxis: boolean,
  axisLabel: string,
  min: number | string,
  max: number | string,
) => {
  const axisTestId = getAxisTestId(isXAxis, 'linear');
  if (axisLabel) cy.get(byTestId(axisTestId)).contains(axisLabel);
  cy.get(byTestId(axisTestId)).children('g').first().should('contain', min);
  cy.get(byTestId(axisTestId)).children('g').last().should('contain', max);
};

/**
 * Get the location (x or y) of each tick in the axis
 *
 * @deprecated
 * @param axisTestId testId of the <Axis/> component
 * @param isHorizontal is the axis for the x plane
 * @returns list of tick locations (x or y) along a single axis
 */
export const getVisibleTickLocations = (
  axisTestId: string,
  isHorizontal: boolean = false,
) => {
  const tickLocations: number[] = [];

  cy.get(byTestId(axisTestId))
    .find('.tick')
    .each((tick) => {
      getTransformAttribute(tick).then((transform) =>
        tickLocations.push(getTransformValue(transform, isHorizontal)),
      );
    });

  return tickLocations;
};

