// Bar

/**
 *
 * Compare the relative size of all bars in a bar chart to determine whether
 * the bars are sized correctly to the data.
 * A reference bar is required to compare the relative size of all
 * other bars, this is set using an index relative to how the bars are rendered
 * left to right or bottom to top depending on the bar chart orientation.
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @param relativeSizesToReference list of relative sizes
 * (compared to the bar at referenceIndex) for each bar
 * ie [1, 3, 2, 4] or [1/2, 1/5, 65/88, 2]
 * @param referenceIndex index reference to the bar that is [1] in relativeSizesToReference
 * * ie 0
 * @param isHorizontal is the bar chart horizontal
 */
export const compareRelativeBar = (
  chartTestId: string,
  relativeSizesToReference: number[],
  referenceIndex: number = 0,
  isHorizontal: boolean = false,
) => {
  const measure = isHorizontal ? 'width' : 'height';
  relativeSizesToReference.forEach((relativeSize, idx) => {
    cy.get(byTestId(`${chartTestId}-bar-${referenceIndex}`))
      .invoke(measure)
      .then((width) => {
        cy.get(byTestId(`${chartTestId}-bar-${idx}`))
          .invoke(measure)
          .then((referenceWidth) => (referenceWidth ?? 0).toFixed(2))
          .should('eq', ((width ?? 0) * relativeSize).toFixed(2));
      });
  });
};

/**
 * Get the location (x or y) of each bar in the bar chart along the categorical axis.
 *
 * @deprecated
 * @param plotTestId testId of the <Plot/> component
 * @param isHorizontal is the bar chart horizontal
 * @returns list of bar locations (x or y)
 */
export const getBarLocations = (plotTestId: string, isHorizontal: boolean = false) => {
  const barLocations: number[] = [];

  cy.get(byTestId(plotTestId))
    .children('rect')
    .each((bar) => {
      cy.wrap(bar)
        .invoke('attr', isHorizontal ? 'y' : 'x')
        .then((size) => {
          if (size) barLocations.push(Number(size));
        });
    });

  return barLocations;
};

/**
 * Check whether the tick and bars have the same distance between each other
 * Allows us to check whether the data is matched to the correct bar
 *
 * If the chart is not set up correctly this test will fail due to the bars being all set at 0
 *
 * @deprecated
 * @param tickLocations list of tick locations (x or y) along a single axis
 * @param barLocations list of bar locations (x or y) along a single axis
 */
export const areTicksAndBarsEvenlySpaced = (
  tickLocations: number[],
  barLocations: number[],
) => {
  cy.then(() => {
    tickLocations.forEach((tickLocation, idx) => {
      const barLocation = barLocations[idx];

      // Ignore if there is no previous tick since we can't compare
      const tickDistanceFromLast = tickLocations?.[idx - 1]
        ? tickLocation - tickLocations?.[idx - 1]
        : 0;
      const barDistanceFromLast = barLocations?.[idx - 1]
        ? barLocation - (barLocations?.[idx - 1] ?? 0)
        : 0;
      // Only the first tick should have 0 distance from the previous tick
      if (idx !== 0) {
        cy.wrap(tickDistanceFromLast).should('not.eq', 0);
      }
      cy.wrap(tickDistanceFromLast.toFixed(2)).should(
        'eq',
        barDistanceFromLast.toFixed(2),
      );
    });
  });
};

/**
 * Compare the relative size of all bars in a complex bar chart to determine whether
 * the bars are sized correctly to the data.
 * A reference bar is required to compare the relative size of all
 * other bars, this is set using an index relative to how the bars are rendered.
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @param barStyleTestId testId of the <Shape/> component that renders the multiple bars (BarGroup, BarStack)
 * @param relativeSizesToReference
 * [[2/3, 1/2], [1, 1/22], [4/21, 5/11]]
 * @param referenceGroupIndex index reference to the group of bars that is [1] in relativeSizesToReference
 * ie 1
 * @param referenceIndex index reference to the bar that is [1] in relativeSizesToReference
 * ie 0
 * @param isHorizontal is the bar chart horizontal
 */
export const compareRelativeBarValues = (
  chartTestId: string,
  barStyleTestId: string,
  relativeSizesToReference: number[][],
  referenceGroupIndex: number = 0,
  referenceIndex: number = 0,
  isHorizontal: boolean = false,
) => {
  const measure = isHorizontal ? 'width' : 'height';
  relativeSizesToReference.forEach((group, groupIdx) => {
    group.forEach((relativeSize, barIdx) => {
      cy.get(
        byTestId(
          `${chartTestId}-${barStyleTestId}-group-${referenceGroupIndex}-bar-${referenceIndex}`,
        ),
      )
        .invoke(measure)
        .then((width) => {
          cy.get(
            byTestId(
              `${chartTestId}-${barStyleTestId}-group-${groupIdx}-bar-${barIdx}`,
            ),
          )
            .invoke(measure)
            .then((compareWidth) => {
              cy.wrap(compareWidth?.toFixed(2)).should(
                'eq',
                ((width ?? 0) * relativeSize).toFixed(2),
              );
            });
        });
    });
  });
};

/**
 * Test whether the bars in a group/stack bar chart are colored correctly.
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @param barStyleTestId testId of the <Shape/> component that renders the multiple bars (BarGroup, BarStack)TestId
 * @param colors ordered list of color classnames that we expect the bars to be colored
 */
export const isBarsColored = (
  chartTestId: string,
  barStyleTestId: string,
  colors: string[],
) => {
  cy.get(byTestId(chartTestId))
    .children('g')
    .each((_, groupIdx) => {
      colors.forEach((color, idx) => {
        isBarInBarGroupColored(
          `${chartTestId}-${barStyleTestId}-group-${groupIdx}-bar-${idx}`,
          color,
        );
      });
    });
};

