// Dot

/**
 * From a list of x positions for the rendered dots, compare the relative position of each dot in the x axis
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @param xPositions list of x axis values for each dot
 * @param referenceIndex index reference to the dot that is not equal to 0 in xPositions
 * @param marginLeft your left margin value
 * @param xScaleStart the start of your linear scale in the x axis
 */
export const compareRelativeDotX = (
  chartTestId: string,
  xPositions: number[],
  referenceIndex: number,
  marginLeft: number,
  xScaleStart: number,
) => {
  xPositions
    .map((v) => calculateRelativeSizeX(v, xPositions[referenceIndex], xScaleStart))
    .forEach((relativeSize, idx) => {
      cy.get(byTestId(`${chartTestId}-dot-${referenceIndex}`))
        .invoke('attr', 'cx')
        .then((referenceWidth) => {
          cy.get(byTestId(`${chartTestId}-dot-${idx}`))
            .invoke('attr', 'cx')
            .then((compareWidth) =>
              ((Number(compareWidth) ?? 0) - marginLeft).toFixed(2),
            )
            .should(
              'eq',
              (((Number(referenceWidth) ?? 0) - marginLeft) * relativeSize).toFixed(2),
            );
        });
    });
};

/**
 * From a list of y positions for the rendered dots, compare the relative position of each dot in the y axis
 *
 * @deprecated
 * @param chartTestId testId of the <Chart/> component
 * @param yPositions list of y axis values for each dot
 * @param referenceIndex index reference to the dot that is not equal to 0 in xPositions
 * @param marginTop your top margin value
 * @param yScaleEnd the end of your linear scale in the y axis
 */
export const compareRelativeDotY = (
  chartTestId: string,
  yPositions: number[],
  referenceIndex: number,
  marginTop: number,
  yScaleEnd: number,
) => {
  yPositions
    .map((v) => calculateRelativeSizeY(v, yPositions[referenceIndex], yScaleEnd))
    .forEach((relativeSize, idx) => {
      cy.get(byTestId(`${chartTestId}-dot-${referenceIndex}`))
        .invoke('attr', 'cy')
        .then((referenceHeight) => {
          cy.get(byTestId(`${chartTestId}-dot-${idx}`))
            .invoke('attr', 'cy')
            .then((compareHeight) =>
              ((Number(compareHeight) ?? 0) - marginTop).toFixed(2),
            )
            .should(
              'eq',
              (((Number(referenceHeight) ?? 0) - marginTop) * relativeSize).toFixed(2),
            );
        });
    });
};
