import cx from 'classnames';

interface LabelProps {
  /** The text to render */
  children: string;
  /** The size of the label */
  size?: 'regular' | 'large';
  /** An optional testId for cypress */
  testId?: string;
  /** class overrides to add to <label> */
  className?: string;
}

const fontSizeClasses = {
  regular: 'font-label',
  large: 'font-label-lg',
};

export const Label = ({
  children,
  size = 'regular',
  testId,
  className = '',
}: LabelProps) => (
  <label
    className={cx(fontSizeClasses[size], 'text-fgAlt', className)}
    data-testid={testId}
  >
    {children}
  </label>
);
