import { PillSubComponentContext } from './context';
import { ListSub } from './subcomponents/List';
import { TextareaSub, type TextareaSubProps } from './subcomponents/Textarea';
import { type Delimiter } from './types';
import { usePillState } from './usePillState';

export type PillTextareaProps = TextareaSubProps & {
  value: string;
  name: string;
  /** optional cb to notify parent of current state */
  onChange?: (fullValue: string) => void;
  delimiter?: Delimiter;
};

export const PillTextarea = ({
  value,
  name,
  isEdit,
  delimiter = ',',
  placeholder = '',
  onChange,
  testId = 'pill-textarea',
  trackingId = 'pill-textarea',
  ...rest
}: PillTextareaProps) => {
  const context = usePillState({ defaultValue: value, delimiter, onChange });

  return (
    <PillSubComponentContext.Provider value={context}>
      <div className="flex flex-col gap-y-4">
        <TextareaSub
          {...rest}
          name={name}
          placeholder={placeholder}
          isEdit={isEdit}
          testId={testId}
          trackingId={trackingId}
        />
        <div className="flex flex-wrap gap-2">
          {isEdit && context.pills.length > 0 && (
            <ListSub
              testId={`${testId}-list`}
              trackingId={`${trackingId}-list`}
              onClickRemove={context.handleRemove}
            />
          )}
        </div>
      </div>
    </PillSubComponentContext.Provider>
  );
};
