import React, {
  type JSX,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { DndProvider } from 'react-dnd';
import { HTML5Backend } from 'react-dnd-html5-backend';
import AutoSizer from 'react-virtualized-auto-sizer';
import { VariableSizeTree as VTree } from 'react-vtree';

import { DEFAULT_ITEM_HEIGHT, FONT_SIZE_TO_HEIGHT_MAP } from './constants';
import {
  DefaultFileTreeItemWrapper,
  FileTreeItemWrapperProps,
} from './DefaultFileTreeItemWrapper';
import { TreeNode } from './TreeNode';
import { treeWalker } from './treeWalker';
import {
  FileTreeItemType,
  InternalFileTreeItemType,
  ItemFontSize,
  MoveFileFn,
  NodeProps,
  type OnFileSelect,
  type OnFolderSelect,
} from './types';
import { getDropPathDefault } from './utils/getDropPathDefault';
import { sortNodes } from './utils/sortNodes';

const defaultTreeNodeChild = React.memo(
  (FileTreeItemProps: FileTreeItemWrapperProps) => (
    <DefaultFileTreeItemWrapper {...FileTreeItemProps} />
  ),
);

export type FileTreeProps = {
  /**
   * Required:
   * The nodes (files and folders) which make up the FileTree.
   */
  items: FileTreeItemType[];
  /**
   * Required:
   * The name of the top level folder of the project which is not included in the FileTreeItemTypes
   */
  rootNodeName: string;
  /**
   * Label for the entire tree
   */
  ariaLabel?: string;
  /**
   * Enable close folder on second click. The **onFolderSelect** and **selectedFolder** are required for this feature to work.
   */
  enableCloseFolderOnSecondClick?: boolean;
  /**
   * Array of relative paths that will show folder's children
   */
  openDirectories?: string[];
  /**
   * The component that will be rendered for each item in the FileTree
   */
  children?: React.MemoExoticComponent<
    (fileTreeItemProps: FileTreeItemWrapperProps) => JSX.Element
  >;
  /**
   * Called on dropping a file or folder on a new location
   */
  onMoveFile?: MoveFileFn;
  /**
   * Turns off drag & drop as well as file actions menu
   */
  isReadOnly?: boolean;
  /**
   * The font size of each tree item. It can be set for each type of item (file, directory, root, and empty)
   */
  itemFontSize?: ItemFontSize;
  /**
   * Determines whether an expand indicator is displayed next to folders when open or closed.
   */
  showExpandButton?: boolean;
  /**
   * Determines whether an expand indicator is displayed next to folders when open or closed when item is hovered.
   */
  showExpandButtonOnHover?: boolean;
  /**
   * Fire when a file is selected. Does not fire for directories.
   */
  onFileSelect?: OnFileSelect;
  /**
   * Fire when a directory is selected. Does not fire for files.
   */
  onFolderSelect?: OnFolderSelect;
  /**
   * Custom sort function for the file tree where it's passed the filesystem sort key for each node
   *
   * The sort key is used to ensure files and directories are sorted in the correct order:
   *
   * 1. Directories before files
   * 2. Root is always first
   * 3. Same rules apply for each subfolder
   *
   * To achieve this order quickly, we create a sort key that enforces by appending a prefix
   *  to files and directories, which allow us to sort the list lexographically
   *
   */
  onSort?: (a: string, b: string) => number;
  /**
   * The currently selected file
   */
  selectedFile?: string;
  /**
   * The currently selected folder
   */
  selectedFolder?: string;
  /**
   * Overwrites the current `openDirectories`
   */
  setOpenDirectories?: (
    directories: (directories: string[] | undefined) => string[] | undefined,
    event: React.MouseEvent<HTMLButtonElement, MouseEvent>,
  ) => void;
};

type TreeNodeAdditionalProps = {
  nodeHeight?: number;
  setNodeHeight: (height: number) => void;
};

type TreeNodeWrapperProps = FileTreeProps & TreeNodeAdditionalProps;

const TreeNodeWrapper = (props: TreeNodeWrapperProps & { nodeProps: NodeProps }) => {
  const TreeNodeWrapperProps = {
    isReadOnly: props.isReadOnly,
    onMoveFile: props.onMoveFile,
    showExpandButton: props.showExpandButton,
    showExpandButtonOnHover: props.showExpandButtonOnHover,
    children: props.children,
  };
  const { nodeProps } = props;
  const { style, ...treeNodeProps } = nodeProps;
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (ref.current && !props.nodeHeight) {
      props.setNodeHeight(ref.current.clientHeight);
    }
  }, [props, ref]);

  return (
    <div ref={ref} style={{ ...nodeProps.style }}>
      <TreeNode
        {...treeNodeProps}
        {...TreeNodeWrapperProps}
        onFileSelect={props.onFileSelect}
        onFolderSelect={props.onFolderSelect}
        enableCloseFolderOnSecondClick={props.enableCloseFolderOnSecondClick}
        isRootDropPath={props.rootNodeName === nodeProps.data.dropPath}
        isSelected={
          props.selectedFile === treeNodeProps.data.relativePath ||
          props.selectedFolder === treeNodeProps.data.relativePath
        }
        setOpenDirectories={props.setOpenDirectories}
      >
        {props.children || defaultTreeNodeChild}
      </TreeNode>
    </div>
  );
};

const withTreeNodeWrapper = (
  Component: React.ComponentType<TreeNodeWrapperProps & { nodeProps: NodeProps }>,
  fileTreeProps: TreeNodeWrapperProps,
) => {
  const WrappedComponent = (props: NodeProps) => (
    <Component nodeProps={props} {...fileTreeProps} />
  );
  return WrappedComponent;
};

export const FileTree = React.memo((props: FileTreeProps) => {
  const { rootNodeName, openDirectories = [] } = props;

  // Hydrate the item heights with the default item height for load-more and loading
  // we set the them to be the same as the directory or file font size if provided
  const hydratedItemHeights = {
    ...props.itemFontSize,
    'load-more': props.itemFontSize?.directory ?? props.itemFontSize?.file ?? 'text-sm',
    loading: props.itemFontSize?.directory ?? props.itemFontSize?.file ?? 'text-sm',
  };

  const itemHeights = Object.entries(hydratedItemHeights || {}).reduce(
    (acc, [key, value]) => ({
      ...acc,
      [key]: FONT_SIZE_TO_HEIGHT_MAP[value] || DEFAULT_ITEM_HEIGHT,
    }),
    {},
  );

  const [nodeHeight, setNodeHeight] = useState<number>();
  const getDropPathCallback = useCallback(
    (node: InternalFileTreeItemType) => getDropPathDefault(node, rootNodeName),
    [rootNodeName],
  );

  const items = useMemo(() => {
    const childrenMap: Record<string, string[]> = {};
    props.items.forEach((item) => {
      const parts = item.id.split('/');
      parts.pop();
      const parent = parts.join('/') || rootNodeName;
      childrenMap[parent] = childrenMap[parent] || [];
      childrenMap[parent].push(item.id);
    });
    return props.items
      .sort((a, b) => sortNodes(a, b, props.onSort))
      .map((item, index): InternalFileTreeItemType => {
        const parts = item.id.split('/');
        const name = parts.pop() || '';
        const depth = parts.length;
        if (item.data.pathType === 'directory') {
          return {
            text: name,
            ...item,
            data: {
              name,
              depth,
              index,
              treeSize: props.items.length,
              relativePath: item.id,
              ariaOwns: (childrenMap[item.id] || []).join(' '),
              ...item.data,
            },
          };
        }
        return {
          text: name,
          ...item,
          data: {
            name,
            depth,
            index,
            treeSize: props.items.length,
            relativePath: item.id,
            ...item.data,
          },
        };
      });
  }, [props.items, rootNodeName, props.onSort]);

  const treeWalkerWrapper = useCallback(
    () => treeWalker(items, openDirectories, getDropPathCallback, itemHeights),
    [getDropPathCallback, openDirectories, items, itemHeights],
  );

  const WrappedTreeNode = withTreeNodeWrapper(TreeNodeWrapper, {
    nodeHeight,
    setNodeHeight,
    ...props,
  });

  return (
    <DndProvider backend={HTML5Backend}>
      <AutoSizer>
        {({ height, width }: { height: number; width: number }) => (
          <div role="tree" aria-label={props.ariaLabel || 'File tree'}>
            {/* @ts-expect-error. Internal vtree library is deprecated */}
            <VTree treeWalker={treeWalkerWrapper} height={height} width={width}>
              {WrappedTreeNode}
            </VTree>
          </div>
        )}
      </AutoSizer>
    </DndProvider>
  );
});
