import type { FC } from 'react';
import React from 'react';
import {
  FloatingFocusManager,
  FloatingPortal,
  useMergeRefs,
  useTransitionStyles,
} from '@floating-ui/react';

import { useReducedMotion } from '@/hooks/useReducedMotion';
import { usePopoverContext } from '../context';
import type { BaseContentProps } from '../types';
import { getFinalOffset } from '../utils';

type HeadlessContentProps = {
  hideOnEscape?: boolean;
  hideOnReferenceHidden?: boolean;
};

export const HeadlessContent: FC<BaseContentProps & HeadlessContentProps> =
  React.forwardRef<HTMLDivElement, BaseContentProps & HeadlessContentProps>(
    function PopoverContent(
      {
        children,
        testId,
        trackingId,
        className,
        style = {},
        hideOnEscape,
        hideOnReferenceHidden,
        ...props
      },
      propRef,
    ) {
      const {
        context: floatingContext,
        labelledBy,
        describedBy,
        getFloatingProps,
        floatingStyles,
        offset,
        zIndex,
        shouldShowOnHover,
        openChangeReason,
        ...floatingProps
      } = usePopoverContext();

      const reducedMotion = useReducedMotion();

      const ref = useMergeRefs([floatingProps.refs.setFloating, propRef]);

      const { styles: transitionStyles } = useTransitionStyles(floatingContext, {
        initial: {
          opacity: 0.95,
          transform: 'scale(0.98)',
        },
        duration: {
          open: reducedMotion ? 0 : 150,
          close: reducedMotion ? 0 : 150,
        },
        common: ({ side }) => ({
          animationTimingFunction: 'ease-in-out',
          transformOrigin: {
            top: 'bottom',
            bottom: 'top',
            left: 'right',
            right: 'left',
          }[side],
        }),
      });

      if (!floatingContext.open) {
        return null;
      }

      const hasEscaped = hideOnEscape && !!floatingProps.middlewareData.hide?.escaped;
      const hasReferenceHidden =
        hideOnReferenceHidden && !!floatingProps.middlewareData.hide?.referenceHidden;

      const hideStyles = {
        display: hasEscaped || hasReferenceHidden ? 'none' : 'block',
      };

      const offsetStyles = {
        top: Number(floatingStyles.top ?? 0),
        left: Number(floatingStyles.left ?? 0),
      };

      const finalOffset = getFinalOffset(offsetStyles, offset);

      const finalTestId = testId ?? 'popover';
      const finalTrackingId = trackingId ?? testId ?? 'popover';

      /**
       * For keyboard enablement, we want to return focus to last focused element on close.
       * However, if opening on hover, we want to avoid returning focus so that page doesn't scroll to last focused interactive element.
       * Unfortunately, opening with space/enter has openChangeReason: `click`, so we can't be more specific than !hover.
       */
      const returnFocus = openChangeReason !== 'hover';

      return (
        <FloatingPortal>
          <FloatingFocusManager
            context={floatingContext}
            visuallyHiddenDismiss={true} // provide dismiss button for touch screen readers
            returnFocus={returnFocus}
          >
            <div
              ref={ref}
              style={{
                ...floatingStyles,
                ...hideStyles,
                ...style,
                ...finalOffset,
                // z-index is required here to live within the document stacking context rather than the popover (absolute) context
                zIndex,
              }}
              aria-labelledby={labelledBy}
              aria-describedby={describedBy}
              data-testid={finalTestId}
              data-trackingid={finalTrackingId}
              {...getFloatingProps(props)}
            >
              <div
                style={{
                  ...transitionStyles,
                }}
                className={className}
              >
                {children}
              </div>
            </div>
          </FloatingFocusManager>
        </FloatingPortal>
      );
    },
  );
