import { useCallback, useEffect, useRef } from 'react';
import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { Icon } from '../Icon/Icon';
import type { IconProps } from '../Icon/types';
export type Segment = {
  label: string;
  value: string;
  className?: string;
  startIcon?: IconProps;
  endIcon?: IconProps;
};

type ButtonSize = 'sm' | 'md';
type Variant = 'default' | 'stretch';

export type SegmentedButtonProps = {
  segments: Segment[];
  onSelect: (value: string) => void;
  /**
   * The value of the currently selected segment.
   * When provided, the component is fully controlled.
   */
  selectedValue?: string;
  size?: ButtonSize;
  className?: string;
  variant?: Variant;
  testId?: string;
  trackingId?: string;
};

const baseWrapperClasses =
  'border-borderMuted inline-flex items-center rounded-md border p-0.5 flex gap-0.5 bg-bgBackground';

const baseWrapperSizeClasses = {
  md: 'h-[40px]',
  sm: 'h-[32px]',
};

const sizeClasses = {
  md: 'h-[34px]',
  sm: 'h-[26px]',
};

const baseButtonClasses =
  'flex items-center gap-1.5 px-2 border transition-colors rounded hover:shadow-hover font-label-lg';
const selectedClasses = 'border border-borderMainHover text-fgMain bg-bgMain';
const unselectedClasses = 'border border-transparent text-fgAlt bg-bgBackground';
const interactiveClasses =
  'hover:border-borderMainHover hover:bg-bgMainHover hover:text-fgMain active:bg-bgMainActive active:border-borderMainActive';
const focusClasses =
  ' focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-focusBrand focus-visible:ring-offset-focusInverse focus-visible:border-borderMain focus-visible:z-10';

const stretchClasses = 'w-full justify-center';

const buttonClasses = cx(baseButtonClasses, interactiveClasses, focusClasses);

const getTabIndex = (
  segmentValue: string,
  selectedValue: string | undefined,
  index: number,
) => {
  if (selectedValue === segmentValue) {
    return 0;
  }
  if (!selectedValue && index === 0) {
    return 0;
  }
  return -1;
};

export const SegmentedButton = ({
  segments,
  onSelect,
  selectedValue,
  className,
  size = 'md',
  variant = 'default',
  testId = 'segmented-button',
  trackingId = 'segmented-button',
}: SegmentedButtonProps) => {
  const buttonRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const wrapperClasses = twMerge(
    cx(
      baseWrapperClasses,
      baseWrapperSizeClasses[size],
      { 'w-full': variant === 'stretch' },
      className,
    ),
  );

  useEffect(() => {
    // is any button focused?
    const focusedIndex = buttonRefs.current.findIndex(
      (btn) => btn === document.activeElement,
    );

    // find index of selected value
    const selectedIndex = segments.findIndex(
      (segment) => segment.value === selectedValue,
    );

    // if focused index is not the selected index, focus the selected index
    if (focusedIndex !== -1 && focusedIndex !== selectedIndex) {
      buttonRefs.current[selectedIndex]?.focus();
    }
  }, [selectedValue, segments]);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      const currentIndex = segments.findIndex(
        (segment) => segment.value === selectedValue,
      );

      if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
        event.stopPropagation();
        const newIndex = (currentIndex + 1) % segments.length;
        onSelect(segments[newIndex].value);
      } else if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
        event.stopPropagation();
        const newIndex = (currentIndex - 1 + segments.length) % segments.length;
        onSelect(segments[newIndex].value);
      }
    },
    [segments, onSelect, selectedValue],
  );

  const handleClick = useCallback(
    (event: React.MouseEvent<HTMLButtonElement>, value: string) => {
      onSelect(value);
      event.preventDefault();
      event.stopPropagation();
    },
    [onSelect],
  );

  return (
    <div
      className={wrapperClasses}
      data-testid={testId}
      data-tracking-id={trackingId}
      style={{ width: variant === 'stretch' ? '' : 'max-content' }}
      role="radiogroup"
      onKeyDown={handleKeyDown}
    >
      {segments.map((segment, index) => {
        const isSelected = selectedValue === segment.value;
        return (
          <button
            key={segment.value}
            onClick={(event) => handleClick(event, segment.value)}
            ref={(el) => {
              buttonRefs.current[index] = el;
            }}
            role="radio"
            aria-checked={isSelected}
            aria-label={segment.label}
            data-testid={`${testId}-${segment.value}`}
            tabIndex={getTabIndex(segment.value, selectedValue, index)}
            className={twMerge(
              cx(buttonClasses, sizeClasses[size], {
                [selectedClasses]: isSelected,
                [unselectedClasses]: !isSelected,
                [stretchClasses]: variant === 'stretch',
              }),
              segment.className,
            )}
          >
            {segment.startIcon && <Icon {...segment.startIcon} size={size} />}
            {segment.label}
            {segment.endIcon && <Icon {...segment.endIcon} size={size} />}
          </button>
        );
      })}
    </div>
  );
};
