import { PropsWithChildren, useEffect, useMemo } from 'react';

import { useLiveRegion } from '../../../hooks';
import { ActionList } from '../../Actions';
import { BadgeProps } from '../../Badge';
import { Breadcrumb } from '../../Breadcrumbs';
import { Notification, NotificationBanner } from '../../NotificationBanner';
import { PageHeader } from '../../PageHeader';
import { RyeconChatResponse } from '../../ryecons';

/**
 * @deprecated Use BasicLayout instead
 */

export interface BaseLayoutProps {
  /** The Header of the page **/
  title: string;

  /** The Subtitle of the page **/
  subtitle?: string;

  headerBadge?: BadgeProps;

  /** An array of actions for the page header */
  actions?: ActionList;

  /** A flag to indicate whether to show a feedback button - usually for pendo */
  feedbackButton?: boolean;

  /** A list of breadcrumbs to display **/
  breadcrumbs?: Breadcrumb[];

  /** A boolean to determine whether the page is loading */
  isLoading: boolean;

  /** Error notification to display, if it exists */
  errorNotification?: Notification;

  /** A callback to be triggered when the error banner close button is clicked **/
  onErrorDismiss?: () => void;
}

export const BaseLayout: React.FC<PropsWithChildren<BaseLayoutProps>> = ({
  children,
  title,
  subtitle,
  headerBadge,
  actions,
  breadcrumbs,
  errorNotification,
  onErrorDismiss,
  feedbackButton,
  isLoading = false,
}): React.ReactElement => {
  const {
    clearMessage: clearErrorNotification,
    LiveRegion: ErrorNotification,
    setMessage: setErrorNotification,
  } = useLiveRegion();

  useEffect(() => {
    if (!isLoading && errorNotification) {
      setErrorNotification(
        <NotificationBanner
          notification={errorNotification}
          onCloseClick={onErrorDismiss}
        />,
      );
    } else {
      clearErrorNotification();
    }
  }, [
    clearErrorNotification,
    errorNotification,
    isLoading,
    onErrorDismiss,
    setErrorNotification,
  ]);

  const _actions = useMemo(
    () =>
      feedbackButton
        ? ([
            {
              text: 'Leave feedback',
              buttonProps: {
                type: 'link',
                ryecon: RyeconChatResponse,
                testId: 'leave-feedback',
                trackingId: 'leave-feedback',
              },
            },
            ...(actions ?? []),
          ] as ActionList)
        : actions,
    [actions, feedbackButton],
  );

  return (
    <>
      <div className="relative">
        <PageHeader
          title={title}
          subtitle={subtitle}
          badge={headerBadge}
          actions={_actions}
          breadcrumbs={breadcrumbs}
        />
        <div className="mt-8 space-y-6">
          <ErrorNotification />
          {children}
        </div>
      </div>
    </>
  );
};
