import { useEffect, useRef, useState } from 'react';
import cx from 'classnames';
import mergeRefs from 'merge-refs';
import { twMerge } from 'tailwind-merge';

import { RegisterOptions, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { get } from '../../../utils';
import { HelpIcon } from '../../HelpIcon';
import { FormFieldMessage } from '../FormFieldMessage/FormFieldMessage';

interface CustomCheckboxProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'defaultChecked'> {
  name: string;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** Description Text */
  description?: React.ReactNode;

  /** react-hook-form register config, accepts any options react-hook-form's register can accept. */
  formConfig?: RegisterOptions;

  /** Class names for the input element */
  inputClassName?: string;

  /** Boolean representing whether the label and description should be displayed inline */
  isInline?: boolean;

  /** Boolean representing that the checkbox should start checked. For use in standalone checkboxes only.
   * For setting defaults in react-hook-form, use the defaultValues object passed to useForm instead. */
  defaultChecked?: boolean | 'indeterminate';

  /** Ignore the react hook form context and behave as a standalone checkbox */
  ignoreForm?: boolean;

  /** Custom onChange handler. Allows for extra handling past the default react-hook-form usage */
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;

  /** Whether the checkbox should be hidden */
  isHidden?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
}

export type CheckboxProps = BaseInputProps & CustomCheckboxProps;

export const Checkbox: React.FC<CheckboxProps> = ({
  name,
  children,
  label,
  description,
  defaultChecked,
  ignoreForm,
  className,
  inputClassName,
  error,
  formConfig,
  helpLink,
  onHelpClick,
  isDisabled,
  isEdit,
  isInline,
  skeleton,
  isHidden = false,
  testId = 'checkbox',
  trackingId = 'checkbox',
  ...props
}) => {
  const [isChecked, setIsChecked] = useState(defaultChecked);
  const ref = useRef<HTMLInputElement>(null);

  const formMethods = useFormContext();

  const registration = ignoreForm
    ? undefined
    : formMethods?.register(name, formConfig ?? {});

  const errors = ignoreForm ? {} : formMethods?.formState?.errors ?? {};
  const errorMessage = get(errors, name)?.message ?? error;
  const hasError = !!errorMessage;

  const hasCustomViewOnly = !!children;

  const shouldHaveStandardStyles = !hasError && isEdit && !isDisabled;
  const shouldHaveErrorStyles = hasError && isEdit && !isDisabled;
  const shouldHaveDisabledStyles = isDisabled || !isEdit;

  useEffect(() => {
    // Reset checked state if default value changes
    setIsChecked(defaultChecked);

    // Set indeterminate state if default value is 'indeterminate'
    const input = ref.current;
    if (input) {
      input.indeterminate = defaultChecked === 'indeterminate';
    }
  }, [defaultChecked]);

  const checkboxClassnames = twMerge(
    'mt-1 h-4 w-4 rounded',
    shouldHaveStandardStyles &&
      'cursor-pointer text-fgBrandSelection focus:ring-focusBrand focus:ring-offset-bgMain border-borderMain bg-transparent hover:border-borderMainHover hover:bg-bgMainHover active:bg-bgMainActive',
    shouldHaveErrorStyles &&
      'bg-transparent text-fgBrandSelection focus:ring-focusBrand focus:ring-offset-bgMain',
    shouldHaveDisabledStyles &&
      'cursor-not-allowed border-transparent bg-bgDisabled text-fgDisabled',
    inputClassName,
  );

  return (
    <div
      className={cx(className)}
      data-testid={`${testId}-wrapper`}
      data-trackingid={`${trackingId}-wrapper`}
    >
      <label>
        <div className="relative flex items-start">
          {(isEdit || !hasCustomViewOnly) && (
            <div className="flex items-center">
              <input
                type={isHidden ? 'hidden' : 'checkbox'}
                data-testid={testId}
                data-trackingid={trackingId}
                className={checkboxClassnames}
                disabled={isDisabled || !isEdit}
                aria-describedby={
                  hasError ? `field-${name}-error` : `field-${name}-description`
                }
                {...(registration ?? {
                  checked: isChecked === true,
                  onChange: (e) => {
                    setIsChecked(e.target.checked);
                    if (props.onChange) {
                      props.onChange(e);
                    }
                  },
                })}
                // mergeRefs is not managed by us
                // eslint-disable-next-line react-hooks/refs
                ref={registration ? mergeRefs(registration.ref, ref) : ref}
                {...props}
              />
            </div>
          )}
          {(!!label || !!description || hasError) && (
            <div className={cx({ 'ml-3': isEdit || !hasCustomViewOnly })}>
              <div
                className={cx('font-label-lg mt-0.5 flex', {
                  'text-fgAlt': !hasError && !isDisabled,
                  'text-fgDanger': hasError && isEdit && !isDisabled,
                  'text-fgDisabled': isDisabled,
                  'cursor-not-allowed': shouldHaveDisabledStyles,
                  'cursor-pointer': shouldHaveStandardStyles,
                })}
              >
                {label}
                {Boolean(helpLink) && !onHelpClick && (
                  <HelpIcon className="ml-1 flex items-center" linkTo={helpLink} />
                )}
                {!helpLink && onHelpClick && (
                  <HelpIcon className="ml-1 flex items-center" onClick={onHelpClick} />
                )}
                {isInline && (
                  <span
                    className={cx('ml-1 font-normal', {
                      'text-fgDecorative': !hasError && !isDisabled,
                    })}
                  >
                    {description}
                  </span>
                )}
              </div>
              {!!description && !hasError && !isInline && (
                <FormFieldMessage
                  name={name}
                  description={description}
                  errorMessage={errorMessage}
                  isEdit={isEdit}
                  testId={testId}
                  trackingId={trackingId}
                />
              )}
              {hasError && !isInline && (
                <FormFieldMessage
                  name={name}
                  description={description}
                  errorMessage={errorMessage}
                  isEdit={isEdit}
                  testId={testId}
                  trackingId={trackingId}
                />
              )}
            </div>
          )}
        </div>
        {!isEdit && hasCustomViewOnly && (
          <div
            data-testid={`${testId}-display`}
            data-trackingid={`${trackingId}-display`}
          >
            {children}
          </div>
        )}
      </label>
    </div>
  );
};
