import { useMemo } from 'react';
import cx from 'classnames';

import type { SourdoughComponent } from '../../globalTypes';
import { ansiToHtml } from '../../utils';
import { Tooltip } from '../Tooltip/Tooltip';
import { getDisplayTimestamp, getSanitizedMessage } from './utils';

export type LogLineVariant =
  | 'default'
  | 'warning'
  | 'danger'
  | 'success'
  | 'info'
  | 'info-alt'
  | 'decorative'
  | 'disabled';

export type LogLineType =
  | 'success'
  | 'skipped'
  | 'reused'
  | 'error'
  | 'warning'
  | 'info'
  | 'debug'
  | 'summary'
  | 'disabled'
  | 'deprecation';

export interface LogLineProps extends SourdoughComponent {
  /** Timestamp for the log entry */
  timestamp: string;

  /** The log message content - can be HTML string or plain text */
  message: string;

  /** Optional log level/variant for styling */
  variant?: LogLineVariant;

  /** Optional log type for filtering (separate from variant for styling) */
  type?: LogLineType | LogLineType[];

  /** Optional additional data to display */
  additionalData?: Record<string, any>;

  /** Optional React children to render below the message */
  children?: React.ReactNode;

  /** Optional: show local time in tooltip */
  showLocalTime?: boolean;

  /** Optional: unique ID for URL linking */
  lineId?: string;

  /** Whether to treat the message as HTML and use dangerouslySetInnerHTML */
  isHtml?: boolean;

  /** Whether to treat the message as ANSI encoded */
  isAnsi?: boolean;

  /** Handler for any errors if ANSI handling fails */
  onAnsiConversionError?: (e: unknown) => void;
}

const getVariantClasses = (variant: LogLineVariant): string => {
  switch (variant) {
    case 'warning':
      return 'bg-bgWarningTinted text-fgWarning hover:text-fgWarningHover hover:bg-bgWarningMuted';
    case 'danger':
      return 'bg-bgDangerTinted text-fgDanger hover:text-fgDangerHover hover:bg-bgDangerMuted';
    case 'success':
      return 'text-fgSuccess hover:text-fgSuccessHover hover:bg-bgSuccessMuted';
    case 'info-alt':
      return 'text-fgInfoAlt hover:text-fgInfoAltHover hover:bg-bgInfoAltMuted';
    case 'info':
      return 'text-fgInfo hover:text-fgInfoHover hover:bg-bgInfoMuted';
    case 'disabled':
      return 'text-fgDisabled';
    case 'decorative':
      return 'text-fgDecorative hover:bg-bgMainHoverTinted hover:text-fgAltHover';
    default:
      return 'text-fgAlt hover:text-fgAltHover hover:bg-bgMainHover';
  }
};

export const LogLine: React.FC<LogLineProps> = ({
  timestamp,
  message,
  variant = 'default',
  children,
  showLocalTime = false,
  lineId,
  testId = 'log-line',
  trackingId = 'log-line',
  isHtml = false,
  isAnsi = false,
  onAnsiConversionError,
}): React.ReactElement => {
  const variantClasses = getVariantClasses(variant);
  const displayTimestamp = getDisplayTimestamp(timestamp);

  // Convert timestamp to local time for tooltip
  const getLocalTime = (timestamp: string): string => {
    try {
      // Try to parse as ISO string first
      const date = new Date(timestamp);
      if (!isNaN(date.getTime())) {
        return `${date.toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric',
          year: 'numeric',
        })} at ${date.toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
          hour12: true,
          timeZoneName: 'short',
        })}`;
      }

      // Try to parse common timestamp formats
      const timeMatch = timestamp.match(/(\d{1,2}):(\d{2}):(\d{2})/);
      if (timeMatch) {
        const now = new Date();
        const [_, hours, minutes, seconds] = timeMatch;
        const localTime = new Date(
          now.getFullYear(),
          now.getMonth(),
          now.getDate(),
          parseInt(hours),
          parseInt(minutes),
          parseInt(seconds),
        );
        return `${localTime.toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric',
          year: 'numeric',
        })} at ${localTime.toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
          hour12: true,
          timeZoneName: 'short',
        })}`;
      }

      return timestamp; // Fallback to original
    } catch {
      return timestamp;
    }
  };

  const timestampElement = (
    <div className="text-fgDecorative font-code flex-shrink-0 leading-5">
      {displayTimestamp}
    </div>
  );

  const _message = useMemo(() => {
    if (isAnsi) {
      return (
        <div
          dangerouslySetInnerHTML={{
            __html: ansiToHtml(message, onAnsiConversionError),
          }}
        />
      );
    }

    if (isHtml) {
      return (
        <div
          dangerouslySetInnerHTML={{
            __html: getSanitizedMessage(message, true),
          }}
        />
      );
    }

    return message;
  }, [isAnsi, isHtml, message, onAnsiConversionError]);

  return (
    <div
      className={cx(
        'relative flex min-h-6 items-start gap-2 whitespace-break-spaces rounded-sm px-2 py-0.5',
        variantClasses,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
      id={lineId}
    >
      {showLocalTime ? (
        <Tooltip content={getLocalTime(timestamp)}>{timestampElement}</Tooltip>
      ) : (
        timestampElement
      )}
      <div className="font-code flex-1 break-words leading-5">
        {_message}
        {!!children && <div className="mt-2">{children}</div>}
      </div>
    </div>
  );
};
