import React from 'react';
import { useResizeDetector } from 'react-resize-detector';
import cx from 'classnames';

import { useInteractionItem } from '../../../hooks/interactions';
import { Icon } from '../../Icon';
import { RyeconSpinner, RyeconWarningOutline } from '../../ryecons';
import { ChartContextProvider } from '../ChartProvider/ChartProvider';
import { Filters } from '../Filters';
import {
  InteractionLayer,
  InteractionPoint,
  InteractionType,
} from '../InteractionLayer/InteractionLayer';
import { Legend, LegendProps } from '../Legend/Legend';
import { Accessor, InteractionMeta, Margin, Point, Shape } from '../types';
import { createFullPlotId } from '../util/plot';
import { createRange } from '../util/range';
import { Scales } from '../util/scales';
import { VizTooltip } from '../VizTooltip/VizTooltip';
import { ColorSet, DEFAULT_COLOR_SET } from './Color';

export interface TooltipCallbackArgs<T extends Object> {
  interactionItem: InteractionItem<T> | null;
}

export type TooltipCallback<T extends object = any> = (
  args: TooltipCallbackArgs<T>,
) => React.ReactNode;

export interface ChartProps<ItemType extends object = any> {
  /** Top, right, bottom, left margin values */
  margin: Margin;
  /** Tooltip callback that provides the inner markup of the tooltip for a given item, state is managed internally by Chart */
  tooltip?: TooltipCallback<ItemType>;
  /** Scale object as created by utils/scales */
  xScale: Scales;
  /** Scale object as created by utils/scales */
  yScale: Scales;
  /** Accessor callback to provide the x value of a given data point */
  xAccessor: Accessor<ItemType, any>;
  /** Accessor callback to provide the y value of a given data point */
  yAccessor: Accessor<ItemType, any>;
  /** Height of the chart in pixels */
  height: number;
  /** Axis and Plot items to create your visualization */
  children?: React.ReactNode;
  /** Callback to handle clicks on individual items */
  onItemClick?(item: InteractionItem<ItemType>): void;
  /** If true, show a loading state */
  isLoading?: boolean;
  /** If not undefined, display this error */
  error?: React.ReactNode;
  /** Set true to see interaction cells */
  shouldShowCells?: boolean;
  /** Chart colors in order of usage in relation to Plot items order */
  colors?: ColorSet[];
  /** Callback to handle getting color classNames of plot relative to other plots */
  getColor?: (subPlotIndex?: number) => ColorSet;
  /** Callback to handle clicks on whole item set */
  onClickDataset?: (plotId: string, subPlotIndex?: number) => void;
  /** Accessor callback to find the currently focused plotId */
  focusPlotId?: string;
  /** Id for testing */
  testId?: string;
  /** Props for legend component */
  legendProps?: LegendProps;
  /** Interaction type, will dictate how the chart responds to users */
  interactionType?: InteractionType;
}
export interface InteractionItem<T extends Object> extends InteractionMeta {
  item: T;
  subItem?: unknown;
  plotId: string;
  exact: Point;
  shape: Shape | null;
}

/** @deprecated */
export function ValidChart(props: ChartProps) {
  const {
    margin,
    tooltip,
    children,
    xScale,
    yScale,
    onItemClick,
    getColor,
    legendProps,
    height = 300,
    shouldShowCells = false,
    colors = DEFAULT_COLOR_SET,
    testId,
    interactionType = 'voronoi',
  } = props;
  const [focusPlotId, setFocusPlotId] = React.useState<string>();
  const { width, ref } = useResizeDetector({
    // Recommended method to avoid harmless but noisy ResizeObserver loop limit exceeded errors
    // https://github.com/maslianok/react-resize-detector/issues/45#issuecomment-829928247
    refreshMode: 'debounce',
    refreshRate: 0,
  });
  const { setInteractionItem, cancelInteraction, interactionItem } =
    useInteractionItem();

  const handleOverItem = ({
    plotId,
    fullItem: item,
    point: exact,
    shape,
    ...rest
  }: InteractionPoint): void => {
    setInteractionItem({ plotId, item, exact, shape, ...rest });
  };

  const handleClick = ({
    plotId,
    fullItem: item,
    point: exact,
    shape,
    ...rest
  }: InteractionPoint): void => {
    onItemClick?.({ plotId, item, exact, shape, ...rest });
  };

  const handleLeave: React.MouseEventHandler<Element> = (event): void => {
    const newTarget = event?.relatedTarget as Element | undefined;

    if (newTarget && newTarget.closest) {
      if (!newTarget?.closest('[data-interaction-container]')) {
        setInteractionItem(null);
      }
    } else {
      setInteractionItem(null);
    }
  };

  const onClickDataset = (plotId: string, subPlotIndex: number = 0) => {
    const id = createFullPlotId(plotId, subPlotIndex);
    if (focusPlotId === id) {
      setFocusPlotId(undefined);
      return;
    }

    setFocusPlotId(id);
  };

  const chartMetaBase = {
    ...props,
    plotHeight: props.height! - (margin?.top ?? 0) - (margin?.bottom ?? 0),
    interactionItem,
    setInteractionItem,
    cancelInteraction,
    handleLeave,
  };
  return (
    <div className="relative" ref={ref}>
      {width && (
        <ChartContextProvider
          chartMeta={{
            ...chartMetaBase,
            xScale: createRange(
              xScale,
              margin?.left ?? 0,
              width -
                (margin?.left ?? 0) -
                (margin?.right ?? 0) -
                (legendProps?.width ?? 0),
            ),
            yScale: createRange(yScale, chartMetaBase?.plotHeight, margin?.top ?? 0),
            plotWidth:
              width -
              (margin?.left ?? 0) -
              (margin?.right ?? 0) -
              (legendProps?.width ?? 0),
            colors,
            svgHeight: height,
            svgWidth: width ?? 0,
            getColor,
            onClickDataset,
            focusPlotId,
          }}
        >
          <div
            className={cx('flex', {
              'flex-row': legendProps?.position === 'right',
              'flex-col': legendProps?.position === 'bottom',
            })}
          >
            <svg
              className="h-auto max-w-full"
              width={width - (margin?.left ?? 0) - (legendProps?.width ?? 0)}
              height={height}
              data-testid={testId}
            >
              <Filters />
              {children}
              <InteractionLayer
                show={shouldShowCells}
                onOver={handleOverItem}
                onLeave={handleLeave}
                onClick={onItemClick && handleClick}
                interactionType={interactionType}
              />
            </svg>
            {legendProps && <Legend {...legendProps} />}
          </div>
          {!!tooltip && (
            <VizTooltip testId={testId}>{tooltip({ interactionItem })}</VizTooltip>
          )}
        </ChartContextProvider>
      )}
    </div>
  );
}

/** @deprecated */
export function Chart(props: ChartProps) {
  const testId = props.testId ?? 'chart';
  const height = props.height;
  if (props.error) {
    return (
      <div
        style={{ height }}
        className="text-fgDanger relative mx-auto w-fit text-lg"
        data-testid={`${testId}-error`}
      >
        <div className="absolute left-1/2 top-1/2 mx-auto -translate-x-1/2 -translate-y-1/2 whitespace-nowrap text-center">
          <Icon ryecon={RyeconWarningOutline} size="2xl" className="mb-4" />
          <div className="align-middle">{props.error}</div>
        </div>
      </div>
    );
  }
  if (props.isLoading) {
    return (
      <div
        className="relative w-full"
        style={{ height }}
        data-testid={`${testId}-loading`}
      >
        <div className="absolute left-1/2 top-1/2 mx-auto -translate-x-1/2 -translate-y-1/2">
          <Icon
            testId="loadingSpinner"
            ryecon={RyeconSpinner}
            className="text-fgDecorative animate-spin"
            size="xl"
          />
        </div>
      </div>
    );
  }
  return <ValidChart {...props} testId={testId} />;
}
