import { Fragment } from 'react';
import cx from 'classnames';

import { Listbox, Transition } from '@/externals/headlessui';
import { type TriggerLocation, useContainerPlacement } from '../../hooks';
import { Avatar } from '../Avatar';
import { Badge, type BadgeProps } from '../Badge';
import { Icon, IconProps } from '../Icon';
import { RyeconCheckmark } from '../ryecons';

export interface DropdownOption {
  label: string | React.ReactNode;
  value: number | string;
  includeTopDivider?: boolean;
  includeBottomDivider?: boolean;
  avatar?: string;
  disabled?: boolean;
  secondaryLabel?: React.ReactNode;
  description?: React.ReactNode;
  startIcon?: IconProps;
  badge?: BadgeProps;
}

export interface DropdownOptionGroup {
  label: string;
  options: DropdownOption[];
  groupKey?: string; // Optional group key for different handling depending on group
}

export interface DropdownOptionsProps {
  /** An array of options for the select */
  options: (DropdownOption | DropdownOptionGroup)[];

  /** Placement options for the menu, auto will self-determine position */
  placement: 'auto' | TriggerLocation;

  /** Custom classnames for the dropdown option list */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

const isDropdownGroup = (
  item: DropdownOption | DropdownOptionGroup,
): item is DropdownOptionGroup => {
  return (item as DropdownOptionGroup).options !== undefined;
};

/**
 * Given an assorted list of options and option groups, returns a set of all options
 */
export const getFlattenedDropdownOptions = (
  options: (DropdownOption | DropdownOptionGroup)[],
) => {
  return options.reduce((acc, option) => {
    const currOptions = isDropdownGroup(option) ? option.options : [option];
    return acc.concat(currOptions);
  }, [] as DropdownOption[]);
};

/*
 * The <DropdownOptions> component defines common option styling and behavior that can
 * be used across multiple dropdown related components.
 *
 * For example, currently these options are used in:
 * - ButtonGroupDropdown (A dropdown component that can be used in a button group)
 * - DropdownButton (A dropdown component that is often used for filtering lists)
 *
 */
export const DropdownOptions: React.FC<DropdownOptionsProps> = ({
  options,
  className,
  testId = 'dropdown-options',
  trackingId = 'dropdown-options',
  placement = 'auto',
}) => {
  const { triggerRef, triggerAt, update } = useContainerPlacement();

  return (
    <div
      ref={triggerRef}
      className={cx(
        'font-label-lg absolute z-10',
        {
          'top-full mt-2': placement === 'bottom' || triggerAt === 'bottom',
          'bottom-full mb-2': placement === 'top' || triggerAt === 'top',
        },
        className,
      )}
    >
      <Transition
        as={Fragment}
        leave="transition ease-in duration-100"
        leaveFrom="opacity-100"
        leaveTo="opacity-0"
        beforeEnter={placement === 'auto' ? update : undefined}
      >
        {(ref) => (
          <Listbox.Options
            data-testid={testId}
            data-trackingid={trackingId}
            className="bg-bgMain border-borderMuted shadow-hover flex max-h-60 flex-col overflow-auto rounded-md border p-1 text-left focus:outline-none"
            ref={ref}
          >
            {options.map((option, index) => {
              if (isDropdownGroup(option)) {
                const { label, options } = option;

                return (
                  <div key={label}>
                    <div className="text-fgDecorative font-label py-2 pl-1">
                      {label}
                    </div>
                    {options.map((option) => {
                      return (
                        <DropdownOptionComponent key={option.value} option={option} />
                      );
                    })}
                  </div>
                );
              }
              return (
                <DropdownOptionComponent
                  key={option.value}
                  isTopLevel
                  option={option}
                  testId={`${testId}-${index}`}
                  trackingId={`${trackingId}-${index}`}
                />
              );
            })}
          </Listbox.Options>
        )}
      </Transition>
    </div>
  );
};

interface DropdownOptionProps {
  isTopLevel?: boolean;
  option: DropdownOption;
  testId?: string;
  trackingId?: string;
}

const DropdownOptionComponent: React.FC<DropdownOptionProps> = ({
  option,
  isTopLevel,
  testId = 'dropdown-option',
  trackingId = 'dropdown-option',
}) => {
  return (
    <Listbox.Option
      className={({ active }) =>
        cx(
          'text-fgMain relative shrink-0 cursor-pointer select-none truncate rounded-md border py-2 pl-2 pr-8 transition-colors',
          {
            'bg-bgMain border-transparent': !active,
            'bg-bgMainActive border-transparent': active,
            'border-t-borderMuted border-transparent': option.includeTopDivider,
            'hover:border-transparent': option.disabled,
            'pl-3': !isTopLevel,
            'hover:cursor-not-allowed': !active,
          },
        )
      }
      value={option}
      data-testid={testId}
      data-trackingid={trackingId}
      disabled={option.disabled}
    >
      {({ selected }) => (
        <>
          <div className="flex items-center">
            {!!option.avatar && (
              <Avatar size="2xs" src={option.avatar} className="mr-2 shrink-0" />
            )}
            {!!option.startIcon && <Icon {...option.startIcon} />}
            <span
              className={cx('break-all', {
                'text-fgBrand pr-4': selected && !option.disabled,
                'text-fgDisabled': option.disabled,
              })}
            >
              {option.label}
              {!!option.badge && (
                <span className="ml-2">
                  <Badge {...option.badge} />
                </span>
              )}
            </span>
          </div>
          {!!option.description && (
            <div
              className={cx('font-caption', {
                'text-fgDisabled': option.disabled,
                'text-fgDecorative': !option.disabled,
              })}
            >
              {option.description}
            </div>
          )}

          {selected && (
            <span
              className={cx('text-fgBrand absolute inset-y-0 right-2 flex', {
                'items-center': !option.description,
                'top-3': !!option.description,
              })}
            >
              <Icon ryecon={RyeconCheckmark} size="xs" aria-hidden="true" />
            </span>
          )}
        </>
      )}
    </Listbox.Option>
  );
};
