import { useChartContext } from '../ChartProvider/ChartProvider';
import { TickSpacing } from './BaseAxis';

/**
 * The minimum number of ticks
 */
const SPARSE_NUM_TICKS = 3;

/** @deprecated */
export const useNumTicks = (
  axis: 'x' | 'y',
  tickSpacing: TickSpacing,
  minTicks = SPARSE_NUM_TICKS,
) => {
  const { chartMeta } = useChartContext() ?? {};
  if (tickSpacing === 'sparse') {
    return minTicks;
  }
  const plotSize =
    axis === 'x' ? chartMeta?.plotWidth || 0 : chartMeta?.plotHeight || 0;

  return Math.max(Math.floor(plotSize / tickSpacing), minTicks);
};
