import { PropsWithChildren, useEffect } from 'react';
import cx from 'classnames';

import { ActionList } from '../Actions';
import { Notification, NotificationBanner } from '../NotificationBanner';
import { DrawerActionBar } from './DrawerActionBar';

export interface DrawerContentProps {
  /** The title to display in the header */
  title?: React.ReactNode;
  /** The description to display in the header */
  description?: React.ReactNode;
  /** Event handler for close button click */
  onClose: () => void;
  /** List of actions to display in the footer */
  actions?: ActionList;
  /** Additional class names to apply to the content */
  className?: string;
  /** Error notification to display */
  errorNotification?: Notification;
  /** Event handler for dismissing the error notification */
  onErrorDismiss?: () => void;
  /** Event handler for previous button click */
  onPrevious?: () => void;
  /** Event handler for next button click */
  onNext?: () => void;
  /** Whether the previous button is disabled */
  hasPrevious?: boolean;
  /** Whether the next button is disabled */
  hasNext?: boolean;
}

export const DrawerContent: React.FC<PropsWithChildren<DrawerContentProps>> = ({
  title,
  description,
  onClose,
  actions,
  className,
  errorNotification,
  onErrorDismiss,
  children,
  onPrevious,
  onNext,
  hasPrevious,
  hasNext,
}) => {
  // Handle the arrow keys events.
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      switch (event.key) {
        case 'ArrowDown':
          if (hasNext && onNext != null) {
            event.preventDefault();
            onNext();
          }
          break;
        case 'ArrowUp':
          if (hasPrevious && onPrevious != null) {
            event.preventDefault();
            onPrevious?.();
          }
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [hasNext, onNext, hasPrevious, onPrevious]);

  return (
    <div className={cx('flex h-full flex-col', className)}>
      <DrawerActionBar
        onClose={onClose}
        actions={actions}
        onPrevious={onPrevious}
        onNext={onNext}
        hasPrevious={hasPrevious}
        hasNext={hasNext}
      />
      <div className="flex flex-1 flex-col gap-4 overflow-y-auto p-4">
        <div className="flex flex-col">
          <h2 className="text-fgMain font-heading-2 truncate">{title}</h2>
          <div className="text-fgDecorative font-caption mt-1 text-wrap">
            {description}
          </div>
        </div>
        {errorNotification && (
          <div className="px-4 pt-4">
            <NotificationBanner
              notification={errorNotification}
              onCloseClick={onErrorDismiss}
            />
          </div>
        )}
        {children}
      </div>
    </div>
  );
};
