import cx from 'classnames';

import { Icon } from '../../Icon/Icon';
import { RyeconErrorOutline, RyeconWarningOutline } from '../../ryecons';

export interface FormFieldMessageProps {
  /** The field name, used for aria attributes */
  name: string;
  /** Optional description text to show when there's no error */
  description?: React.ReactNode;
  /** Optional error message to show */
  errorMessage?: React.ReactNode;
  /** Optional warning message to show */
  warningMessage?: React.ReactNode;
  /** Whether the field is in edit mode */
  isEdit?: boolean;
  /** Whether to hide the error label */
  shouldHideErrorLabel?: boolean;
  /** Optional className for the message container */
  className?: string;
  /** Optional test id for testing */
  testId?: string;
  /** Optional tracking id for analytics */
  trackingId?: string;
}

export const FormFieldMessage: React.FC<FormFieldMessageProps> = ({
  name,
  description,
  errorMessage,
  warningMessage,
  isEdit = false,
  shouldHideErrorLabel = false,
  className,
  testId = 'form-field-message',
  trackingId = 'form-field-message',
}) => {
  if (!description && !errorMessage && !warningMessage) return null;

  const showError = isEdit && !!errorMessage && !shouldHideErrorLabel;
  const showWarning = !!warningMessage;
  // Only show description if there's no error or warning
  const showDescription = !!description && !errorMessage && !warningMessage;

  const baseClasses = cx(
    'font-caption mt-1',
    {
      'text-fgDecorative': showDescription,
      'text-fgDanger': showError,
      'text-fgWarning': showWarning,
    },
    className,
  );

  if (showDescription) {
    return (
      <p
        className={baseClasses}
        id={`field-${name}-description`}
        data-testid={`${testId}-description`}
        data-trackingid={`${trackingId}-description`}
      >
        {description}
      </p>
    );
  }

  if (showError) {
    return (
      <p
        className={cx(baseClasses, 'flex items-center gap-1.5')}
        id={`field-${name}-error`}
        data-testid={`${testId}-error`}
        data-trackingid={`${trackingId}-error`}
      >
        <Icon ryecon={RyeconErrorOutline} size="sm" className="shrink-0" alt="error" />
        {errorMessage}
      </p>
    );
  }

  if (showWarning) {
    return (
      <p
        className={cx(baseClasses, 'flex items-center gap-1.5')}
        id={`field-${name}-warning`}
        data-testid={`${testId}-warning`}
        data-trackingid={`${trackingId}-warning`}
      >
        <Icon
          ryecon={RyeconWarningOutline}
          size="sm"
          className="shrink-0"
          alt="warning"
        />
        {warningMessage}
      </p>
    );
  }

  return null;
};
