import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { Icon } from '../../components/Icon/Icon';
import { Button } from '../Button';
import {
  RyeconCheckmarkOutline,
  RyeconClose,
  RyeconErrorOutline,
  RyeconInfoOutline,
  RyeconWarningOutline,
} from '../ryecons';
import { Sizes } from '../types';

export interface NotificationAction {
  /** The text to display on the action button */
  text: string;
  /** The onClick handler for the action button */
  onClick?: () => void;
  /** Optional href for the action button */
  href?: string;
  /** Optional aria label for the action button */
  ariaLabel?: string;
  /** Optional test id for the action button */
  testId?: string;
  /** Whether the action button is disabled */
  isDisabled?: boolean;
}

export interface Notification {
  /** The header to display in the banner */
  header: React.ReactNode;

  /** The helper text to display. Often includes a link to external docs */
  helperText?: React.ReactNode;

  /** An id for the banner. This value gets passed to the onRemove function */
  id: string | number;

  /** The banner type */
  type?: 'success' | 'error' | 'warning' | 'info';

  /** Optional action button configuration */
  action?: NotificationAction;
}

export interface NotificationBannerProps {
  /** The notification to display */
  notification: Notification;

  /** A removal handler function, if omitted, no close icon will be shown. */
  onCloseClick?: (id: number | string) => void;

  /** Determines whether the element should use full width styles or not */
  isGlobal?: boolean;

  /** Classnames for notification banner element */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const NotificationBanner: React.FC<NotificationBannerProps> = ({
  notification: { header, helperText, id, type = 'success', action },
  onCloseClick,
  isGlobal,
  className,
  testId = 'notification-banner',
  trackingId = 'notification-banner',
}): React.ReactElement => {
  const classNames = cx(
    'border p-2',
    {
      'border-borderSuccessMuted bg-bgSuccessMuted': type === 'success',
      'border-borderWarningMuted bg-bgWarningMuted': type === 'warning',
      'border-borderDangerMuted bg-bgDangerMuted': type === 'error',
      'border-borderInfoMuted bg-bgInfoMuted': type === 'info',
      'rounded-lg': !isGlobal,
    },
    className,
  );

  const ryecons = {
    error: RyeconErrorOutline,
    warning: RyeconWarningOutline,
    info: RyeconInfoOutline,
    success: RyeconCheckmarkOutline,
  } as const;

  const ryecon = ryecons[type];

  const IconColors = {
    error: 'text-fgDanger',
    warning: 'text-fgWarning',
    info: 'text-fgInfo',
    success: 'text-fgSuccess',
  } as const;

  const iconColor = IconColors[type];

  return (
    <div className={classNames} data-testid={testId} data-trackingid={trackingId}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Icon
            ryecon={ryecon}
            size="md"
            className={twMerge(iconColor, 'flex-shrink-0')}
            alt={type}
          />
          <div className="text-fgMain font-body-sm font-medium">{header}</div>
        </div>

        <div className="flex items-center gap-2">
          {action && (
            <Button
              type="secondary"
              size={Sizes.xs}
              onClick={action.onClick}
              text={action.text}
              ariaLabel={action.ariaLabel}
              testId={action.testId || `${testId}-action-button`}
              trackingId={`${trackingId}-action-button`}
              isDisabled={action.isDisabled}
            />
          )}
          {!!onCloseClick && (
            <Button
              type="tertiary"
              size={Sizes.xs}
              className="hover:bg-bgMainHoverTinted"
              ryecon={RyeconClose}
              testId={`${testId}-remove-button`}
              trackingId={`${trackingId}-remove-button`}
              onClick={() => onCloseClick(id)}
            />
          )}
        </div>
      </div>
      {!!helperText && (
        <div className="text-fgMain font-caption ml-6">{helperText}</div>
      )}
    </div>
  );
};
