/**
 * Helper for cy.get variants, given a testId, wrap it in the required attribute selector syntax
 *
 * Also supports a modifier as a second argument, allows for changing the matching on the pattern,
 * valid options can be found at: https://developer.mozilla.org/en-US/docs/Web/CSS/Attribute_selectors#syntax
 */
export const byTestId = (id: string, modifier: string = ''): string =>
  `[data-testid${modifier}="${id}"]`;

/**
 * Helper for cy.get, given an input name, wrap it up in the required attribute selector syntax
 */

export const byInputName = (name: string): string => `input[name="${name}"]`;

/**
 * Helper for cy.get, given an input name, wrap it up in the required attribute selector syntax
 */
export const byTrackingId = (id: string, modifier: string = ''): string =>
  `[data-trackingid${modifier}=${id}]`;
