import { AxisScale, NumberValue } from 'd3';
import { Axis, Orient } from 'd3-axis-for-react';

import { useChartContext } from '../../ChartProvider/ChartProvider';
import { TimeAxisScale } from '../../util/scales';
import { generateAxisTextFormatter } from '../../util/truncate';
import {
  AxisProps,
  BASE_AXIS_PROPS,
  BaseAxis,
  getTickWidth,
  TickSpacing,
} from '../BaseAxis';
import { useNumTicks } from '../numTicks';

export interface TimeAxisProps extends AxisProps {
  /**
   * Used to format the tick labels into any output string
   */
  tickFormat?(d: Date): string;

  /**
   * Defaults to `sparse` for time axes.
   * More at {@link TickSpacing}.
   */
  tickSpacing?: TickSpacing;
}

const MIN_NUM_TICKS = 5;

/** @deprecated */
export const TimeAxis: React.FC<TimeAxisProps> = ({
  axis = 'x',
  tickSpacing = 'sparse',
  enableTruncation = true,
  tickFormat,
  testId = 'time-axis',
  label,
}) => {
  const { chartMeta } = useChartContext() ?? {};
  const axisScale = chartMeta?.[`${axis}Scale`] as TimeAxisScale;
  const numSuggestedTicks = useNumTicks(axis, tickSpacing, MIN_NUM_TICKS);

  const tickValues = axisScale.scale.ticks(numSuggestedTicks);
  const numTicks = tickValues.length;
  const tickWidth = getTickWidth(axis, chartMeta, numTicks);

  const allowTruncation = enableTruncation && axis === 'x' && !!tickFormat;
  const formatterWithTruncation = generateAxisTextFormatter(allowTruncation, tickWidth);

  return (
    <BaseAxis label={label} testId={testId} axis={axis}>
      <Axis
        scale={axisScale.scale as AxisScale<Date | NumberValue>}
        tickValues={axisScale?.scale.ticks(numTicks)}
        tickFormat={
          allowTruncation
            ? (d: Date) => formatterWithTruncation(tickFormat!(d))
            : tickFormat
        }
        tickLineProps={{ className: 'hidden' }}
        tickTextProps={{ ...BASE_AXIS_PROPS.labelTextProps }}
        orient={axis === 'x' ? Orient.bottom : Orient.left}
        domainPathProps={{ className: 'hidden' }}
      />
    </BaseAxis>
  );
};
