import cx from 'classnames';

import { Badge, type BadgeType } from '../../Badge';
import { HelpIcon } from '../../HelpIcon';

type TabContents =
  | {
      /** The Text of the tab **/
      text: React.ReactNode;
      children?: never;
    }
  | {
      /** The Text of the tab **/
      children: React.ReactNode;
      text?: never;
    };

type DisabledContents =
  | {
      /** Flag for preventing the tab from being clickable **/
      isDisabled: boolean;

      /** screen-reader-only text to inform users why the tab is disabled **/
      disabledReason: string;
    }
  | {
      isDisabled?: false;
      disabledReason?: never;
    };

export type TabProps = TabContents &
  DisabledContents & {
    /** A unique identifier for onClick handling **/
    id: string;

    /** Shows a count badge next to the tab text if supplied */
    count?: number;

    /** Count badge type to provide status theming - uses Badge component types */
    countType?: BadgeType;

    /** @deprecated Use countType instead. Count variants on the button to provide extra status theming */
    countVariant?: 'default' | 'error' | 'warn' | 'success';

    /** Flag for displaying an asterisk indicator */
    hasIndicator?: boolean;

    /** Flag for indicating the currently selected tab **/
    isActive?: boolean;

    /** onClick handling for the tab */
    onClick?(id: string): void;

    /** Shows a linked help icon next to the tab text if supplied */
    helpLink?: string;

    /** data-testid for cypress targeting */
    testId?: string;

    /** data-trackingid for pendo targeting */
    trackingId?: string;
  };

interface SubComponents {
  Tab: typeof FloatingTab;
}

export const FloatingTab: React.FC<TabProps> = ({
  text,
  children,
  id,
  onClick,
  isActive,
  isDisabled = false,
  disabledReason,
  hasIndicator,
  count,
  countType,
  countVariant = 'default',
  helpLink,
  testId = 'floating-tab',
  trackingId = 'floating-tab',
}): React.ReactElement => {
  const tabClasses = cx(
    'font-label-lg group inline-flex items-center gap-1 rounded-t-sm border-b-2 px-2 pb-1 pt-1.5 transition-colors',
    {
      'border-borderMain text-fgMain': isActive,
      'hover:text-fgBrandHover active:text-fgBrandActive text-fgAlt active:bg-bgNeutralTinted border-transparent':
        !isActive && !isDisabled,
    },
    {
      'text-fgDisabled cursor-not-allowed border-transparent': isDisabled,
    },
  );

  const getBadgeType = (): BadgeType => {
    if (countType) return countType;

    // Map deprecated countVariant to BadgeType for backward compatibility
    switch (countVariant) {
      case 'success':
        return 'success';
      case 'error':
        return 'error';
      case 'warn':
        return 'warning';
      case 'default':
      default:
        return 'default';
    }
  };

  return (
    <button
      className={tabClasses}
      aria-current={isActive ? 'page' : undefined}
      type="button"
      onClick={() => onClick && onClick(id)}
      data-testid={testId}
      data-trackingid={trackingId}
      aria-disabled={isDisabled}
    >
      {children || text}
      {isDisabled && <div className="sr-only">{disabledReason}</div>}
      {count !== undefined && (
        <Badge
          text={count.toString()}
          type={getBadgeType()}
          size="xs"
          testId={`${testId}-count`}
        />
      )}
      {!!hasIndicator && <span className="text-fgDanger -mt-2 ml-0.5">*</span>}
      {!!helpLink && <HelpIcon className="ml-1" linkTo={helpLink} />}
    </button>
  );
};

export interface FloatingTabsProps {
  children: React.ReactNode;

  /** Flag to remove the bottom border */
  isBorderless?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const FloatingTabs: React.FC<FloatingTabsProps> & SubComponents = ({
  children,
  isBorderless = false,
  testId = 'floating-tabs',
  trackingId = 'floating-tabs',
}): React.ReactElement => {
  return (
    <div
      className={cx('px-0', {
        'border-borderMuted border-b': !isBorderless,
      })}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <nav className="-mb-px flex gap-2" aria-label="Tabs">
        {children}
      </nav>
    </div>
  );
};

FloatingTabs.Tab = FloatingTab;
