import { createContext, useContext } from 'react';

import type { UsePillStateReturn } from './types';

export const PillSubComponentContext = createContext<UsePillStateReturn | null>(null);

export const usePillSubComponentContext = () => {
  const context = useContext(PillSubComponentContext);

  if (context == null) {
    throw new Error(
      'Pill field components must be wrapped in <PillSubComponentContext.Provider />',
    );
  }

  return context;
};
