import { useEffect, useState } from 'react';
import cx from 'classnames';

import type { TriggerLocation } from '../../hooks/containerPlacement/useContainerPlacement';
import { ButtonGroup } from '../ButtonGroup';
import type { MenuItem } from '../MenuItems/MenuItems';
import { RyeconSpinner } from '../ryecons';
import type { Ryecon } from '../ryecons/types';
import { Sizes } from '../types';

import './SplitButton.css';

export type SplitButtonProps = {
  /** Set which option will appear in main button (Default: item at index 0) */
  defaultValue?: string | number;

  /** The type of split button */
  type?: 'default' | 'tertiary' | 'primary';

  /** Placement options for the menu, auto will self-determine position */
  menuPlacement?: 'auto' | TriggerLocation;

  /** Will send menu to nearest Portal if true */
  shouldPortalMenu?: boolean;

  /**
   * If specified, we will use the element with this ID as the scroll parent
   * instead of automatically trying to detect it
   */
  menuScrollRootId?: string;

  /** An array of items for the menu */
  items: MenuItem[];

  ryecon?: Ryecon;

  /** onClick handler for items array */
  onClick(item: string | number): void;

  /** onMenuToggleClick */
  onMenuToggleClick?(event: React.MouseEvent): void;

  /** Custom classnames for the SplitButton wrapper */
  className?: string;

  /** The button size */
  size?: Sizes;

  /** Custom classnames for the inner MenuButton */
  menuClassName?: string;

  menuLabel?: string;

  /** Custom classnames for the inner Button */
  buttonClassName?: string;

  /** Custom classnames for the MenuContainerClass */
  menuContainerClassName?: string;

  /** Flag to indicate button is not yet ready */
  isLoading?: boolean;

  /** Flag to indicate disabled inputs */
  isDisabled?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Enabled additional logging */
  debug?: boolean;

  /** Will make selected action from menu the new default and old default moved to dropdown */
  stickyAction?: boolean;

  /** Shows dropdown menu even if no menuOptions exist */
  alwaysShowMenu?: boolean;
};

export const SplitButton: React.FC<SplitButtonProps> = ({
  defaultValue,
  type: inputType = 'default',
  items,
  onClick,
  onMenuToggleClick,
  className,
  size = Sizes.md,
  isLoading,
  isDisabled,
  ryecon,
  menuPlacement = 'auto',
  menuScrollRootId,
  buttonClassName,
  menuClassName,
  menuContainerClassName,
  menuLabel,
  shouldPortalMenu = false,
  stickyAction = false,
  alwaysShowMenu = false,
  testId = 'split-button',
  trackingId = 'split-button',
  debug,
}): React.ReactElement => {
  const [currentDefault, setCurrentDefault] = useState<number | string | undefined>(
    defaultValue || items[0].value,
  );

  useEffect(() => {
    setCurrentDefault(defaultValue || items[0].value);
  }, [defaultValue, items]);

  const isClickable = !isLoading && !isDisabled;
  const type = !isClickable ? 'default' : inputType;

  const groupClasses = cx(
    'sourdough-splitbutton',
    'group',
    className,
    'w-full',
    'override-menu-radius',
    {
      'hover:shadow-rest': isClickable,
      'hover:shadow-none': !isClickable,
    },
  );

  const sharedClasses = cx(
    'focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain',
    {
      'bg-bgDisabled': !isClickable && inputType !== 'tertiary',
      'bg-bgMain':
        (inputType !== 'primary' && isClickable) ||
        (!isClickable && inputType === 'tertiary'),
      'bg-bgInverse hover:bg-bgInverseHover hover:shadow-brand-hover':
        inputType === 'primary' && isClickable,
      '!border-0': inputType === 'tertiary',
    },
  );

  const primaryColorClasses =
    'active:bg-bgInverseActive border-transparent focus:border-transparent active:border-transparent text-fgInverse';

  const buttonClasses = cx(
    'w-full',
    {
      [`${primaryColorClasses} shadow-brand-rest !border-fgInverse border-r-1 border-y-0 border-l-0`]:
        type === 'primary',
    },
    sharedClasses,
  );

  const menuClasses = cx(
    {
      '!border-l': type === 'default',
      '!border-l-0': type !== 'default',
      'text-fgAlt !border-l-0': inputType === 'tertiary' && !isDisabled,
      [`${primaryColorClasses} shadow-brand-rest`]: type === 'primary',
    },
    sharedClasses,
  );

  const iconClasses = cx({
    'animate-spin': isLoading,
  });

  const defaultOption = items.find((item) => item.value === currentDefault) || items[0];
  const menuOptions = items.filter((item) => item !== defaultOption);

  return (
    <ButtonGroup className={groupClasses} testId={testId} trackingId={trackingId}>
      <ButtonGroup.Button
        className={cx(buttonClasses, buttonClassName)}
        size={size}
        text={defaultOption.label}
        label={defaultOption.label}
        title={defaultOption.title}
        iconClassName={iconClasses}
        ryecon={isLoading ? RyeconSpinner : ryecon || defaultOption.ryecon}
        onClick={() => onClick(defaultOption.value!)}
        isDisabled={!isClickable}
      />
      {(menuOptions.length > 0 || alwaysShowMenu) && (
        <ButtonGroup.Menu
          className={cx(menuClasses, menuClassName)}
          menuContainerClassName={menuContainerClassName}
          label={menuLabel}
          items={menuOptions}
          onClick={(val) => {
            if (stickyAction) {
              setCurrentDefault(val);
            }
            onClick(val);
          }}
          onMenuToggleClick={onMenuToggleClick}
          isDisabled={!isClickable}
          menuPlacement={menuPlacement}
          shouldPortal={shouldPortalMenu}
          menuAlignment={'right'}
          debug={debug}
          menuScrollRootId={menuScrollRootId}
        />
      )}
    </ButtonGroup>
  );
};
