import { flexRender } from '@tanstack/react-table';
import cx from 'classnames';

import { Tooltip } from '../../Tooltip/Tooltip';
import {
  type CellVariant,
  type DefaultTData,
  type Header,
  type StickyColumn,
} from '../types';
import { getColumnStyles } from '../utils';
import { SortableHeader } from './SortableHeader';

type HeaderCellProps<TData extends DefaultTData, TValue extends React.ReactNode> = {
  header: Header<TData, TValue>;
  colIdx: number;
  stickyColumn: StickyColumn | undefined;
  testId: string;
  trackingId: string;
  cellVariant: CellVariant;
};

const HEADER_VARIANT_CLASSES: { [key in CellVariant]: string } = {
  DEFAULT: `border-y px-3 py-[7px]`,
  COMPACT: `border-y px-3 py-[7px]`,
  NO_PADDING: `p-0`,
};

export const HeaderCell = <TData extends DefaultTData, TValue extends React.ReactNode>({
  header,
  colIdx,
  stickyColumn,
  testId,
  trackingId,
  cellVariant = 'DEFAULT',
}: HeaderCellProps<TData, TValue>) => {
  const onClick = header.column.getToggleSortingHandler();
  const sortDir = header.column.getIsSorted();
  const isSortable = header.column.getCanSort();
  const isRightAligned =
    header.column.columnDef.meta?.align === 'end' ||
    header.column.columnDef.meta?.align === 'right';
  const classNames = cx(
    'border-borderMuted text-fgDecorative font-label flex truncate bg-inherit',
    {
      'text-left': !isRightAligned,
      'text-right': isRightAligned,
      'hover:bg-bgMainHover hover:text-fgAlt group hover:cursor-pointer': isSortable,
      'first:border-borderMuted first:sticky first:left-0 first:border-r':
        stickyColumn === 'first',
      'last:border-borderMuted last:sticky last:right-0 last:border-l':
        stickyColumn === 'last',
    },
    HEADER_VARIANT_CLASSES[cellVariant],
  );

  const cellContent = (
    <Tooltip
      displayOnlyWhenTruncated
      content={flexRender(header.column.columnDef.header, header.getContext())}
      className="w-full"
    >
      {(ref) => (
        <div ref={ref} className="truncate">
          {flexRender(header.column.columnDef.header, header.getContext())}
        </div>
      )}
    </Tooltip>
  );

  return (
    <th
      className={classNames}
      data-testid={`${testId}-header-${colIdx}`}
      data-trackingid={`${trackingId}-header-${colIdx}`}
      id={header.column.id}
      style={{
        ...getColumnStyles(header.column.columnDef),
      }}
      onClick={onClick}
      colSpan={header.colSpan}
    >
      {isSortable ? (
        <SortableHeader
          header={header}
          onClick={onClick}
          sortDir={sortDir}
          isRightAligned={isRightAligned}
          isSorted={!!sortDir}
        />
      ) : (
        cellContent
      )}
    </th>
  );
};
