import type { FC } from 'react';
import { twMerge } from 'tailwind-merge';

import { Content } from './Content';
import { PopoverContext } from './context';
import { HeadlessTrigger } from './headless/HeadlessTrigger';
import { StructuredContent } from './StructuredContent';
import type { PopoverProps } from './types';
import { usePopover } from './usePopover';

type SubComponents = {
  StructuredContent: typeof StructuredContent;
};

export const Popover: FC<PopoverProps> & SubComponents = ({
  children,
  content,
  asChild,
  className,
  /** @deprecated Let user config set variant */
  variant,
  style = {},
  ...rest
}) => {
  // sane defaults added in usePopover
  const config = usePopover(rest);
  return (
    <PopoverContext.Provider value={config}>
      <HeadlessTrigger asChild={asChild}>{children}</HeadlessTrigger>
      <Content
        testId={config.testId}
        trackingId={config.trackingId}
        className={twMerge(className)}
        style={style}
        variant={variant}
      >
        {content}
      </Content>
    </PopoverContext.Provider>
  );
};

Popover.StructuredContent = StructuredContent;
