import { useCallback, useMemo, useState } from 'react';

import { LiveRegion, LiveRegionProps } from './LiveRegion.internal';

export interface UseLiveRegion {
  /** The container for your message; defaults to empty so screenreaders know it exists before it's populated. */
  LiveRegion: React.FC;

  /** Clears the message from the LiveRegion component; useful if you need to supply the same message a second time! */
  clearMessage: () => void;

  /** Used to populate the LiveRegion component */
  setMessage: React.Dispatch<React.SetStateAction<React.ReactNode>>;
}

export type UseLiveRegionArgs = Omit<LiveRegionProps, 'message'>;

export const useLiveRegion = ({
  display,
  level,
  testId,
}: UseLiveRegionArgs = {}): UseLiveRegion => {
  const [message, setMessage] = useState<React.ReactNode>();

  const clearMessage = useCallback(() => {
    setMessage(null);
  }, [setMessage]);

  const _LiveRegion: React.FC = useCallback(
    () => (
      <LiveRegion display={display} level={level} message={message} testId={testId} />
    ),
    [display, level, message, testId],
  );

  return useMemo(() => {
    return {
      LiveRegion: _LiveRegion,
      clearMessage,
      setMessage,
    };
  }, [_LiveRegion, clearMessage, setMessage]);
};
