import { MouseEventHandler } from 'react';
import React from 'react';
import cx from 'classnames';
import { Delaunay } from 'd3';

import {
  type ChartMeta,
  type PlotRegistry,
  useChartContext,
} from '../ChartProvider/ChartProvider';
import type { Point, Shape } from '../types';
import type { Scales } from '../util';

export type InteractionType = 'none' | 'voronoi';

export const createInteractionLayerTestId = (
  datum: unknown,
  subDatum?: unknown,
): string => {
  const datumKeys = Object.keys(Object(datum));
  const subDatumKeys = Object.keys(Object(subDatum));
  const datumString = datumKeys.sort().map((key) => `${key}-${Object(datum)[key]}`);
  const subDatumString = subDatumKeys
    .sort()
    .map((key) => `${key}-${Object(subDatum)[key]}`);
  return `voronoi-cell-${datumString.concat(subDatumString).join('-')}`;
};

export interface InteractionPoint {
  /** Location of the InteractionPoint */
  point: Point;
  /** Id of the plot associated with this InteractionPoint */
  plotId: string;
  /** Name of the plot associated with this InteractionPoint */
  plotName?: string | string[];
  /** The single item associated with this InteractionPoint */
  fullItem: unknown;
  /** If multiple InteractionPoints are associated to a single fullItem within a Plot, it is represented as a subItem */
  subItem?: unknown;
  /** Shape of the Plot associated with this InteractionPoint */
  shape: Shape | null;
}

/**
 *  flattenedPoints
 *
 *  converts a plot registry (map of plot id's to data) into a flat array of points representing all the data in the chart
 *
 */
const flattenedPoints = (
  plots: PlotRegistry,
  chartMeta: ChartMeta,
  xScale: Scales,
  yScale: Scales,
): InteractionPoint[] =>
  Object.values(plots).reduce<InteractionPoint[]>((plotPoints, plot) => {
    const { id, xAccessor, yAccessor, data, shape } = plot;
    const newPoints: InteractionPoint[] = data.flatMap((item: any) => {
      if (shape?.getInteractionPoints) {
        return shape.getInteractionPoints({
          plot,
          item,
          chartMeta,
        });
      }
      return [
        {
          plotName: plot.name,
          plotId: id,
          fullItem: item,
          point: [
            xScale.scale(xAccessor(item)) ?? 0,
            yScale.scale(yAccessor(item)) ?? 0,
          ],
          shape,
        } as InteractionPoint,
      ];
    });
    return [...plotPoints, ...newPoints];
  }, []);

export interface InteractionLayerProps {
  /** Set true to show voronoi cells */
  show?: boolean;
  onOver(interactionPoint: InteractionPoint): void;
  onClick?(interactionPoint: InteractionPoint): void;
  onLeave: MouseEventHandler;
  interactionType?: InteractionType;
}

/** @deprecated */
export const InteractionLayer: React.FC<InteractionLayerProps> = ({
  show = false,
  onOver,
  onLeave,
  onClick,
  interactionType = 'voronoi',
}) => {
  const chartContext = useChartContext();
  const points = React.useMemo(() => {
    if (
      chartContext &&
      chartContext.chartMeta !== null &&
      chartContext.chartMeta.xScale &&
      chartContext.chartMeta.yScale
    ) {
      return flattenedPoints(
        chartContext.plots,
        chartContext.chartMeta,
        chartContext.chartMeta.xScale,
        chartContext.chartMeta.yScale,
      );
    }
    return [];
  }, [chartContext]);

  if (interactionType === 'none') return null;

  const { top, left } = chartContext?.chartMeta?.margin ?? {};
  const plotWidth = chartContext?.chartMeta?.plotWidth ?? 0;
  const plotHeight = chartContext?.chartMeta?.plotHeight ?? 0;

  const voronoi = Delaunay.from(points.map(({ point }) => point)).voronoi([
    Math.min(left ?? 0, plotWidth),
    Math.min(top ?? 0, plotHeight),
    plotWidth,
    plotHeight,
  ]);

  const cells = points.map((point, idx) => {
    const path = voronoi.renderCell(idx);
    return (
      <g key={idx}>
        {/* Only render when it has a path and can be interacted with. */}
        {path && (
          <path
            data-testid={createInteractionLayerTestId(point.fullItem, point.subItem)}
            d={path}
            className={cx({
              // debug values, should never be true in production
              'fill-fgVizSkyBlue stroke-borderVizNeutral hover:fill-fgVizOrangeHover opacity-20 transition-all':
                show,
              'fill-transparent stroke-transparent': !show,
            })}
            onMouseEnter={() => onOver(point)}
            onMouseLeave={onLeave}
            onClick={onClick && (() => onClick(point))}
          />
        )}
        {show && (
          <circle cx={point.point[0]} cy={point.point[1]} fill="black" r={5}></circle>
        )}
      </g>
    );
  });

  return <g>{cells}</g>;
};
